INSERT INTO `article` VALUES
('03baf6c6-c348-4e69-aa0b-809d04bfce10','Curitiba de Volta ao Centro: a revitalização que busca devolver segurança, movimento e prosperidade ao coração da cidade','curitiba-de-volta-ao-centro-a-revitalizacao-que-busca-devolver-seguranca-movimento-e-prosperidade-ao-coracao-da-cidade-ahkgd','Comerciantes relatavam dificuldades crescentes. Muitos clientes passaram a evitar determinadas áreas, especialmente à noite. Em algumas regiões','Durante muitos anos, o Centro de Curitiba foi o principal cartão-postal econômico, cultural e comercial da capital. Entretanto, assim como ocorreu em diversas grandes cidades brasileiras, a região passou a enfrentar desafios cada vez mais visíveis: aumento da sensação de insegurança, crescimento da população em situação de rua, degradação de imóveis históricos e afastamento gradual de consumidores, moradores e investidores.\n\nComerciantes relatavam dificuldades crescentes. Muitos clientes passaram a evitar determinadas áreas, especialmente à noite. Em algumas regiões, estabelecimentos conviviam diariamente com pessoas dormindo em calçadas, ocupação irregular de espaços públicos e ocorrências criminais que comprometiam a atividade econômica e a circulação de pedestres.\n\nFoi diante desse cenário que a Prefeitura de Curitiba decidiu adotar uma estratégia mais ampla do que simples ações de fiscalização ou segurança. A aposta passou a ser a revitalização completa da região central, combinando investimentos públicos, incentivos econômicos, recuperação urbana e atração de novos moradores e empreendedores.\n\n**Uma mudança de conceito**\n\nA administração do prefeito Eduardo Pimentel estruturou o programa \"Curitiba de Volta ao Centro\", que tem como objetivo estimular a recuperação urbana, atrair investimentos privados, fomentar atividades econômicas e ampliar a presença de moradores na região central. O programa prevê investimentos e incentivos que podem chegar a R$ 163 milhões até 2032.\n\n> A lógica é simples: centros urbanos movimentados, ocupados e economicamente ativos tendem a ser mais seguros e mais atrativos\n\nPor isso, a revitalização não se resume à recuperação de fachadas ou melhorias paisagísticas. O projeto busca criar um novo ciclo econômico para o Centro de Curitiba.\n\n**Incentivos para quem investir**\n\nUm dos pilares mais importantes da iniciativa é a criação de incentivos fiscais para atrair empresas, profissionais liberais e investidores.\n\n**Entre as medidas adotadas estão:**\n\nisenções e reduções de tributos municipais;\nincentivos para restauração de imóveis históricos;\nestímulo ao retrofit de edifícios antigos;\ndescontos em impostos como ISS, IPTU e ITBI;\nampliação do potencial construtivo para novos empreendimentos.\n\nA prefeitura também regulamentou benefícios que podem garantir até 100% de isenção de ISS para determinadas atividades instaladas na região central até 2032, beneficiando profissionais como médicos, advogados, contadores, dentistas e outros prestadores de serviço.\n\nAlém disso, editais de subvenção econômica poderão custear até 50% do valor de obras de revitalização e retrofit, reduzindo significativamente o custo para investidores interessados em recuperar imóveis da região.\n\n**Segurança e ocupação dos espaços**\n\nA revitalização do Centro também passa pela ocupação qualificada dos espaços urbanos.\n\nExperiências em diversas cidades demonstram que ruas movimentadas, imóveis ocupados, comércio ativo e presença constante de moradores contribuem diretamente para reduzir a degradação urbana e aumentar a sensação de segurança.\n\nPor isso, a estratégia da prefeitura busca combinar:\n\nmoradia;\ncomércio;\ncultura;\nserviços;\nturismo;\ne preservação histórica.\n\n> O objetivo é transformar o Centro novamente em um local de convivência permanente, e não apenas uma área de passagem durante o horário comercial.\n\n**A recuperação da identidade histórica**\n\nA reabertura e recuperação de estabelecimentos tradicionais também fazem parte desse processo.\n\nCasos como o do histórico Bar Stuart simbolizam uma política que procura preservar a memória da cidade ao mesmo tempo em que estimula novos investimentos e atividades econômicas no Centro.\n\nA revitalização não pretende apagar a história da região, mas utilizar esse patrimônio como elemento de atração para moradores, turistas e empreendedores.\n\n**Um projeto de longo prazo**\n\nA transformação do Centro de Curitiba não ocorrerá de forma imediata.\n\nA própria legislação que instituiu o programa estabelece um planejamento de longo prazo, com ações graduais de requalificação urbana, integração entre moradia, trabalho, segurança, cultura e lazer.\n\n**O desafio continua sendo grande.**\n\nEntretanto, a estratégia adotada pela prefeitura parte de um diagnóstico amplamente compartilhado por comerciantes e moradores: a recuperação do Centro exige mais do que policiamento. Exige atividade econômica, ocupação dos espaços, investimentos privados e presença permanente de pessoas circulando pela região.\n\nA aposta da gestão Eduardo Pimentel é justamente essa: devolver vida ao Centro para que a segurança, o comércio e a qualidade urbana voltem a caminhar juntos.',NULL,'/api/media/materia/novo-1780918634959-s0n4fcch3/imagens/1780918636980-Revitaliza__o_ctba.jpg',NULL,0,'published','2026-06-08 11:39:47.536','2026-06-08 11:39:10.161','2026-06-08 11:40:04.262','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ricardo Marajó/SECOM',2,NULL),
('0413284f-cc3a-4cc1-b8f2-9fcff58b2597','O que Sergio Moro tem de melhor que Sandro Alex?','o-que-sergio-moro-tem-de-melhor-que-sandro-alex-l3ln1','A resposta mais honesta para essa pergunta é simples: notoriedade nacional.','Sergio Moro ficou conhecido no Brasil inteiro por causa da Lava Jato.\nConstruiu uma imagem forte no combate à corrupção, ganhou espaço nacional, deixou o judiciário e entrou para a política, criou um eleitorado fiel, condições que ainda possuem peso importante no Paraná.\n\nMas o problema começa justamente depois disso. Porque, quando a disputa sai da fama e entra na comparação prática entre os dois nomes, Sandro Alex começa a ocupar um espaço político cada vez mais sólido.\n\n**Moro tem fama. Sandro tem gestão.**\nEsse passou a ser o verdadeiro eixo da disputa.\nMoro construiu carreira no Poder Judiciário, na projeção nacional, no enfrentamento político e no embate ideológico. \n\n> Sandro Alex construiu trajetória administrativa, regional, executiva e diretamente ligada à infraestrutura do Paraná. \n\nHoje, grande parte das obras que Ratinho Junior entrega no interior, passou pela Secretaria de Infraestrutura, comandada por Sandro Alex.\nE isso cria um contraste inevitável. O eleitor começa a perguntar, quem conhece o Paraná administrativo? quem executou obras? quem esteve dentro da máquina pública estadual?\n\n**O principal ativo de Moro virou também seu maior problema.**\nA força de Sergio Moro sempre foi Brasília. Mas, neste momento, Brasília virou desgaste.\nAs recentes turbulências envolvendo Flávio Bolsonaro, empresários, banqueiros, financiadores e o ambiente nacional do PL, começam a atingir diretamente o campo político ligado a Moro.\nRatinho Junior percebeu isso cedo. Por isso construiu distância estratégica das guerras ideológicas nacionais.\n\n> Enquanto Moro aparece conectado ao bolsonarismo nacional, às crises do PL e ao desgaste político de Brasília, Sandro Alex aparece ao lado de obras, prefeitos, investimentos e agendas no interior.\n\n**Na pesquisa, vale mais o número ou a tendência?**\nEsse é o fato político mais importante das últimas pesquisas.\nMoro continua conhecido, competitivo e muito forte eleitoralmente. \nMas Sandro Alex é quem mais cresce. E cresce porque Ratinho Junior conseguiu algo raro: transformar aprovação administrativa em força eleitoral. O eleitor começa a enxergar Sandro Alex não como um candidato improvisado, mas como continuidade, estabilidade e sequência do atual governo. \n\n> Ou seja, a tendência de crescimento não está com Moro. É Sandro Alex que deu uma arrancada e segue crescendo. Na última pesquisa, na simulação de segundo turno, aparece em segundo lugar, com forte tendência a ultrapassar Moro, já nas próximas pesquisas.\n> \n\n**Moro enfrenta dificuldade no interior.**\nExiste uma diferença gigantesca entre repercussão nacional e capilaridade regional. \nNo interior do Paraná Ratinho Junior domina politicamente, prefeitos acompanham o governo, o PSD ocupa espaço crescente e Sandro Alex aparece permanentemente nas agendas regionais. \nMoro continua forte nos grandes centros urbanos, mas eleição estadual se ganha no conjunto do estado. E é exatamente nesse ponto que Sandro Alex cresce mais rapidamente.\n\n**Sandro Alex virou candidato de continuidade.**\nOutro detalhe importante, que a população já percebeu, é que Sandro Alex não transmite ruptura.\nEle transmite continuidade, previsibilidade, gestão e manutenção de um governo altamente aprovado. \nIsso gera conforto político para prefeitos, empresários, lideranças regionais e parte significativa do eleitorado. \nEnquanto Moro representa enfrentamento, polarização e tensão política nacional, Sandro representa continuidade administrativa.\n\n**O problema de Moro: o debate deixou de ser apenas moral.**\nDurante muito tempo, Moro dominou o debate político porque a eleição girava em torno de corrupção, de Lava Jato e de combate político. Aliás, foi levado para o governo Bolsonaro porque estes eram os temas predominantes naquele momento. Assim que passou essa “febre”, foi defenestrado do governo. \nMas o ambiente mudou. Hoje o eleitor fala de obras, emprego, infraestrutura, crescimento regional e qualidade da gestão. \nE nesse terreno Ratinho Junior é extremamente forte e Sandro Alex cresce junto com ele.\n\n**E aí?**\n\nO que Sergio Moro tem de melhor que Sandro Alex? Fama nacional, notoriedade política, recall eleitoral.\n\nMas a eleição do Paraná começa a entrar em outro campo: gestão, obras, continuidade e presença regional. \n\n***E nesse ambiente, Sandro Alex cresce, Ratinho Junior fortalece o sucessor e Moro começa a enfrentar o peso do desgaste nacional do PL. A disputa deixa de ser apenas sobre quem é mais conhecido e começa a virar quem representa mais segurança política para o futuro do Paraná.***\n***',NULL,'/api/media/materia/novo-1779883848158-jbo97vn4o/imagens/1779883853863-Sandro__Ratinho_e_Moro.png',NULL,0,'published','2026-05-29 19:08:53.392','2026-05-27 12:12:04.090','2026-06-05 01:11:55.224','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',23,NULL),
('064fc864-e192-49ec-b1bf-6b7c1f0fdbfd','Quando o discurso encontra o limite da realidade','quando-o-discurso-encontra-o-limite-da-realidade-cntuk','Não se trata de questionar biografia. Trata-se de reconhecer adequação.','A candidatura de Sérgio Moro carrega força — mas também carrega um problema estrutural que não pode ser ignorado: ela foi construída longe da gestão.\n\nE isso, numa eleição estadual, cobra um preço.\nNão se trata de questionar biografia.\nTrata-se de reconhecer adequação.\n\nO Paraná não está escolhendo um símbolo.\nEstá escolhendo quem vai operar uma máquina pública complexa, com orçamento bilionário, pressão política constante e necessidade de execução diária.\n\n> E aqui surge o contraste incômodo.\n\n**De um lado**, um grupo que passou anos governando, com erros e acertos — mas com experiência concreta de gestão;\n**Do outro**, uma candidatura que se sustenta, até aqui, muito mais naquilo que representa do que naquilo que executou.\n\n> Isso não é detalhe.\n> É o centro da eleição.\n\nPorque quando o debate sai do campo simbólico e entra no campo prático, a régua muda.\n\nE, sob essa régua, o discurso precisa responder a uma pergunta simples:\nOnde estão as entregas?\nAté agora, essa resposta ainda não apareceu com clareza.\n',NULL,'/api/media/materia/064fc864-e192-49ec-b1bf-6b7c1f0fdbfd/imagens/1777402602810-SERGIO_MORO.jpg',NULL,0,'published','2026-04-29 13:08:46.890','2026-04-28 13:55:28.139','2026-05-22 23:18:15.609','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Marcos Oliveira/Agência Senado',5,NULL),
('0920f9de-b088-461f-bb75-87a03a138012','Ratinho Junior transformou o interior do Paraná no principal palco político de 2026','ratinho-junior-transformou-o-interior-do-parana-no-principal-palco-politico-de-2026-8l4f0','O governador não transmite a imagem de quem encerra um ciclo. Transmite a imagem de quem tenta consolidar um legado político','Já escrevemos aqui neste blog que, enquanto muitos governos entram no último ano de mandato administrando desgaste, crises ou despedidas protocolares, Ratinho Junior faz exatamente o contrário: intensifica presença, acelera entregas, percorre o estado, amplia investimentos e transforma viagens ao interior em demonstrações públicas de força política.\n\n> As agendas dos últimos dias mostram um governador em movimento permanente: entrega de recursos, pavimentação de estradas rurais, inauguração de obras, casas populares, investimentos regionais, encontros partidários do PSD e contato direto com prefeitos, lideranças e população. \n\n**O fim deste governo parece muito distante.**\nEsse é o ponto mais impressionante. Governos próximos do encerramento normalmente entram em modo administrativo defensivo. Mas Ratinho Junior parece operar em lógica oposta.\nAs viagens recentes revelam intensidade política, presença regional, mobilização partidária e construção clara de continuidade. O governador não transmite a imagem de quem encerra um ciclo. Transmite a imagem de quem tenta consolidar um legado político.\n\n**O interior virou a grande vitrine do governo.**\nExiste uma estratégia evidente nessa movimentação. O governo compreendeu algo essencial da política paranaense: ***eleição estadual se constrói nos municípios***. E é exatamente ali que Ratinho Junior consolidou sua força, junto a prefeitos, lideranças regionais, associações locais, produtores rurais, empresários, vereadores e a população. \nCada entrega de estrada rural, habitação, escola, ponte ou investimento municipal, reforça uma narrativa simples: “o governo chegou”.\n\n**As viagens também funcionam como pré-campanha de Sandro Alex.**\nE isso já deixou de ser disfarçado. Sandro Alex acompanha agendas, participa dos encontros, aparece ao lado do governador e começa a ocupar o espaço simbólico de continuidade administrativa. \nO que se percebe nos eventos do PSD é uma tentativa clara de transferência política gradual: ***Ratinho apresenta, valida, aproxima e fortalece o pré-candidato diante das bases municipais***.\nE o detalhe importante:\nSandro Alex começa a demonstrar desenvoltura crescente.\n\n**O apoio recebido revela algo maior.**\nOs encontros recentes não têm sido apenas protocolares. Centenas de lideranças, prefeitos, moradores e políticos locais têm participado das agendas e, em muitos momentos, manifestado apoio explícito à continuidade do grupo político. Isso acontece porque boa parte do interior associa diretamente o atual governo à ideia de investimento regional.\nE na política estadual isso pesa muito. Especialmente quando o eleitor vê obra, percebe presença e sente proximidade do governo.\n \n**Ratinho Junior construiu um modelo político raro.**\nÉ perceptível que a principal força do governador está justamente na combinação entre gestão, presença popular e baixa rejeição. \n\n> Ratinho Junior, que entrou cedo para a política, tem se mostrado um político experiente, agregador e um grande articulador, que hoje enxerga o que pode acontecer lá na frente, nos dias seguintes.\n\nIsso, sem contar que mantém algo incomum: carisma político sem desgaste intenso.\nPor onde passa tira fotos, abraça moradores, conversa espontaneamente e demonstra uma comunicação popular extremamente natural. Isso fortalece emocionalmente a conexão com o eleitorado do interior.\n\n**Na prática, o governo virou máquina política eficiente.**\nExiste uma leitura inevitável sobre tudo isso. As entregas administrativas e as viagens regionais também se transformaram em instrumento político de sucessão. E é nisso que está a principal eficiência do grupo governista: ***não separar gestão de presença política e nem obra de capital eleitoral.*** \nO governo percebeu que quem ocupa o território político continuamente larga na frente na sucessão.\n\n**E aí?**\nAs viagens de Ratinho Junior pelo interior já não são apenas agendas administrativas. São demonstrações públicas de força política, aprovação regional, articulação partidária e construção organizada da sucessão estadual. \nE Sandro Alex começa claramente a ser incorporado nesse processo.\n\n**Fato.**\nEnquanto muitos governos entram no último ano administrando desgaste,\nRatinho Junior percorre o Paraná entregando obras, recursos e presença política.\nE cada viagem ao interior reforça uma mensagem simples: o ciclo político do grupo ainda não terminou.\n',NULL,'/api/media/materia/novo-1778933626906-u7u1pa8s1/imagens/1778933628789-carism_tico.jpg',NULL,0,'published','2026-06-02 11:36:32.704','2026-05-16 12:15:00.102','2026-06-05 20:46:56.966','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos',30,NULL),
('09d84b52-7a69-4fe2-b585-b55957c57013','Queda das temperaturas: Saúde reforça necessidade da vacinação para evitar síndromes respiratórias','queda-das-temperaturas-saude-reforca-necessidade-da-vacinacao-para-evitar-sindromes-respiratorias-73663','Com a chegada das estações mais frias, o Paraná entra em um período de maior atenção. Dados do boletim InfoGripe, da Fundação Oswaldo Cruz (FioCruz), apontam que as regiões Sul e Sudeste estão em alerta com risco moderado a alto para o aumento de casos, tendência que deve se intensificar ao longo do outono e inverno.','Com a chegada das estações mais frias, o Paraná entra em um período de maior atenção para as Síndromes Respiratórias Agudas Graves (SRAG). Dados do boletim InfoGripe, da Fundação Oswaldo Cruz (FioCruz), apontam que as regiões Sul e Sudeste estão em alerta com risco moderado a alto para o aumento de casos, tendência que deve se intensificar ao longo do outono e inverno.\n\n> Além da vacinação, a Secretaria reforça medidas simples e eficazes que ajudam a reduzir a transmissão de vírus respiratórios e evitar agravamentos:\n\n- Higienize as mãos com frequência, especialmente antes de consumir alimentos\n\n- Utilize lenços descartáveis para higiene nasal\n\n- Cubra nariz e boca ao tossir ou espirrar\n\n- Evite tocar olhos, nariz e boca\n\n- Higienize as mãos após tossir ou espirrar\n\n- Não compartilhe objetos de uso pessoal, como talheres, pratos, copos ou garrafas\n\n- Mantenha os ambientes bem ventilados\n\n- Evite contato próximo com pessoas com sintomas gripais\n\n- Evite sair de casa, se possível, em períodos de maior transmissão\n\n- Reduza a exposição a aglomerações e ambientes fechados\n\n- Adote hábitos saudáveis, como alimentação equilibrada e ingestão de líquidos\n\nA população idosa segue como a mais afetada: pessoas com mais de 80 anos concentram 24 dos óbitos registrados. Nos casos relacionados à Influenza, a média de idade das vítimas é de 77 anos.',NULL,'/api/media/materia/novo-1777385758729-z02zhunvc/imagens/1777385762076-Vacina__o.jpg',NULL,0,'published','2026-04-28 14:18:01.085','2026-04-28 14:18:01.092','2026-05-26 05:21:51.307','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos',3,NULL),
('0aa15858-ebc5-4623-af72-d724ed87783f','Entre o discurso e o movimento','entre-o-discurso-e-o-movimento-kueh1','A versão oficial é de normalidade','O discurso público insiste em estabilidade, alinhamento institucional e compromisso com agendas que, ao menos no papel, seguem previsíveis. Mas, como quase sempre na política, o que se diz em público não revela completamente o que se constrói nos bastidores.\n\nNo Paraná, assim como no Brasil, o cenário recente tem sido marcado por uma movimentação silenciosa — daquelas que não aparecem em coletivas, nem em notas oficiais, mas que se manifestam em agendas paralelas, encontros reservados e mudanças sutis de posicionamento.\nNada disso é, por si só, incomum.\n\nA política se organiza justamente nesse espaço: entre o que é anunciado e o que é articulado.\nO ponto de atenção está no descompasso.\n\nEnquanto o discurso projeta continuidade, os sinais indicam reorganização. Lideranças que até então orbitavam o mesmo campo começam a recalibrar suas posições. Interlocutores mudam, prioridades são revistas, e alianças — ainda que não rompidas — passam a operar sob novas condições.\n\nEsse tipo de movimento raramente é explicado de forma direta.\nEm vez disso, ele aparece diluído em expressões genéricas: \n\n> “ajustes”, “diálogo permanente”, “reavaliação de cenário”\n\nTermos que, na prática, funcionam mais como proteção narrativa do que como explicação.\n\nE é justamente aí que o contexto local encontra o nacional.\nO que se observa no Paraná não está isolado. Há uma sintonia com o ambiente político mais amplo, em que a antecipação de cenários futuros começa a influenciar decisões presentes. A política, afinal, raramente reage apenas ao agora — ela se antecipa ao que pode vir.\n\n**Nesse processo, o discurso cumpre um papel central.**\n\nNão apenas como instrumento de comunicação, mas como ferramenta de construção de realidade. Ao afirmar estabilidade, busca-se produzi-la. Ao evitar conflitos, tenta-se contê-los antes que se tornem visíveis.\nMas o discurso tem limites.\n\nEle organiza a percepção, mas não elimina a dinâmica real do poder — que segue em movimento, ainda que de forma discreta.\nNo fim, o que se vê é um cenário duplo.\n\nDe um lado, a narrativa pública de equilíbrio.\nDe outro, a reorganização silenciosa que antecipa novos arranjos.\n\nE como quase sempre na política, entender o que está acontecendo passa menos pelo que é dito — e mais pelo que, cuidadosamente, não é.\n',NULL,'/api/media/materia/novo-1777139436586-b7047mie5/imagens/1777139436905-PALACIO-IGUAÇU.jpg',NULL,0,'archived','2026-04-25 19:50:07.613','2026-04-25 17:51:16.258','2026-04-26 15:27:52.217','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,1,NULL),
('1150a3a1-d675-417b-8b13-02cf0a577f7c','Porque a esquerda do Paraná irá votar no candidato de Ratinho Junior','porque-a-esquerda-do-parana-ira-votar-no-candidato-de-ratinho-junior-0z7od','O caso Flávio Bolsonaro/Vorcaro pode reorganizar a eleição no Paraná — e abrir mais espaço para Ratinho Junior. Os acontecimentos nacionais envolvendo Flávio Bolsonaro e Daniel Vorcaro começam a produzir reflexos que vão além da disputa presidencial.','No Paraná, o impacto político pode ser ainda mais sensível, isso porque a eleição estadual paranaense possui uma característica muito específica: ela mistura fortemente política local com influência nacional, mas sem depender integralmente da polarização Brasília x PT.\nE é justamente aí que Ratinho Junior parece encontrar vantagem.\n\n# Ratinho Junior preservou distância estratégica de Brasília.\nEsse está entre os principais ativos políticos do governador do Paraná.\nAo longo dos últimos anos, Ratinho Junior manteve relação institucional com Bolsonaro, dialogou com Lula, evitou radicalização nacional e preservou, com muito trabalho e investimentos, a imagem de gestor estadual. \n\nIsso produziu um efeito importante: o governador não ficou preso ao desgaste político permanente de Brasília.\n\n> Enquanto a política nacional vive de escândalos, polarização, conflitos judiciais e desgaste ideológico constante, Ratinho construiu uma narrativa regional com obras, infraestrutura, interiorização, gestão, investimento público e aprovação administrativa. \n\n# Flávio Bolsonaro ajuda ou prejudica Sergio Moro?\nSergio Moro continua sendo um nome forte na disputa pelo governo do Paraná, pelo menos no universo atingido pelas pesquisas.\n\nMas existe um detalhe delicado. Moro depende fortemente do eleitorado bolsonarista/conservador. E o caso Vorcaro cria um sério problema para esse campo político: desgaste moral, associação com bastidores financeiros, perda parcial do discurso anti-sistema e desconforto em parte da direita tradicional. \n\nMesmo que Moro não esteja diretamente envolvido no caso, o ambiente político tende a gerar desgaste indireto por associação ideológica.\nEspecialmente porque Moro precisa do eleitor bolsonarista, mas também tenta preservar imagem técnica e ética. \n\n**A esquerda sofre no Paraná.**\nEsse talvez seja hoje o maior problema do campo progressista estadual.\nRequião Filho aparece com alta rejeição (a maior entre os pré-candidatos), dificuldade de expansão, pouca capilaridade estadual e teto eleitoral aparentemente limitado. \nAlém disso, parte significativa do eleitor petista não possui forte conexão emocional com o PDT no Paraná. \n\n> E existe outro fator decisivo: o PT paranaense jamais esqueceu o papel de Sergio Moro na prisão de Lula. \n\nIsso cria um bloqueio político muito forte, praticamente intransponível.\n\n# A esquerda pode adotar voto estratégico contra Moro.\nEsse cenário começa a ser discutido silenciosamente nos bastidores políticos.\nSe a eleição caminhar para Moro x Sandro Alex, candidato apoiado por Ratinho Junior, parte do eleitorado de esquerda poderá entrar numa lógica pragmática: **evitar a vitória de Moro**. **E eleitor de esquerda, não anula voto.**\nE isso não seria totalmente novo na política brasileira. Em eleições polarizadas, setores ideológicos frequentemente fazem voto útil, voto defensivo ou alianças indiretas. \n\n# O eleitor anti-Moro.\nEsse pode vir a ser o movimento mais inteligente do grupo governista. Sandro Alex poderá tentar ocupar o campo da gestão, continuidade administrativa, moderação e estabilidade política. \nOu seja, uma candidatura menos ideológica e mais gerencial.\nIsso pode atrair cada vez mais prefeitos, centro político, parte do empresariado, setores conservadores moderados e até eleitores de esquerda anti-Moro. \n\n**O interior dará as cartas.**\nOutro ponto importante é que o eleitor do interior tende a valorizar obras, a presença regional, os investimentos e o apoio aos municípios. \nE Ratinho Junior construiu justamente sua força política nesse ambiente.\nSe Sandro Alex conseguir herdar parte dessa estrutura, consolidar apoio de prefeitos e crescer no interior, a disputa deixa de ser apenas “quem é mais conhecido” e passa a ser \"quem possui maior capacidade de coalizão regional\".\n\n**Moro tem força eleitoral?**\nSeria um erro subestimar Sergio Moro. Ele continua extremamente conhecido, forte nas cidades médias, competitivo em Curitiba e muito consolidado no eleitorado conservador. \nAlém disso, ainda carrega o símbolo da Lava Jato, do combate à corrupção e forte recall político.\n\n> O problema é que notoriedade não garante crescimento infinito e rejeição também pesa em segundo turno. \n\n# **O segundo turno da rejeição.**\nEsse é o cenário mais provável hoje. Não necessariamente vencerá o mais amado. Pode vencer o menos rejeitado.\nE nesse ponto Ratinho Junior aparece muito forte politicamente. Sandro Alex tende a herdar parte dessa imagem, enquanto Moro mantém rejeição alta no campo progressista. \n\n**E aí?**\nOs episódios envolvendo Flávio Bolsonaro e Daniel Vorcaro não irão destruir o campo conservador no Paraná, mas já fizeram um grande estrago e, seguramente, estarão entre os principais temas de debates nesta eleição.\n\n> Essa relação nacional, muito mal explicada até agora, pode e deve alterar o ambiente político da sucessão estadual.\n\nEspecialmente porque Ratinho Junior preservou distância da radicalização nacional, Moro continua fortemente associado ao bolsonarismo e a esquerda paranaense parece sem candidatura competitiva própria.\nNesse cenário, cresce a possibilidade de voto útil, alianças silenciosas e rearranjos inesperados no segundo turno. \n\n**Fato.**\nO Paraná pode viver uma eleição menos ideológica do que parece.\nMoro lidera pela notoriedade, mas Ratinho domina pela estrutura e aprovação.\nE a esquerda, sem nome competitivo e sem disposição para apoiar Moro, deve ser empurrada para uma escolha pragmática: impedir a entrada da Lava Jato no Palácio Iguaçu. ***Como isso pode acontecer? Com o voto no candidato de Ratinho Junior, o deputado federal Sandro Alex.***\n',NULL,'/api/media/materia/novo-1779282629871-5pf60gc10/imagens/1779282632724-Ratinho__Sandro__Lula_e_Fl_vio.png',NULL,0,'published','2026-05-20 22:57:40.141','2026-05-20 13:11:38.606','2026-05-29 13:25:54.395','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',15,NULL),
('127f7ea1-46ec-4152-8bb0-64fc1a4c8d48','Governo do Paraná adia a inauguração da Ponte da Vitória','governo-do-parana-adia-a-inauguracao-da-ponte-da-vitoria-ok9nk','A população das duas cidades está convidada para assistir ao show em Caieiras e na Prainha, que vão ser os melhores locais para visualização completa da apresentação.','Com a previsão do tempo indicando muita chuva, ventos fortes e raios para o Litoral paranaense na próxima quarta-feira (29), com chance de precipitações ainda na quinta-feira (30), o Governo do Paraná decidiu alterar a data de \n\n> inauguração da Ponte de Guaratuba para a próxima sexta-feira (1º), às 16h\n\n. A cerimônia de inauguração será na cabeceira da ponte do lado de Guaratuba.\n\nO evento terá dois momentos. O primeiro, na cabeceira da ponte em Guaratuba, é reservado para autoridades e convidados. O segundo será o hasteamento da bandeira do Paraná perto da parte estaiada na ponte, seguido de um show de fogos, drones e luzes. A população poderá acessar a ponte após o show. As forças de segurança e o Departamento de Estradas de Rodagem do Paraná (DER-PR) vão orientar a movimentação das pessoas e do fluxo dos veículos.\n\nA população das duas cidades está convidada para assistir ao show em Caieiras e na Prainha, que vão ser os melhores locais para visualização completa da apresentação. A TV Paraná Turismo fará a transmissão ao vivo do evento, que também poderá ser assistido nas redes sociais do Governo do Paraná.\n\nInformações importantes:\n\n- O acesso da população à Ponte de Guaratuba vai acontecer apenas após o show de fogos e drones. Antes disso haverão bloqueios nas proximidades das cabeceiras.\n\n- Os locais mais indicados para a visualização dos shows são Caieiras e Prainha, que terão telões e arquibancadas.\n\n- O ferry boat continuará funcionando durante todo o período, mantendo o deslocamento entre os municípios.',NULL,'/api/media/materia/novo-1777310845736-w9sus9c7k/imagens/1777310845966-Ponte_alta_resolu__o.jpg',NULL,0,'published','2026-04-27 21:22:16.433','2026-04-27 17:28:03.402','2026-05-10 02:53:41.920','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Maquete DER',3,NULL),
('138afc20-3cad-42d9-9626-34cca7f2130c','Câmara aprova projeto que regulamenta a jornada de trabalho de policiais e bombeiros militares','camara-aprova-projeto-que-regulamenta-a-jornada-de-trabalho-de-policiais-e-bombeiros-militares-apa3z','Proposta limita a jornada comum a 144 horas mensais; texto vai ao Senado','A Câmara dos Deputados aprovou projeto de lei que limita a 144 horas mensais a jornada de trabalho de policiais militares e bombeiros militares. A proposta será enviada ao Senado.\n\nDe autoria do deputado Sargento Portugal (Pode-RJ) e outros, o Projeto de Lei 5967/23 foi aprovado na forma de substitutivo do relator, deputado Coronel Meira (PL-PE).\n\n> O texto fixa a jornada de trabalho normal nessas 144 horas mensais, exceto para as escalas dos serviços ordinários com carga horária de 24 horas por plantão.\n\nNesses casos, o limite mensal de horas será de 192 horas devido à natureza das atividades e caráter do serviço.\n\nQuando a rotina ordinária de serviço trabalhada exceder as 144 horas mensais, o excesso deverá ser adicionado a banco de horas como crédito de horas extras. Se o trabalho a mais ocorrer em domingos e feriados, a contagem das horas do banco será em dobro.\n\nFonte: Agência Câmara de Notícias',NULL,'/api/media/materia/novo-1777553590305-09mk6i63t/imagens/1777553592734-Coronel_Meira.jpg',NULL,0,'published','2026-04-30 12:57:49.635','2026-04-30 12:57:49.638','2026-05-05 09:20:42.661','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Agência Câmara de Notícias',4,NULL),
('13b871bb-7702-4621-bf34-70de2d9da1ca','Pesquisa IRG: Sandro Alex entra definitivamente na disputa — e o apoio de Ratinho Junior começa a produzir efeito real.','pesquisa-irg-sandro-alex-entra-definitivamente-na-disputa-e-o-apoio-de-ratinho-junior-comeca-a-produzir-efeito-real-nw3uk',NULL,'A nova pesquisa IRG divulgada nesta quinta-feira (21) consolidou um movimento político que já vinha sendo percebido nos bastidores do Paraná. Sandro Alex deixa de ser apenas o nome escolhido pelo grupo governista e passa a ser um candidato eleitoralmente competitivo.\n\nO crescimento do pré-candidato do PSD ocorre justamente no momento em que Ratinho Junior intensifica viagens pelo interior, amplia entregas de obras, fortalece encontros regionais do partido e coloca Sandro Alex ao seu lado em praticamente todos os eventos políticos. \n\n**A pesquisa mostra que essa estratégia funciona.**\nRatinho Junior conseguiu transformar aprovação em ativo eleitoral.\nEsse é o principal dado político do levantamento. Ratinho Junior possui hoje uma das maiores aprovações entre governadores do Brasil, forte presença regional, apoio massivo de prefeitos, enorme capacidade de comunicação popular e um carisma inigualável. \n\n> O desafio do PSD era transformar essa popularidade em transferência de votos. O IRG demonstra que isso começa a acontecer de forma concreta.\n\nSandro Alex cresce exatamente no momento em que aparece mais ao lado do governador, participa das entregas, assume discurso de continuidade e passa a ser apresentado como herdeiro político do atual governo. \n\n**Moro lidera, mas enfrenta desgaste indireto do ambiente nacional.**\nSergio Moro continua liderando a disputa. Sua força eleitoral permanece sustentada por alta notoriedade, imagem construída na Lava Jato, forte presença em Curitiba e apoio consolidado no eleitorado conservador. \n\nMas o cenário político mudou nos últimos dias. Moro passou a dividir espaço com o desgaste nacional envolvendo Flávio Bolsonaro e o banqueiro Daniel Vorcaro.\nO senador Flávio Bolsonaro, principal nome do PL na disputa presidencial, foi atingido por denúncias e questionamentos envolvendo relações com Vorcaro, situação que provocou forte repercussão política e desgaste nas pesquisas nacionais.\n\n**Isso produz e deverá seguir gerando reflexos no Paraná.**\nPorque Moro depende fortemente do mesmo campo político conservador e bolsonarista. Enquanto Ratinho Junior mantém distância estratégica das crises de Brasília e concentra discurso em gestão, obras e desenvolvimento regional, Moro acaba mais vinculado ao ambiente nacional de confronto político.\n\n**Sandro cresce justamente no campo da gestão.**\nOutro dado importante da pesquisa: Sandro Alex cresce menos pelo discurso ideológico e mais pela associação administrativa.\nE o mais importante, é que o eleitor começa a enxergá-lo como continuidade do governo, nome ligado à infraestrutura, representante das entregas do Estado e candidato apoiado diretamente pelo governador mais aprovado do país. \n\nIsso muda completamente a dinâmica da eleição. A disputa deixa de ser apenas “quem é mais conhecido” e passa a ser “quem representa continuidade de um governo altamente aprovado”.\n\n**O interior do Paraná ganha protagonismo.**\nA pesquisa também confirma algo importante: o interior se tornou o principal terreno político do grupo governista.\nRatinho Junior percorre o estado entregando casas, asfaltando estradas, inaugurando escolas, liberando recursos e fortalecendo prefeitos aliados. \n\n> Sandro Alex, para descontentamento de Moro, acompanha essa agenda permanentemente.\n\nIsso gera exposição regional, associação direta com resultados e fortalecimento político gradual. \nEnquanto Moro concentra força na notoriedade urbana, Sandro cresce na estrutura política estadual.\n\n**Requião Filho permanece isolado.**\nO levantamento também consolida a dificuldade enfrentada por Requião Filho.\nA candidatura do PDT mantém núcleo fiel, mas apresenta alta rejeição, baixo crescimento e dificuldade clara de expansão. \nAlém disso, parte da esquerda do Paraná continua resistente a Sergio Moro.\nIsso cria um cenário curioso, pois, Moro enfrenta rejeição forte no campo progressista, Requião Filho não consegue crescer e Sandro Alex passa a ocupar espaço de candidatura moderada e administrativa.\n \n**E aí? O que a pesquisa realmente mostra?**\nA IRG revela três movimentos muito claros:\n1 - Moro segue liderando pela notoriedade;\n2 - Ratinho Junior conseguiu colocar Sandro Alex definitivamente na disputa;\n3 - O ambiente nacional começa a produzir desgaste indireto sobre o campo bolsonarista.\n\n**Fato.**\nA eleição do Paraná mudou de patamar. Sergio Moro continua forte, mas Sandro Alex agora cresce sustentado por estrutura política, interiorização, apoio de prefeitos, obras espalhadas pelo estado e, principalmente, pela força eleitoral de Ratinho Junior. \n***Enquanto Moro aparece associado ao ambiente nacional do PL e ao desgaste envolvendo Flávio Bolsonaro e Daniel Vorcaro, Ratinho preserva distância de Brasília e mantém discurso focado em gestão.\nE isso começa a aparecer claramente nas pesquisas.***\n',NULL,'/api/media/materia/novo-1779376822366-b0a1ga14i/imagens/1779376831145-PESQUISA_IRG_21_MAIO.png',NULL,0,'published','2026-05-21 15:23:26.677','2026-05-21 15:21:32.957','2026-06-01 03:55:41.918','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',7,NULL),
('170eae16-e4ed-4cc4-9ebe-a0b56153c1a6','Ganhando o Mundo: quando a educação pública do Paraná atravessa fronteiras.','ganhando-o-mundo-quando-a-educacao-publica-do-parana-atravessa-fronteiras-0bw46','Durante décadas, a política educacional brasileira acostumou o país a um padrão limitado: discutir falta, administrar carência e tratar o estudante ','Durante décadas, a política educacional brasileira acostumou o país a um padrão limitado: discutir falta, administrar carência e tratar o estudante da rede pública como alguém destinado a sonhar pequeno.\nO programa Ganhando o Mundo rompe justamente com essa lógica. E talvez esse seja o aspecto mais importante — e menos debatido — da iniciativa do governo do Paraná.\n\n**O programa não exporta apenas estudantes. Exporta expectativa.**\nQuando alunos da rede estadual embarcam para os Estados Unidos, Canadá, Austrália ou Nova Zelândia, não é apenas um intercâmbio acontecendo. \n\n> É uma quebra simbólica de limite social. O estudante da escola pública deixa de enxergar o mundo como algo distante e passa a perceber que também pode ocupar espaços globais.\n\n**O Ganhando o Mundo Agrícola carrega um significado ainda maior.**\nA experiência dos estudantes agrícolas nos Estados Unidos revela um dos pontos mais inteligentes do programa. Conecta, educação, tecnologia, agronegócio e formação técnica internacional. \nNão se trata apenas de ensinar inglês. Trata-se de inserir jovens do interior do Paraná em ambientes de inovação agrícola de escala mundial. E isso dialoga diretamente com a identidade econômica do estado.\n\n**O Paraná constrói algo raro na educação pública.**\nO que o programa produz não é apenas experiência cultural. Produz repertório, autoestima, ambição profissional e transformação de horizonte social. \nQuando um estudante da rede pública volta de Iowa, Toronto ou Auckland, ele retorna diferente. E isso inevitavelmente impacta a escola, a família, a cidade e o ambiente ao redor. \n\n**A crítica inevitável: custo ou prioridade?**\nComo toda política pública de grande escala, o programa também desperta questionamentos. Há quem argumente que o investimento deveria priorizar exclusivamente problemas estruturais internos da educação. É uma discussão legítima, mas existe um contraponto importante: \n\n> Governos não transformam educação apenas construindo paredes. Transformam também ampliando perspectiva.\n\nE esse é o maior mérito do Ganhando o Mundo, quando mostra ao aluno da rede pública que o mundo não termina no limite geográfico da sua cidade.\n\n**O programa ajuda a construir a imagem política do governo.**\nPoliticamente, o impacto também é evidente. O programa reforça uma característica que o governo Ratinho Junior conseguiu consolidar: gestão associada à modernização e oportunidade.\nE faz isso em uma área extremamente sensível: educação, juventude e mobilidade social. \n\n**A força simbólica do programa.**\nExiste algo profundamente político — no melhor sentido — quando o filho de uma família simples embarca pela primeira vez para estudar fora do país com apoio do Estado. Porque isso altera uma lógica histórica brasileira: a ideia de que experiências internacionais pertencem apenas à elite.\n\n**E aí?**\nO Ganhando o Mundo é uma das políticas públicas mais simbólicas do atual governo do Paraná. Não apenas pelo número de estudantes enviados ao exterior, mas pelo que o programa representa: ampliação de horizonte, mobilidade social e valorização da educação pública. \nFato.\n\n> Durante muito tempo, o estudante da rede pública brasileira foi treinado para acreditar no limite. O Ganhando o Mundo faz o contrário\n\nEnsina que o aluno pode atravessar fronteiras. E, na política, poucas coisas geram tanto impacto quanto um governo que transforma expectativa em possibilidade real. Não se trata se o governante é do partido A ou B. Se trata, sim, de fazer acontecer. Que os bons projetos tenham vida longa! Que a descontinuidade de um mandato político não represente o fim do sonho de um estudante. \n',NULL,'/api/media/materia/novo-1778760327754-vw301u6s7/imagens/1778760331751-GANHANDO_O_MUNDO.jpg',NULL,0,'published','2026-05-14 15:05:36.704','2026-05-14 12:06:50.754','2026-05-27 03:08:38.053','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Lucas Fermin/SEED',8,NULL),
('1876f27e-b4e3-4b0d-8c62-78d963221f79','Ratinho Junior ainda é o principal ativo político do Paraná','ratinho-junior-ainda-e-o-principal-ativo-politico-do-parana-r4ubg','Os encontros do PSD mostram um governador: ativo, presente','**Por onde passa, o governador mobiliza atenção espontânea.**\nAbraços, fotos, conversas rápidas, demonstrações de carinho e recepção calorosa se repetem em praticamente todas as agendas. E isso não parece fabricado.\n\nRatinho Junior consolidou um perfil político raro: proximidade popular sem desgaste evidente. ***Mesmo no último ano de governo, não transmite distanciamento ou clima de despedida***. Pelo contrário. \n\n> Os encontros do PSD mostram um governador: ativo, presente, emocionalmente conectado às bases  e ainda disposto a percorrer o estado intensamente. \n\n**O partido trabalha claramente a ideia de continuidade.**\nOs eventos em cidades como Colombo e Piraquara revelam uma estratégia política muito evidente: transformar o legado administrativo de Ratinho Junior em plataforma eleitoral. As obras, os investimentos regionais, a infraestrutura e os indicadores positivos do governo aparecem constantemente nos discursos e conversas políticas. A mensagem é simples: “**o Paraná avançou e não pode interromper esse ciclo**”. \n\nNesses encontros, a frase ***\"retroceder jamais\"***, tem surgido em todas as falas e marcado o encerramento dos discursos, com forte apoio de lideranças e moradores que lotam os espaços.\n### Sandro Alex amadurece como pré-candidato e começa a ocupar o espaço de sucessor político.\nEsse é o ponto mais importante dos encontros seja justamente o desempenho de Sandro Alex. O pré-candidato deixou de aparecer apenas como nome apresentado pelo governador. Agora começa a demonstrar **domínio administrativo, conhecimento da máquina pública, segurança política e discurso alinhado à continuidade da gestão**. \nNos encontros recentes, Sandro Alex mostrou desenvoltura crescente, o que começa a ser percebido pelas lideranças locais.\n\n**Existe sintonia — e preparação.**\nOutro aspecto que chama atenção é a organização política do projeto. A comunicação, o discurso e a presença pública demonstram que existe: coordenação, alinhamento e uma assessoria politicamente eficiente ao redor do pré-candidato. Nada parece improvisado. A estratégia do PSD claramente busca ampliar conhecimento estadual de Sandro Alex, aproximá-lo emocionalmente das bases e consolidar a associação direta com Ratinho Junior.\n\n**O momento é da Região Metropolitana, como o centro da estratégia.**\nColombo e Piraquara mostraram algo importante: há mobilização real. Centenas de pessoas participaram, ouviram, aplaudiram e acompanharam os discursos.\nE o partido aposta justamente nisso:\n\n**- presença física** \n\n**- proximidade** \n\n**- construção regional** \n\n**- fortalecimento das lideranças municipais.** \n\nO PSD entende que a eleição estadual passa necessariamente pelo interior e pela Região Metropolitana.\n\n**O governo bem avaliado tenta transformar aprovação em sucessão.**\nEsse é hoje o maior desafio político do grupo governista. Ratinho Junior possui aprovação elevada e presença política consolidada.\nAgora, o objetivo é transformar esse capital político em transferência gradual de confiança para Sandro Alex.\nE os encontros regionais funcionam exatamente como instrumento dessa construção.\n\n**E aí?**\nO PSD parece ter compreendido algo importante sobre 2026: a sucessão não será construída apenas em propaganda. Será construída em presença política permanente. Os encontros municipais mostram um partido: organizado, mobilizado e decidido a consolidar a ideia de continuidade administrativa no Paraná. \n\n**Fato.**\nRatinho Junior, por onde passa, atrai multidões, atenção e carinho espontâneo. E o PSD trabalha para que parte desse capital político seja absorvido por Sandro Alex. O que se vê nos encontros pelo estado não é apenas pré-campanha. É a tentativa clara de transformar aprovação em continuidade.\nE, até aqui, o projeto parece cada vez mais sincronizado.\n',NULL,'/api/media/materia/novo-1778674285072-y24xauna1/imagens/1778674287338-com_RATINHO_JR_em_Piraquara.jpeg',NULL,0,'published','2026-05-19 12:11:44.463','2026-05-13 12:14:24.800','2026-05-27 02:19:01.125','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos',8,NULL),
('1c3b6b41-c2a5-4a41-9d98-6d649fe3f9ec','A política fora da política','a-politica-fora-da-politica-y94e3','Na prática, ela expõe uma fragilidade: a dificuldade de transformar posição em ação.','Existe um tipo de candidatura que se constrói fora da política tradicional — e depois tenta governar dentro dela.\nO problema é que os dois mundos não funcionam da mesma forma.\n\n> De fora, o sistema parece simples:\n> há certo e errado, decisão e consequência.\n\nDe dentro, ele é outra coisa:\nnegociação, composição, limite institucional, conflito permanente.\n\nA inconsistência aparece quando alguém transita de um campo para o outro sem ajustar a lógica.\n\n> Continua falando como quem observa, mas precisa agir como quem governa.\n\nE essa transição não é automática.\nNa prática, ela expõe uma fragilidade: a dificuldade de transformar posição em ação.\n',NULL,'/api/media/materia/novo-1777992302995-7uc6nb6xf/imagens/1777992306600-ALIENIGENAS.png',NULL,0,'published','2026-05-05 14:47:44.461','2026-05-05 14:45:27.889','2026-05-09 18:08:57.983','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,8,NULL),
('1d50e6b1-59c7-413e-9aa8-c346b270df30','Ponte da Vitória: esforços concentrados nos acessos e instalação de iluminação','ponte-da-vitoria-esforcos-concentrados-nos-acessos-e-instalacao-de-iluminacao-rjqgp',' Do lado de Matinhos, estão sendo aplicadas camadas finais de asfalto no acesso mais próximo do município','A poucos dias da inauguração da Ponte de Guaratuba, já denominada Ponte da Vitória, marcada para quarta-feira (29/04), o trabalho segue em ritmo intenso para a sonhada entrega. A nova ligação rápida entre Guaratuba a Matinhos realiza o desejo de mais de 40 anos da população.\nPara que a inauguração seja um completo sucesso, as equipes do consórcio construtor trabalham com foco especial na qualificação dos acessos de ambos os lados e na instalação da sinalização necessária e da iluminação.\n\nNo acesso de Guaratuba, além da instalação de um painel de contagem de ciclistas que vão atravessar a ponte, segue a aplicação de grama na rotatória, além da pintura da sinalização horizontal e instalação de placas de sinalização, esses dois últimos também na própria ponte. O último trecho de guarda-rodas (separando a pista de rolamento do passeio), também segue em andamento.\n\nAs equipes estão produzindo a massa asfáltica que será aplicada em Caieiras. Serviços de acabamento em meio-fio e caixa de drenagem também estão nos estágios finais.\n\nDo lado de Matinhos, estão sendo aplicadas camadas finais de asfalto no acesso mais próximo do município e preparada a pavimentação em terra armada. Também está sendo concluída a rampa de ligação da ponte com a rodovia.\nOs esforços se concentram, ainda, na instalação do sistema de iluminação nos mastros, o que vai garantir visibilidade e segurança durante a noite, além de valorizar o aspecto arquitetônico da estrutura. Seguem, ainda, os serviços de limpeza da pista, organização do canteiro de obras e ajustes finais.\n\n**PONTE** – A nova ligação fixa sobre a Baía de Guaratuba representa um investimento de mais de R$ 400 milhões do Governo do Estado e é considerada uma das maiores obras de infraestrutura em andamento no Paraná. \n\n> Com 1.240 metros de extensão, a estrutura conta com quatro faixas de tráfego, além de ciclovia e áreas destinadas a pedestres.\n\n Projetada para substituir a travessia por ferry-boat, a estrutura vai reduzir o tempo de deslocamento entre os municípios para cerca de dois minutos.\n',NULL,'/api/media/materia/1d50e6b1-59c7-413e-9aa8-c346b270df30/imagens/1777298816258-ponte-noite.jpg',NULL,0,'published','2026-04-27 14:07:37.654','2026-04-26 19:59:47.154','2026-05-29 23:46:42.684','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos/AEN',20,NULL),
('20d00801-bbe6-41d4-b03e-84c3b522677c','Manifestação no centro de Curitiba reúne duas mil pessoas contra a cassação do mandato do deputado Renato Freitas','manifestacao-no-centro-de-curitiba-reune-duas-mil-pessoas-contra-a-cassacao-do-mandato-do-deputado-renato-freitas-4t3wc','Seguindo um carro de som, os manifestantes caminharam pela Av. Marechal Deodoro,','Portando cartazes com os dizeres “Renato Fica”, cerca de duas mil pessoas se reuniram na Praça Santos Andrade, na escadaria da UFPR, em protesto contra o ato dos deputados membros da Comissão de Ética, da Alep, que pode levar a cassação do mandato do deputado estadual Renato Freitas (PT).\n\nParticiparam do encontro, eleitores de Freitas, vereadores, deputados estaduais, a deputada federal Gleisi Hofmann e anônimos que não aceitam a cassação do mandato do parlamentar, o que pode acontecer nas próximas sessão da Assembleia Legislativa.\n\nSeguindo um carro de som, os manifestantes caminharam pela Av. Marechal Deodoro, até a Praça Tiradentes, acompanhando os discursos de vários oradores, que denunciaram a tentativa de cassação do mandato de “um deputado negro, de esquerda, cuja origem é a periferia.\n\nO presidente da Assembléia Legislativa deve decidir nos próximos dias a data em que o parecer de cassação, da Comissão de Ética, será votado em plenário. \nO parecer registrou 8 votos a favor e 2 contra, na CCJ (Comissão de Constituição e Justiça) da Alep, que aprovou no dia 2 de junho a recomendação de cassação, por quebra de decoro parlamentar, porque Renato Freitas se envolveu em uma briga na rua, no centro de Curitiba. \n',NULL,'/api/media/materia/novo-1780788144896-t69tfe9fo/imagens/1780788147274-manifesta__o_I.jpeg',NULL,0,'published','2026-06-06 23:24:35.780','2026-06-06 23:23:43.780','2026-06-07 03:46:14.616','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Renan Gabriel Ribeiro',4,NULL),
('242c5b41-1b29-4f5c-8240-fccd92ee13d1','30ª Expo Turismo Paraná reforça protagonismo do setor no Estado','30a-expo-turismo-parana-reforca-protagonismo-do-setor-no-estado-wmb6w','Maior evento do setor no Sul do Brasil acontece nos dias 7 e 8 de maio, em Curitiba, com foco na geração de negócios, hospitalidade e na valorização dos 18 territórios turísticos paranaenses.','Teve inicio nesta quinta-feira (07) e vai até amanhã (08) a 30ª edição da Expo Turismo Paraná – ABAV, no pavilhão Viasoft Experience, na Cidade Industrial de Curitiba. Ao longo de três décadas, o evento se consolidou como o principal encontro do setor no Estado e uma das referências da região Sul, reunindo agentes de viagens, operadoras, destinos e instâncias de governança regional em torno da promoção e comercialização do turismo paranaense. A estrutura é organizada pela Secretaria de Estado do Turismo (Setu), em parceria com a ABAV-PR.\n\nCom programação das 13h às 20h nesta quinta-feira e das 12h às 18h na sexta-feira, \n\n> a feira concentra dois dias de intensa movimentação com rodadas de negócios, apresentações culturais, experiências gastronômicas e articulações institucionais. \n\nA estrutura contempla estandes temáticos voltados à segmentação turística e uma sala exclusiva para reuniões estratégicas entre municípios, entidades e parceiros do setor.\n\nO secretário de Estado do Turismo, Luciano Bartolomeu, destaca que o evento representa um momento de conexão direta entre quem constrói o turismo no dia a dia e quem movimenta o mercado. “O turismo só cresce quando existe equilíbrio. Valor justo atrai mais, fideliza o visitante e fortalece toda a cadeia. A Expo é esse ponto de encontro onde o Paraná se apresenta com verdade, mostrando que aqui o turista é respeitado, não explorado”, afirma.\n\nSegundo ele, a proposta é consolidar o Estado como um destino competitivo sem abrir mão da experiência do visitante e do fortalecimento do mercado local. “Temos uma diversidade enorme distribuída pelos 399 municípios. O que queremos é ampliar oportunidades, gerar resultado para quem trabalha com turismo e fazer com que mais pessoas escolham ficar aqui no Paraná”, completa.\n',NULL,'/api/media/materia/novo-1778182724258-mvltl09io/imagens/1778182725699-expoturismo.jpg',NULL,0,'published','2026-05-07 19:40:21.333','2026-05-07 19:40:21.359','2026-05-31 23:46:33.071','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: SETU',9,NULL),
('290e93fb-b388-404b-99c3-8f56ff2d7f37','Há 54 anos nascia o Calçadão da Rua XV. A primeira via exclusiva para pedestres do Brasil','ha-54-anos-nascia-o-calcadao-da-rua-xv-a-primeira-via-exclusiva-para-pedestres-do-brasil-qwvi9','Em 1984, o calçadão da Rua XV reuniu cerca de 40 mil pessoas no comício das Diretas Já, campanha pelas eleições diretas para presidência da República, abrindo caminho do processo de redemocratização do país.','O calçadão da Rua XV, que nesta terça-feira (19/5) celebra seus 54 anos, é um símbolo da Curitiba inovadora, humana e visionária que ajudou a inspirar cidades em todo o Brasil e no mundo. Essa obra histórica de Jaime Lerner segue viva no cotidiano dos curitibanos, tornou-se um cartão-postal e reafirma a capital como referência em soluções urbanas criativas e sustentáveis. \n\n****História** **\n\n•	No anoitecer do dia 19 de maio de 1972 (sexta-feira), equipes da Prefeitura de Curitiba desembarcaram de caminhões para implantar o calçadão na Rua XV de Novembro, entre a Rua Presidente Faria e a Praça Osório.\n\n•	O calçadão da Rua XV de Novembro foi projetado pelo Instituto de Pesquisa e Planejamento Urbano de Curitiba (Ippuc) para ser o eixo de circulação da área central com o Setor Histórico e o sistema de transporte coletivo: atualmente, praças e vias do entorno são pontos de partida e chegada de ônibus convencionais e BRTs (Praças Rui Barbosa, Tiradentes, Zacarias, Santos Andrade e Senador Correia, Travessa Nestor de Castro e as estações-tubo da Avenida Sete de Setembro e das ruas Presidente Faria e Visconde de Nacar).\n\n•	O calçadão da Rua XV de Novembro, com seus característicos pavimento em petit-pavê, postes republicamos, bancos e floreiras, é um patrimônio tombado como “Paisagem” por lei estadual do Paraná desde 1974. Qualquer intervenção precisa de aprovação do Patrimônio Histórico.\n•	Em 1984, o calçadão da Rua XV reuniu cerca de 40 mil pessoas no comício das Diretas Já, campanha pelas eleições diretas para presidência da República, abrindo caminho do processo de redemocratização do país.\n\n•	Assim como o próprio calçadão, outros cartões-postais se espalham pela via de pedestres: Bondinho da Leitura, Palácio Avenida (com seu famoso coral de Natal), Edifício Moreira Garcez (primeiro “arranha-céu de Curitiba”) e relógio alemão de 1914.\n\n•	No encontro do calçadão da Rua XV e Avenida Luiz Xavier, está a Boca Maldita com tradicionais cafés e bancas. O nome deste trecho do Centro remete à confraria organizada por um grupo de homens em 1956 e que virou ponto de encontro para discutir política e futebol. \n \n•	Os  inúmeros prédios históricos do calçadão da XV merecem ser apreciados pelos diferentes estilos arquitetônicos (eclético, neogótico e art noveau), com destaque para a construção neogótica, de 1905, na esquina com a Rua Monsenhor Celso (popularmente conhecida como Edifício Banestado) e a antiga Casa Louvre, de 1913 e em estilo art noveau, restaurada após um incêndio e que hoje abriga uma loja de roupas femininas entre a Rua Monsenhor Celso e Avenida Marechal Deodoro. \n\n•	Além da escultura em homenagem a Jaime Lerner, inaugurada pelo prefeito Eduardo Pimentel em 2026 e de autoria do escultor Elvo Benito Damo, o calçadão tem outras obras de arte, como a estátua de Enedina Alves Marques (primeira mulher negra a se formar engenheira), obra de Rafael Sartori, e o painel do Barão do Serro Azul, do artista Gardpam, na fachada da sede da Associação Comercial do Paraná (ACP).\n\n•	Diariamente, equipes da Limpeza Pública da Secretaria Municipal do Meio Ambiente fazem a varrição ou a lavagem do calçadão da Rua XV, serviços da Prefeitura que estão alinhados ao programa Curitiba de Volta ao Centro.\n\n•	Durante a programação do Natal de Curitiba, o calçadão da Rua XV recebe atrações muito aguardadas pelo público. Na edição de 2025, os destaques ficaram para a roda-gigante e decoração do Natal O Boticário na Rua XV e a tradicional feira na Praça Osório.  \n\n•	Desde 2025, o calçadão da Rua XV recebe o evento Domingo no Centro, com atividades e serviços gratuitos para toda a família uma vez por mês. A edição de maio do evento, que integra as ações do programa Curitiba de Volta ao Centro, ocorre no próximo domingo (24/5).\n',NULL,'/api/media/materia/novo-1779225572778-5tqlexvcw/imagens/1779225573856-DSC08700.jpg',NULL,0,'published','2026-05-19 21:20:53.421','2026-05-19 21:19:54.689','2026-05-29 13:47:49.912','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Renan Gabriel Ribeiro',10,NULL),
('299d0b43-e05b-4790-818a-0e77ab3b50a7','Entre o discurso e o movimento','entre-o-discurso-e-o-movimento-zfe9s','A versão oficial é de normalidade','O discurso público insiste em estabilidade, alinhamento institucional e compromisso com agendas que, ao menos no papel, seguem previsíveis. Mas, como quase sempre na política, o que se diz em público não revela completamente o que se constrói nos bastidores.\n\nNo Paraná, assim como no Brasil, o cenário recente tem sido marcado por uma movimentação silenciosa — daquelas que não aparecem em coletivas, nem em notas oficiais, mas que se manifestam em agendas paralelas, encontros reservados e mudanças sutis de posicionamento.\nNada disso é, por si só, incomum.\n\nA política se organiza justamente nesse espaço: entre o que é anunciado e o que é articulado.\nO ponto de atenção está no descompasso.\n\nEnquanto o discurso projeta continuidade, os sinais indicam reorganização. Lideranças que até então orbitavam o mesmo campo começam a recalibrar suas posições. Interlocutores mudam, prioridades são revistas, e alianças — ainda que não rompidas — passam a operar sob novas condições.\n\nEsse tipo de movimento raramente é explicado de forma direta.\nEm vez disso, ele aparece diluído em expressões genéricas: \n\n> “ajustes”, “diálogo permanente”, “reavaliação de cenário”\n\nTermos que, na prática, funcionam mais como proteção narrativa do que como explicação.\n\nE é justamente aí que o contexto local encontra o nacional.\nO que se observa no Paraná não está isolado. Há uma sintonia com o ambiente político mais amplo, em que a antecipação de cenários futuros começa a influenciar decisões presentes. A política, afinal, raramente reage apenas ao agora — ela se antecipa ao que pode vir.\n\n**Nesse processo, o discurso cumpre um papel central.**\n\nNão apenas como instrumento de comunicação, mas como ferramenta de construção de realidade. Ao afirmar estabilidade, busca-se produzi-la. Ao evitar conflitos, tenta-se contê-los antes que se tornem visíveis.\nMas o discurso tem limites.\n\nEle organiza a percepção, mas não elimina a dinâmica real do poder — que segue em movimento, ainda que de forma discreta.\nNo fim, o que se vê é um cenário duplo.\n\nDe um lado, a narrativa pública de equilíbrio.\nDe outro, a reorganização silenciosa que antecipa novos arranjos.\n\nE como quase sempre na política, entender o que está acontecendo passa menos pelo que é dito — e mais pelo que, cuidadosamente, não é.\n',NULL,'/api/media/materia/novo-1777151131106-guzvyzfn0/imagens/1777151130304-1777145555609-Discurso.jpg',NULL,0,'archived','2026-04-25 23:48:58.161','2026-04-25 21:06:07.652','2026-04-26 00:17:18.544','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',7,NULL),
('2ccb0e16-6937-4093-a285-0b818d217069','De crocodilo pré-histórico a carro de Fórmula 1, Curitiba reúne curiosidades em museus','de-crocodilo-pre-historico-a-carro-de-formula-1-curitiba-reune-curiosidades-em-museus-zf1a4','Espaços espalhados pela cidade guardam acervos inusitados e ajudam a contar diferentes histórias','Nesta terça-feira (5/5), a Prefeitura dá início à 1ª Semana de Museus de Curitiba, com uma programação voltada à formação, ao debate e à aproximação do público com os espaços expositivos da cidade. \n\n> O evento vai até quinta (7/5) e é aberto a todos os interessados no tema, além de reunir especialistas, gestores e pesquisadores da área.\n\nA iniciativa também é um convite para a população explorar espaços da cidade, que vão desde nomes conhecidos, como o do Museu Oscar Niemeyer (MON), até acervos menores, como o do Museu Ucraniano de Curitiba.\n\nO Museu Ucraniano de Curitiba, na sede da Sociedade Ucraniana do Brasil, no Centro, foi fundado em 1972 para preservar e divulgar a história da imigração ucraniana no Paraná. \nHorário: 13h às 17h (de segunda a sexta)\nEntrada: gratuita, com agendamento pelo telefone (41) 3224-5597\nEndereço: Al. Augusto Stellfeld, 795 – Centro.\n\n**PULMÃO DE AÇO**\nInstalado no prédio histórico da antiga Santa Casa, inaugurado em 1880, o Museu da História da Medicina do Paraná reúne um acervo com mais de 5 mil itens relacionados à evolução da medicina e da saúde no Estado.\nHorário: 9h às 18h30 (de segunda a sábado).\nEntrada: gratuita, com agendamento pelo site\nEndereço: Praça Rui Barbosa, 694 - Centro.\n\n**ESQUELETO DE ORCA**\nO Museu de História Natural Capão da Imbuia da Secretaria Municipal do Meio Ambiente fica dentro de uma Unidade de Conservação. O local abriga coleções científicas representativas da fauna original do Paraná, além de um bosque remanescente de floresta com araucária.\nHorário: 9h às 16h45 (de terça a domingo)\nEntrada: gratuita.\nEndereço: R. Professor Benedito Conceição, 407 – Capão da Imbuia.\n\n**ESTÔMAGO CABELUDO**\nFundado em 1910, o Museu Paranaense de Ciências Forenses preserva a história da Polícia Científica do Paraná. O acervo inclui instrumentos de perícia, ossadas, peças anatômicas e documentos históricos. A exposição está integrada ao espaço do antigo necrotério de Curitiba.\nHorário: 9h às 16h (de segunda a sexta)\nEntrada: gratuita, com agendamento pelo e-mail museuforense@policiacientifica.pr.gov.br\nEndereço: Av. Visconde de Guarapuava, 2.652 - Centro.\n\n**CRÂNIO DE CROCODILO PRÉ-HISTÓRICO**\nO Museu de Ciências Naturais da Universidade Federal do Paraná (UFPR) é referência nas áreas de Ciências Biológicas e História Natural no Estado. Ele reúne exemplares vivos, materiais preservados e réplicas que ajudam a compreender a biodiversidade e a evolução das espécies.\nHorário: 9h às 12h e 13h30 às 17h30 (de segunda a sexta).\nEntrada: gratuita.\nEndereço: Av. Coronel Francisco Heráclito dos Santos, 100 – Jardim das Américas.\n\n**MÚMIA TOTHMEA**\nO Museu Egípcio Rosacruz apresenta um amplo acervo dedicado à cultura do Egito Antigo, com mais de 700 peças entre originais e réplicas. O espaço reúne coleções diversas, incluindo objetos históricos e reproduções feitas por artistas brasileiros.\n\nEntre as peças que despertam curiosidade está a múmia de uma mulher egípcia. Batizada de Tothmea, é a única múmia egípcia verdadeira de corpo inteiro em exposição no Brasil. Com cerca de 2.700 anos, ela está em Curitiba desde 1995.\nHorário: 10h às 16h30 (de terça a sexta) e 10h às 16h (sábados, domingos e feriados)\nEntrada: paga.\nEndereço: R. Nicarágua, 2.641 – Bacacheri.\n\n**IMAGEM DE BOM DE JESUS DOS PINHAIS**\nO Museu de Arte Sacra da Arquidiocese de Curitiba (Masac) está instalado no anexo da Igreja da Ordem Terceira de São Francisco das Chagas, a mais antiga edificação da cidade. O acervo conta com mais de 800 peças, entre objetos litúrgicos, imagens sacras, mobiliário, documentos e obras de arte\n\nUm exemplar de grande valor histórico é a imagem de Bom Jesus dos Pinhais, em terracota e datada do século 17. O item, de autor desconhecido, integrou a antiga Igreja Matriz de Curitiba até 1876 e, após ser extraviado, foi preservado por uma família até a criação do museu.\nHorário: 9h às 12h e 13h às 18h (de terça a sexta) e 9h às 14h (sábados e domingos).\nEntrada: gratuita.\nEndereço: R. Claudino dos Santos, s/n°, Igreja da Ordem - Centro.\n\n**MALETA DE ALFREDO ANDERSEN**\nO Museu Casa Alfredo Andersen funciona na antiga residência, ateliê e escola do artista norueguês Alfredo Andersen. Considerado o pai da pintura paranaense, Andersen chegou em Curitiba em 1902 e deixou um importante legado artístico na cidade.\n\nEntre os objetos pessoais preservados está uma maleta com bastões de pastel utilizados pelo artista para criar obras como o emblema do Estado do Paraná, e que ajuda a revelar aspectos do seu processo criativo e cotidiano de trabalho. No interior, há bastões de diferentes tamanhos e níveis de usos, com alguns praticamente intactos e outros já desgastados pelo manuseio constante.\nHorário: 9h30 às 17h (de terça a domingo)\nEntrada: gratuita.\nEndereço: R. Mateus Leme, 336 - Centro.\n\n**MCLAREN DE EMERSON FITTIPALDI**\nO Museu do Automóvel de Curitiba tem origem na paixão de colecionadores por veículos antigos. Fundado em 1976, o espaço reúne cerca de 150 veículos antigos, que se revezam nas 70 vagas de exposição. A coleção é dividida em categorias como vintage, nacionais e de corrida, além de incluir motocicletas, bicicletas e outras curiosidades mecânicas.\nUm exemplar de grande destaque é modelo do McLaren M-23, carro de Fórmula 1 pilotado por Emerson Fittipaldi. O veículo representa um momento histórico do automobilismo brasileiro, quando Fittipaldi venceu o mundial de 1974.\nHorário: 13h30 às 16h45 (de terça a sexta) e 10h às 12h e 13h30 às 17h45 (sábados, domingos e feriados).\nEntrada: paga.\nEndereço: Av. Cândido Hartmann, 2.300 - Mercês.\n',NULL,'/api/media/materia/novo-1777843530105-m3uffavfj/imagens/1777843530351-Thotmeia.jpeg',NULL,0,'published','2026-05-03 21:27:54.339','2026-05-03 21:27:54.366','2026-05-26 15:14:24.440','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: José Fernando Ogura/SECOM (arquivo)',6,NULL),
('30c5cdc9-af82-4470-a270-c863742d7f4d','A segurança pública e o discurso fácil e eleitoreiro como se este fosse o único problema do país','a-seguranca-publica-e-o-discurso-facil-e-eleitoreiro-como-se-este-fosse-o-unico-problema-do-pais-czkr7','O cidadão que sai de casa com medo de ser assaltado naturalmente se sensibiliza com discursos de enfrentamento ao crime','A política brasileira vive uma distorção perigosa: a transformação da segurança pública em uma espécie de solução mágica para todos os problemas nacionais.\n\nParte significativa da direita brasileira adotou um discurso simplista, emocional e eleitoralmente conveniente, baseado na ideia de que o endurecimento penal, o aumento da repressão e o fortalecimento ostensivo das forças policiais seriam suficientes para resolver os desafios estruturais do país.\n\n**O discurso do medo.**\nÉ um discurso fácil. Funciona eleitoralmente porque explora o medo da população diante da violência, da criminalidade e da sensação de insegurança que atinge milhões de brasileiros. Afinal, poucas pautas possuem impacto emocional tão imediato quanto a segurança pública. O cidadão que sai de casa com medo de ser assaltado naturalmente se sensibiliza com discursos de enfrentamento ao crime. \n\n> E é justamente aí que muitos setores políticos constroem uma narrativa de forte apelo popular, mas de baixa profundidade administrativa.\n\n**Governar vai além da segurança pública.**\n\nO problema é que governar um país não se resume a repetir palavras de ordem sobre criminalidade. O Brasil não enfrenta apenas uma crise de segurança. O país possui gargalos históricos em educação, saúde, infraestrutura, mobilidade, geração de empregos, desenvolvimento econômico, inovação, habitação e gestão pública. Reduzir o debate nacional quase exclusivamente à segurança pública é uma forma conveniente de simplificar problemas complexos e criar uma agenda política baseada muito mais no impacto eleitoral do que em soluções reais.\n\nNo Paraná, esse modelo de discurso também ganhou espaço. Setores da direita local, especialmente ligados ao senador Sergio Moro e seus correligionários, transformaram a pauta da segurança em uma espécie de bandeira permanente. \n\n> Na Assembleia Legislativa e em diversos discursos políticos, o tema aparece quase como um mantra eleitoral\n\nMais endurecimento, mais repressão, mais polícia. É uma narrativa de forte apelo popular, mas que frequentemente ignora a complexidade de administrar um Estado inteiro.\n\nO próprio histórico recente do Paraná demonstra que a realidade administrativa é muito mais ampla do que o discurso político simplificado. O governo Ratinho Junior realizou investimentos robustos na área de segurança pública, com renovação de viaturas, modernização tecnológica, aquisição de equipamentos e fortalecimento das forças policiais. \n\n> Ou seja: o Estado não abandonou a segurança pública e reconheceu sua importância estratégica.\n\n**O discurso eleitoreiro.**\nMas há uma diferença fundamental entre governar e fazer discurso eleitoral. Enquanto alguns grupos políticos tentam vender a ideia de que segurança pública é praticamente a única prioridade nacional, o governo estadual compreendeu que administrar exige equilíbrio entre várias áreas essenciais. \n\nAo mesmo tempo em que investiu nas polícias, o Paraná também avançou em infraestrutura, atração de investimentos, logística, desenvolvimento regional, educação técnica e responsabilidade fiscal.\nEsse é o ponto central que desmonta o discurso fácil e eleitoreiro: segurança pública é importante, mas não sustenta sozinha o desenvolvimento de um Estado ou de um país. \n\nNenhuma sociedade se desenvolve apenas com viaturas novas, operações policiais e discursos de enfrentamento. Segurança sem emprego, sem crescimento econômico, sem educação e sem oportunidade social apenas combate os efeitos da crise — nunca suas causas profundas.\n\n**Fazer política sem levar o terror para o cidadão.**\n\nExiste ainda um componente político evidente nessa estratégia discursiva. \n\n> A pauta da segurança produz dividendos eleitorais rápidos porque trabalha diretamente com emoções fortes como medo, revolta e indignação\n\nJá políticas estruturais — educação, planejamento urbano, desenvolvimento econômico — exigem tempo, gestão técnica e resultados graduais. É muito mais simples politicamente fazer discursos duros contra o crime do que apresentar soluções consistentes para os desafios estruturais do país.\n\nO risco dessa lógica é transformar a política em um ambiente de slogans permanentes. O cidadão passa a ouvir diariamente que “o problema do Brasil é falta de repressão”, enquanto temas igualmente decisivos permanecem em segundo plano. E isso interessa eleitoralmente a determinados grupos, porque simplificar a realidade facilita a construção de narrativas políticas de impacto imediato.\n\n**Pensar e agir pela segurança pública sim, mas sem demagogia.**\n\nO Paraná recente mostra justamente o contrário: é possível investir fortemente em segurança pública sem abandonar outras áreas fundamentais. E talvez esteja aí uma das principais diferenças entre quem governa de fato e quem apenas explora eleitoralmente o medo da população.\n\nA segurança pública é indispensável. Mas o Brasil não será resolvido apenas com discursos de endurecimento penal, operações policiais ou retórica de combate permanente. \n\n**E aí?**\n\nUm país complexo exige governos capazes de enxergar a sociedade além do medo e além da política de efeito imediato. **O verdadeiro desafio da gestão pública é construir equilíbrio entre ordem, desenvolvimento, oportunidade e inclusão — e não transformar a segurança pública em um palanque eleitoral permanente.**\n',NULL,'/api/media/materia/novo-1780349259808-kep21tswz/imagens/1780349260337-BLINDADOS.jpg',NULL,0,'published','2026-06-02 11:04:26.833','2026-06-01 21:28:52.882','2026-06-04 22:14:07.557','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Sesp/PR',20,NULL),
('320e6d20-3e73-4d7c-8dcc-a559efd1a6aa','Há momentos na política que dizem mais pelo gesto do que pelo discurso.','ha-momentos-na-politica-que-dizem-mais-pelo-gesto-do-que-pelo-discurso-1vrs3','Em um cenário eleitoral que ainda se desenha, esse tipo de movimento antecipa uma lógica','A reunião promovida pelo governador Ratinho Junior, na Fazenda Ubatuba, em Apucarana, é um desses momentos.\nNão se tratou apenas de um encontro político.\n\nFoi uma sinalização clara de rumo.\nMais do que uma apresentação\nAo reunir centenas de prefeitos de diferentes regiões do estado e apresentar Sandro Alex como candidato à sucessão, o governador não apenas oficializou um nome.\n\n**Organizou uma base**\n\n**Alinhou expectativas**\n\n**Estruturou uma transição**\n\nEm um cenário eleitoral que ainda se desenha, esse tipo de movimento antecipa uma lógica:\na da continuidade planejada.\n\nA força da articulação municipal\nPrefeitos são, historicamente, o ponto de contato mais direto entre governo e população.\nSão eles que:\n•	executam políticas no território \n•	percebem demandas locais \n•	traduzem decisões estaduais em impacto real.\n\nAo reunir esse conjunto de lideranças, o governo reforça uma das suas principais marcas:\n**Capilaridade administrativa e política\n**\nE, ao fazê-lo, cria um ambiente favorável para que a candidatura de Sandro Alex não comece isolada — mas integrada.\nContinuidade como estratégia.\n\nA escolha por Sandro Alex carrega um significado claro:\n**Não é uma ruptura.**\n\nÉ uma aposta na manutenção de um modelo de gestão que priorizou:\n•	infraestrutura \n•	investimentos estruturantes \n•	organização administrativa \nAo apresentá-lo nesse contexto, o governador reforça a mensagem de que a eleição não será sobre mudança de direção — mas sobre manutenção de trajetória.\n\n**O gesto político**\nMais do que números ou pesquisas, a reunião na Fazenda Ubatuba representa um gesto político relevante:\n- demonstra coesão\n- reduz incerteza interna\n- sinaliza unidade\n\n> Em eleições abertas, esse tipo de movimento não define o resultado —\n> mas define o ponto de partida.\n\nE partir organizado é, quase sempre, uma vantagem.',NULL,'/api/media/materia/novo-1777298360402-7reowkirt/imagens/1777298360596-Fazenda-Ubatuba-geral.jpeg',NULL,0,'published','2026-04-30 12:07:27.651','2026-04-27 14:01:01.490','2026-05-30 01:58:19.086','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Rodrigo Felix Leal/SEIL',8,NULL),
('330919dc-1f1d-40fb-b0dd-059a32e5e720','Eduardo Pimentel consolida força política em Curitiba e se transforma em peça estratégica para o projeto do PSD no Paraná','eduardo-pimentel-consolida-forca-politica-em-curitiba-e-se-transforma-em-peca-estrategica-para-o-projeto-do-psd-no-parana-88e9x','O eleitor avalia serviços públicos, mobilidade, organização urbana, obras, limpeza e capacidade administrativa. ','A nova pesquisa divulgada nos últimos dias trouxe um dado que chamou atenção do meio político: 78% dos curitibanos aprovam a gestão do prefeito Eduardo Pimentel. \nMais do que um índice elevado de aprovação, o levantamento mostra que a administração municipal conseguiu construir algo raro em grandes capitais: estabilidade política combinada com aprovação popular consistente. \nEm Curitiba, cidade tradicionalmente exigente com seus governantes, manter números dessa dimensão representa muito mais do que simpatia pessoal. Representa confiança administrativa.\n\n**A população aprova a gestão e não apenas o prefeito.**\nOs dados mostram que 62,1% dos entrevistados classificam a administração como boa ou ótima, enquanto apenas 11,3% consideram a gestão ruim ou péssima. \n\n> Isso demonstra que a aprovação não está baseada apenas na imagem de Eduardo Pimentel, mas está diretamente ligada à percepção de funcionamento da cidade.\n\nO eleitor avalia serviços públicos, mobilidade, organização urbana, obras, limpeza e capacidade administrativa. \nE a pesquisa mostra que a maioria dos curitibanos entende que a cidade está no rumo correto. \n\n**Eduardo Pimentel virou uma das principais lideranças do PSD.**\nExiste outro aspecto político extremamente relevante. Eduardo Pimentel não é apenas prefeito da capital. Ele pertence ao mesmo partido do governador Ratinho Junior, o PSD.\nIsso faz dele uma das principais lideranças políticas do grupo governista para a eleição deste ano. \nCuritiba concentra o maior colégio eleitoral do Paraná e ter um prefeito com aprovação próxima de 80% significa possuir um ativo político de enorme valor dentro da disputa estadual.\n\n**A capital pode ter papel decisivo na sucessão estadual.**\nHistoricamente, eleições para o Governo do Paraná passam obrigatoriamente por Curitiba. Nenhum projeto estadual competitivo ignora o peso político da capital. Por isso, a força de Eduardo Pimentel ganha importância ainda maior.\n\n> Sua alta aprovação fortalece: Ratinho Junior, Sandro Alex, Alexandre Curi e todo o projeto político liderado pelo PSD. \n\nO prefeito passa a funcionar como uma espécie de ponte entre a popularidade do governador no interior e a força eleitoral do grupo na capital.\n\n**Eduardo Pimentel reforça a narrativa de continuidade.**\nExiste uma sintonia política clara entre Ratinho Junior, Eduardo Pimentel, Sandro Alex e Alexandre Curi. Todos fazem parte de um mesmo projeto político que busca transmitir estabilidade, continuidade, previsibilidade administrativa e foco em gestão. \nA pesquisa mostra que essa narrativa encontra respaldo em Curitiba. O eleitor aprova um modelo de administração baseado menos em conflitos ideológicos e mais em resultados concretos. \n\n**O PSD chega fortalecido ao processo eleitoral.**\nOs números da pesquisa também ajudam a compreender por que o PSD chega tão forte ao cenário eleitoral paranaense.\nO partido reúne atualmente o governador mais popular do estado, o prefeito da capital com aprovação elevada, forte presença no interior e ampla rede de prefeitos e lideranças regionais. \n\n> Nesse contexto, Eduardo Pimentel amplia seu papel político. Ele deixa de ser apenas gestor municipal e passa a ocupar posição estratégica dentro da construção eleitoral do PSD para 2026.\n\n**Curitiba se transforma em vitrine política do grupo governista.**\nOutro fator importante é que a capital funciona como vitrine administrativa. Uma gestão bem avaliada em Curitiba produz repercussão estadual.\nOs números divulgados reforçam a percepção de que o grupo político liderado por Ratinho Junior mantém aprovação tanto no interior quanto na principal cidade do Paraná. \nIsso cria ambiente favorável para fortalecer alianças, ampliar apoios e consolidar candidaturas ligadas ao governo. \n\n**E aí?**\nA pesquisa que aponta 78% de aprovação para Eduardo Pimentel vai muito além da avaliação de um prefeito. \nEla revela força política, aprovação administrativa e capacidade de influência eleitoral.\n\nComo prefeito de Curitiba e integrante do mesmo partido de Ratinho Junior, Eduardo Pimentel passa a desempenhar papel estratégico na eleição deste ano. Sua popularidade fortalece o PSD na capital e ajuda a consolidar o projeto político liderado pelo governador.\n\nEm um cenário onde Curitiba possui peso decisivo nas disputas estaduais, Eduardo Pimentel se transforma em uma das peças mais importantes da engrenagem eleitoral construída por Ratinho Junior para manter o grupo político no comando do Paraná.\n***Resta saber se Pimentel continuará \'unido e em paz\', se Rafael Greca manter a intenção de ser candidato ao governo do Paraná.***\n*',NULL,'/api/media/materia/novo-1780265610662-cyejaspmv/imagens/1780265613496-Pesquisa_78_por_cento.webp',NULL,0,'published','2026-06-02 11:06:10.095','2026-05-31 22:15:06.563','2026-06-06 04:48:08.683','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Pedro Ribas/Prefeitura de Curitiba',20,NULL),
('375b94f3-add8-4fdb-9bb9-332b0e826f3e','Outono é a estação perfeita para subir ao Mirante Marumbi e fazer fotos incríveis','outono-e-a-estacao-perfeita-para-subir-ao-mirante-marumbi-e-fazer-fotos-incriveis-z6gkn','Do terraço do Memorial de Curitiba é possível observar alguns dos principais marcos arquitetônicos da região central','Pouco conhecido, o Mirante Marumbi, no topo do Memorial de Curitiba (Rua Dr. Claudino dos Santos, 79 - São Francisco), oferece uma visão privilegiada da cidade. Do terraço, com visibilidade de mais de 180 graus, é possível observar alguns dos principais marcos arquitetônicos da região central, como igrejas, casarões e edifícios.\n\nO mirante é um convite para registros fotográficos. No parapeito do lado direito de quem chega, foram planejados “recortes” que emolduram a paisagem. O outono é a estação perfeita para as fotos, pois proporciona uma iluminação dourada, menos intensa, especialmente no fim da tarde, período conhecido como golden hour (hora dourada).\n\nOs horários de visitação são os mesmos do Memorial: de terça a sexta-feira, das 9h às 12h e das 13h às 18h; e aos sábados e domingos, das 9h às 15h.\n\nMemorial de Curitiba\nEndereço: Rua Dr. Claudino dos Santos, 79, São Francisco\nHorário: de terça a sexta-feira, das 9h às 18h; sábados e domingos, das 9h às 15h.',NULL,'/api/media/materia/novo-1777164617165-alcp5l7fj/imagens/1777164618028-Mirante-São-Francisco.jpg',NULL,0,'published','2026-04-26 00:51:29.398','2026-04-26 00:51:29.403','2026-05-30 00:43:41.688','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Cido Marques/FCC',14,NULL),
('3cc091c1-888a-4480-82f4-251e0bdf79d1','Curitiba como campo decisivo: o eixo que pode definir o governo do Paraná','curitiba-como-campo-decisivo-o-eixo-que-pode-definir-o-governo-do-parana-0f6og','A eleição de 2026 no Paraná não será decidida apenas no interior. Ela passa, necessariamente, por Curitiba e sua Região Metropolitana. E, neste momento, há um elemento','\n**O eixo PSD: governo, capital e candidato**\nO cenário atual apresenta uma configuração rara:\n•	o governador \n•	o possível candidato ao governo (Sandro Alex) \n•	e o prefeito da capital.\nTodos no mesmo campo político.\nO prefeito Eduardo Pimentel é peça-chave nessa engrenagem.\nNão apenas por comandar a maior cidade do estado.\nMas por representar continuidade política: foi vice-prefeito por dois mandatos de Rafael Greca; foi eleito prefeito com base nessa estrutura e hoje está alinhado ao projeto estadual. \nIsso cria um efeito direto:\nCuritiba deixa de ser um território neutro\ne passa a ser um ativo político do grupo governista.\n\n**O peso eleitoral da capital**\nCuritiba não é apenas um grande colégio eleitoral.\nEla define narrativa.\n•	influencia opinião pública. \n•	pauta o debate político. \n•	reverbera para a Região Metropolitana. \nQuem controla Curitiba, influencia o estado.\nE isso se amplifica quando há alinhamento institucional, como ocorre neste momento:\n**prefeitura - governo do estado - base política. \n**\n\n**O fator Pimentel: ativo ou limite?**\nO nome de Eduardo Pimentel chegou a ser testado como possível candidato ao governo. \nMas sua posição atual cria um dilema:\nele é mais útil onde está.\n\n> Como prefeito:\n> •	fortalece o grupo na capital \n> •	amplia capilaridade urbana \n> •	sustenta o projeto estadual.\n \nSair da prefeitura seria um risco. Permanecer é uma estratégia.\n\n**O elemento Cristina Graeml: a reconfiguração do jogo**\nA entrada de Cristina Graeml no mesmo grupo político muda a equação.\nEla:\n•	foi adversária direta de Pimentel em 2024 \n•	teve desempenho relevante em Curitiba \n•	agora integra o PSD. \nE mais: pode disputar o Senado ou compor chapa majoritária. \nIsso cria um cenário inusitado:\nadversários locais passam a compor o mesmo projeto.\n\n**O efeito na Região Metropolitana**\nA lógica de Curitiba se expande.\nA Região Metropolitana tende a seguir:\n•	influência política da capital \n•	alinhamento administrativo \n•	redes de apoio municipal.\nA eleição deixa de ser fragmentada\ne passa a ter eixo centralizado.\n\n**O desafio do grupo governista**\nA força também gera um risco: excesso de concentração:\n•	múltiplas lideranças no mesmo campo \n•	necessidade de acomodação política \n•	disputa interna por espaço. \nSe bem conduzido:\nvira força eleitoral.\nSe mal conduzido:\nvira ruído interno.\n\n**E a oposição?**\nA oposição enfrenta um problema claro:\ncomo romper esse bloco em Curitiba?\nPorque, neste momento:\n•	governo tem aprovação \n•	capital está alinhada \n•	novas lideranças foram incorporadas.\nO espaço de ruptura diminuiu.\n\n**E aí?**\nA eleição de 2026 no Paraná pode não ser decidida **em Curitiba**.\nMas dificilmente será vencida **sem Curitiba**.\nE, hoje, a capital está integrada a um mesmo projeto político.\nIsso não garante vitória.\nMas muda profundamente o jogo.\n\n**Fato**\nCuritiba deixou de ser campo de disputa e passou a ser base de operação.\nE, na política,\nquem transforma território em base,\nentra na eleição com vantagem estrutural.\n',NULL,'/api/media/materia/novo-1777976168594-kkdaaafqm/imagens/1777976169041-Sandro_e_Eduardo_Pimentel.jpeg',NULL,0,'published','2026-05-05 11:22:26.132','2026-05-05 10:17:05.997','2026-05-26 17:09:24.763','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Rodrigo Felix Leal',30,NULL),
('3df2452a-7142-4c1d-9ebe-465f12da99dd','Curitiba reduz desemprego e Eduardo Pimentel começa a consolidar a imagem de gestor da economia urbana','curitiba-reduz-desemprego-e-eduardo-pimentel-comeca-a-consolidar-a-imagem-de-gestor-da-economia-urbana-zaa8s','Outro ponto importante da atual administração é a tentativa de descentralizar empregabilidade.','A atual gestão da Prefeitura de Curitiba começa a consolidar um ativo político importante: a percepção de eficiência econômica.\nOs números divulgados recentemente mostram que a capital paranaense atingiu uma taxa de desocupação de apenas 3,9%, uma das menores do Brasil. E esse dado não é apenas estatístico.\n\n> Politicamente, ele ajuda a fortalecer a imagem de uma cidade economicamente organizada, atrativa para investimentos e com ambiente favorável à geração de empregos. \n\n**O desemprego caiu — e de forma contínua.**\nTalvez o aspecto mais relevante seja a continuidade da queda.\nCuritiba saiu de: 9,5% de desemprego em 2020, para 5,9% em 2024, de 5% em 2025 e agora 3,9% em 2026. Isso mostra que não se trata apenas de um pico momentâneo. Existe uma tendência consolidada.\nE isso normalmente está ligado a estabilidade administrativa, ambiente econômico favorável e continuidade de políticas públicas. \n\n**A gestão aposta na política do emprego visível.**\nOutro ponto importante da atual administração é a tentativa de descentralizar empregabilidade.\nA Prefeitura passou a levar vagas, qualificação e serviços públicos diretamente para bairros, terminais, praças e espaços comunitários. \nProgramas como Blitz do Emprego, Sine Móvel, mutirões regionais e Curitiba Qualifica ajudam a construir uma imagem de prefeitura mais próxima do trabalhador comum.\n\n**Eduardo Pimentel herda — mas também tenta ampliar.**\nÉ impossível analisar a atual gestão sem reconhecer a continuidade administrativa da era Rafael Greca.\nEduardo Pimentel foi vice-prefeito por dois mandatos, secretário municipal e participou diretamente da construção do atual modelo administrativo da cidade. \nMas existe uma diferença importante. Pimentel tenta consolidar uma identidade mais voltada ao desenvolvimento econômico e empregabilidade.\nE os números do Caged fortalecem essa narrativa. Curitiba registrou saldo de 17.686 empregos formais no primeiro trimestre de 2026, ficando atrás apenas de São Paulo entre as capitais brasileiras. \n\n**O modelo Curitiba continua apostando em inovação.**\nA cidade mantém uma estratégia baseada em empreendedorismo, tecnologia, simplificação burocrática e inovação urbana. \nProjetos como Vale do Pinhão, Worktibas, Pinhão Hub  e incentivo à abertura rápida de empresas ajudam a sustentar essa imagem de cidade moderna e competitiva. \n\n**O desafio agora é evitar desigualdade invisível.**\nApesar dos números positivos, Curitiba ainda enfrenta um desafio importante: crescimento econômico não significa automaticamente distribuição equilibrada de oportunidades. \n\n> A cidade continua convivendo com desigualdade regional, vulnerabilidade social, pressão urbana e custo elevado de vida em algumas áreas. \n\nO desafio da gestão agora será transformar bons índices econômicos em sensação concreta de melhoria cotidiana para toda a população.\n**\nO impacto político é inevitável.**\nPoliticamente, o cenário fortalece Eduardo Pimentel. Porque prefeitos costumam ser avaliados principalmente por sensação de cidade funcionando, economia aquecida, organização urbana, e geração de emprego. E hoje Curitiba transmite exatamente essa percepção.\n\n**E ai?**\nA atual gestão da Prefeitura de Curitiba começa a consolidar uma narrativa baseada em estabilidade econômica, incentivo ao investimento, inovação e empregabilidade. E os números recentes ajudam a transformar essa narrativa em ativo político real.\n\n**Fato:**\nCuritiba não virou referência apenas por planejamento urbano. Agora começa a fortalecer também uma imagem de capital econômica eficiente.\n***E, na política, quando emprego cresce, desemprego cai e a cidade transmite estabilidade, o gestor deixa de ser apenas administrador. Passa a ser associado à ideia de prosperidade.***\n',NULL,'/api/media/materia/novo-1778856293141-g8ivrh1fo/imagens/1778856295858-emprego_Curitiba_IA.png',NULL,0,'published','2026-05-19 12:12:58.742','2026-05-15 14:47:33.696','2026-05-26 19:56:59.750','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Fotos: Valdelino Pontes/Secom Valquir Kiu Aureliano/Secom',5,NULL),
('40731dab-a2e0-4c43-bef7-01df6ccafbdb','A eleição para o Senado será fortemente ligada ao governo','a-eleicao-para-o-senado-sera-fortemente-ligada-ao-governo-twl7d','A tendência é que o eleitor vote “em pacote”. Ou seja, governador, senador, grupo político, alinhamento ideológico e percepção de força eleitoral, andarão juntos.','Esse é o dado mais importante da pesquisa IRG.\nA eleição para o Senado, no Paraná, não será decidida isoladamente.\nA tendência é que o eleitor vote “em pacote”. Ou seja, governador, senador, grupo político, alinhamento ideológico e percepção de força eleitoral, andarão juntos.\nQuem crescer para o governo, puxa o Senado junto.\n\n**Sandro Alex fortalece o grupo governista.**\nO crescimento de Sandro Alex ao governo fortalece diretamente os candidatos aliados ao Palácio Iguaçu.\n\n> Porque, Ratinho Junior aparece fortíssimo, Sandro cresce nas pesquisas e o PSD ocupa o estado com encontros regionais e presença permanente\n\n. \nIsso aumenta o peso político do grupo governista também na disputa senatorial.\n\n**O Senado pode virar eleição de rejeição.**\nEsse é um fator decisivo.\nO Paraná possui eleitorado altamente polarizado.\nIsso significa que nomes muito ideológicos possuem dificuldade de expansão, candidatos muito associados à polarização enfrentam teto eleitoral e figuras moderadas podem crescer silenciosamente.\n \n**O que a pesquisa realmente mostra.**\nA IRG revela um cenário muito claro:\n✅ não existe favorito absoluto;\n✅ a eleição será definida por alianças;\n✅ Ratinho Junior continua sendo o maior ativo político do estado;\n✅ Moro mantém força importante;\n✅ e o Senado dependerá diretamente da disputa pelo governo. \n\n**E aí?**\nA disputa pelo Senado no Paraná deixou de ser uma corrida individual. Agora é uma guerra de blocos políticos.\nDe um lado, Ratinho Junior, Sandro Alex e a máquina estadual.\nDo outro, Moro, PL e o eleitorado conservador ligado ao bolsonarismo.\n***No meio disso, Álvaro Dias resiste, Gleisi mantém sua base e o eleitor começa a escolher não apenas nomes, mas projetos de poder para o Paraná.***\n',NULL,'/api/media/materia/novo-1779387225127-0wxgd5mh2/imagens/1779387225513-PESQUISA_IRG_SENADO.png',NULL,0,'published','2026-05-21 18:16:42.423','2026-05-21 18:15:06.726','2026-05-31 11:08:11.408','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição dados',4,NULL),
('473fdf58-3dd8-4286-8da8-a44499e74f50','O estilo pessoal de Ratinho Junior fortalece sua popularidade','o-estilo-pessoal-de-ratinho-junior-fortalece-sua-popularidade-1pnma',NULL,'Um diferencial importante na trajetória do governador do Paraná, é a disposição de manter comportamento extremamente próximo das pessoas.\n\nEm praticamente todas as viagens, Ratinho Junior tira fotos, abraça moradores, conversa com comerciantes, atende lideranças e não evita contato popular.  É uma característica que produz enorme conexão emocional com o eleitor do interior.\n\nO governador não transmite distância institucional. Pelo contrário, transmite proximidade. E isso ajuda a explicar por que mantém alta aprovação, mobiliza multidões e consegue transformar agendas administrativas em grandes atos políticos espontâneos. \n\n**Sandro Alex é o grande beneficiado.**\nSandro Alex acompanha de perto praticamente todas essas agendas e isso possui enorme peso eleitoral.\n\nComo ex-secretário de Infraestrutura, Sandro conhece as obras, participou diretamente de muitos projetos, domina os detalhes técnicos e aparece naturalmente associado às entregas do governo. \n\n> A população começa a enxergar a necessidade de continuidade administrativa.\n\nEm muitas cidades, Sandro Alex já não aparece apenas como pré-candidato.\nAparece como parceiro do governo, homem das obras e nome ligado ao desenvolvimento regional. \n',NULL,'/api/media/materia/novo-1779920517409-w2hf9suqe/imagens/1779920518039-com_Ratinho_em_Altamira_do_Paran_.jpg',NULL,0,'published','2026-05-27 22:23:20.226','2026-05-27 22:23:20.230','2026-05-29 11:03:03.929','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ricardo Zanoncini/AEN',3,NULL),
('4af074b4-1181-42f5-bcca-6f6ef85652fb','Calendário Eleitoral 2026: a corrida política entra na reta decisiva a partir de junho','calendario-eleitoral-2026-a-corrida-politica-entra-na-reta-decisiva-a-partir-de-junho-yyy85','O calendário do Tribunal Superior Eleitoral (TSE) estabelece datas que passam a influenciar diretamente o comportamento','A partir de deste mês de junho de 2026, a eleição presidencial e as disputas estaduais entram oficialmente em uma fase decisiva. É nesse período que começam as restrições eleitorais, a definição das alianças, a escolha formal dos candidatos e o início da propaganda eleitoral. \nO calendário do Tribunal Superior Eleitoral (TSE) estabelece datas que passam a influenciar diretamente o comportamento de partidos, pré-candidatos, emissoras, agentes públicos e campanhas políticas. \n\n📅 **JUNHO 2026.**\n💰 Fundo Eleitoral e restrições na TV\n📌 16 de junho\nO TSE divulgará oficialmente o valor disponível no Fundo Eleitoral (FEFC), principal fonte de financiamento das campanhas. \n📌 30 de junho\nPassa a ser proibido que emissoras de rádio e televisão transmitam programas apresentados ou comentados por pré-candidatos. \n📊 **Impacto político\nJUNHO**\n├── Fundo Eleitoral definido\n├── Pré-candidatos deixam rádio e TV\n└── Bastidores de alianças aceleram\nEste é o momento em que os partidos começam a medir força financeira, estrutura de campanha e potencial de alianças. \n\n📅 **JULHO 2026.**\n⚖️ Condutas vedadas e início das restrições\n📌 4 de julho\nEntram em vigor as chamadas “condutas vedadas” para agentes públicos. \nFicam proibidos nomeações, exonerações, contratações, participação de candidatos em inaugurações públicas e determinadas ações administrativas. \n📌 Julho\nO TSE divulgará o número oficial de eleitores aptos a votar. \n📊 **Impacto político\nJULHO**\n├── Governo entra em modo eleitoral\n├── Obras continuam, mas sob restrições\n├── Prefeitos e governadores ganham cautela\n└── Pesquisas passam a ter peso estratégico\nÉ o mês em que candidatos intensificam viagens, alianças regionais são fechadas e os partidos começam a definir prioridades. \n\n📅 **AGOSTO 2026.**\n🗳️ Convenções e início oficial da campanha\n📌 20 de julho a 5 de agosto\nConvenções partidárias para definir candidatos, aprovar coligações e homologar chapas. \n📌 15 de agosto\nPrazo final para registro das candidaturas. \n📌 16 de agosto\nComeça oficialmente a propaganda eleitoral. \n📌 28 de agosto\nInício do horário eleitoral gratuito no rádio e na TV. \n📊 **Linha do tempo**\nAGOSTO\n20/07 ─ Convenções partidárias\n05/08 ─ Fim das convenções\n15/08 ─ Registro das candidaturas\n16/08 ─ Início da campanha\n28/08 ─ Horário eleitoral gratuito\nAgosto marca o começo da disputa real, o início dos ataques, crescimento das pesquisas e a consolidação das candidaturas competitivas. \n\n📅 **SETEMBRO 2026.**\n🔐 Segurança eleitoral e reta final do 1º turno\n📌 Até 14 de setembro\nLacração dos sistemas eleitorais pelo TSE. \n📌 19 de setembro\nCandidatos não poderão ser presos, salvo flagrante delito. \n📌 29 de setembro\nEleitores passam a ter proteção contra prisão arbitrária até após a eleição. \n📊 **Clima político\nSETEMBRO**\n├── Debates ganham intensidade\n├── Redes sociais entram em guerra total\n├── Pesquisas influenciam voto útil\n└── Campanhas entram na reta decisiva\nSetembro costuma ser o mês das viradas eleitorais, crescimento do voto útil e definição dos candidatos ao segundo turno. \n\n📅 **OUTUBRO 2026.**\n🗳️ Eleição e possível segundo turno\n📌 4 de outubro\n👉 Primeiro turno das eleições. \n📌 25 de outubro\n👉 Eventual segundo turno. \n📌 9 a 23 de outubro\nHorário eleitoral do segundo turno. \n📊 **Linha do tempo final\nOUTUBRO**\n04/10 ─ 1º turno\n09/10 ─ Início propaganda 2º turno\n25/10 ─ 2º turno\n\n**O que o calendário significa politicamente?**\nO calendário eleitoral não organiza apenas datas.\nEle define ritmo da campanha, estratégia dos partidos, tempo de exposição e movimentação das alianças. \n\n**A partir de junho, toda agenda pública passa a ter leitura eleitoral.**\nGovernadores, prefeitos e parlamentares intensificam agendas regionais, ampliam presença política e tentam consolidar alianças antes das convenções. \n\n**O cenário do Paraná entra na fase mais estratégica.**\nNo Paraná, o calendário tende a acelerar a consolidação de Sergio Moro no campo bolsonarista, o crescimento da candidatura de Sandro Alex ao lado de Ratinho Junior e a tentativa da esquerda de estruturar o palanque de Requião Filho. \nAs próximas datas serão fundamentais para medir força política, capacidade de mobilização e viabilidade de segundo turno.\n\n**E aí?**\nEntre junho e outubro de 2026, o Brasil viverá convenções, propaganda eleitoral, pesquisas decisivas, alianças, debates e a disputa mais intensa da política nacional. \n**O calendário eleitoral marca oficialmente a transformação da pré-campanha em campanha real.\nE cada data passa a influenciar diretamente estratégias, alianças, narrativas e o futuro político do país.** \n',NULL,'/api/media/materia/novo-1780404902219-mho5vfdri/imagens/1780404905542-elei__es_2026_calend_rio.png',NULL,0,'published','2026-06-02 12:57:34.608','2026-06-02 12:55:49.746','2026-06-06 15:07:41.586','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',10,NULL),
('4f264798-738d-499a-aa05-6fc6d62a5841','Pesquisa Genial/Quaest: A liderança que não resolve — e a eleição que ainda não começou','pesquisa-genialquaest-a-lideranca-que-nao-resolve-e-a-eleicao-que-ainda-nao-comecou-zv3cr','Até 84% dos eleitores ainda não sabem em quem votar. Mesmo no cenário estimulado, os indecisos ainda giram em torno de 17% a 18%. ','A nova pesquisa Genial/Quaest confirma o que já vinha sendo desenhado no Paraná:\nSérgio Moro lidera a disputa ao governo com cerca de 35% das intenções de voto no cenário estimulado. \n\nA vantagem é consistente.\nMas está longe de ser definitiva.\nPorque o dado mais relevante da pesquisa não é quem lidera.\nÉ quem ainda não decidiu.\n\n**1. O dado que muda a eleição**\n\nNo cenário espontâneo — quando o eleitor não recebe nomes — a pesquisa revela algo decisivo:\n- Até 84% dos eleitores ainda não sabem em quem votar.\nMesmo no cenário estimulado, os indecisos ainda giram em torno de 17% a 18%. \nIsso indica um ponto central:\nA eleição ainda não entrou na fase de decisão real\n\n**2. A liderança de Moro** — forte, mas antecipada.\nA pesquisa confirma que Moro:\n•	lidera no primeiro turno \n•	vence todos os cenários de segundo turno. \n***Mas há uma nuance importante:***\nEssa liderança acontece em um ambiente ainda pouco consolidado, quando o eleitor ainda não decidiu. \n\nLiderança significa:\n•	reconhecimento \n•	posicionamento inicial \n•	vantagem de largada.\n \nNão significa voto cristalizado.\n\n**3. O espaço aberto para crescimento**\n\nEnquanto Moro ocupa o topo, os demais nomes aparecem com baixa pontuação:\n•	Sandro Alex ainda surge com cerca de 5% a 6% nos cenários estimulados. \nIsso pode parecer fragilidade.\nMas, na prática, revela outra coisa:\n\n> Existe um espaço eleitoral enorme ainda não ocupado.\n> E esse espaço é onde a eleição será decidida.\n\n**4. A eleição ainda não tem dono**\n\nO cenário atual mostra três camadas distintas:\n\n🔹 Camada 1 — liderança\n\nMoro consolida vantagem inicial\n\n🔹 Camada 2 — indefinição\n\nmaior parte do eleitorado ainda não escolheu\n\n🔹 Camada 3 — construção\n\nCandidaturas ainda estão sendo apresentadas.\n\nEssa combinação cria um cenário raro:\numa eleição com líder — mas sem dono.\n\n**5. O fator nacional segue presente**\n\nA pesquisa também reforça algo estrutural:\nA candidatura de Moro carrega peso nacional e isso explica sua vantagem inicial.\n\nMas também cria uma vulnerabilidade:\nSe a eleição for “puxada” para o campo estadual, o eixo da disputa muda.\n\nE esse movimento ainda está em aberto.\n\n**E aí?**\nA pesquisa Quaest não mostra uma eleição decidida.\nMostra uma eleição em formação.\nMoro lidera — e isso é relevante.\n\nMas lidera em um cenário onde:\n•	o eleitor ainda não escolheu \n•	os candidatos ainda não se consolidaram \n•	e o tema da eleição ainda não está definido.\n\n> O resultado não está nos números de hoje:\n> Está na disputa que ainda vai acontecer.\n\n**Vamos pensar:**\nO Paraná vive apenas um momento típico de pré-eleição:\n•	há um favorito \n•	mas ainda não há decisão.\n \n***E, quando a maioria do eleitorado ainda não decidiu, liderar é importante — mas não é suficiente*.**\n',NULL,'/api/media/materia/4f264798-738d-499a-aa05-6fc6d62a5841/imagens/1777399227603-Pesquisa_27_04.jpg',NULL,0,'published','2026-04-30 12:35:24.162','2026-04-27 18:41:25.697','2026-05-04 22:07:55.133','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Sergio Moro, Requião Filho, Rafael Greca, Sandro Alex, Luiz França e Tony Garcia (Crédito de imagem: Divulgação Redes Sociais, Reprodução ric.com.br)',2,NULL),
('50d498c6-a0d6-4c0a-9999-791a138a9f0b','Eduardo Pimentel, moradores de rua e o risco político da exposição pública','eduardo-pimentel-moradores-de-rua-e-o-risco-politico-da-exposicao-publica-k1hkx','O prefeito de Curitiba, Eduardo Pimentel, voltou ao centro do debate político após publicar em seu perfil pessoal no','O prefeito de Curitiba, Eduardo Pimentel, voltou ao centro do debate político após publicar em seu perfil pessoal no Instagram um vídeo abordando um morador de rua e afirmando que ele não poderia permanecer naquele local.\nA cena rapidamente ganhou repercussão.\nE não apenas pelo conteúdo.\nMas pelo simbolismo político que ela carrega.\n\n**O tema que mais mobiliza Curitiba hoje**\nA questão da população em situação de rua se tornou um dos temas mais sensíveis da capital. Segurança, ocupação do espaço público, dependência química, degradação urbana, tudo isso passou a influenciar diretamente a percepção sobre gestão pública.\nE Eduardo Pimentel parece ter entendido isso. \n\n> O vídeo não foi casual.\n> Foi um gesto político calculado.\n\n**A estratégia da presença direta**\nAo aparecer pessoalmente nas ruas, conversando diretamente com moradores em situação de vulnerabilidade, Pimentel tenta transmitir uma imagem específica: prefeito presente, gestão ativa, enfrentamento direto do problema.\n\nEssa estratégia conversa diretamente com parte importante do eleitorado curitibano, que cobra ações mais firmes sobre o tema. \n\n**O limite entre ação e exposição**\nMas existe um ponto delicado.\nQuando o gestor transforma esse tipo de abordagem em conteúdo político, surge um risco: a linha entre política pública e espetacularização fica mais tênue.\n\nEsse debate já apareceu em reportagens recentes que criticaram o uso de vídeos envolvendo pessoas em situação de rua como ferramenta de comunicação política. \nA crítica central é clara: combater o problema é uma coisa. Transformar vulnerabilidade em narrativa digital é outra. \n\n**O contraponto que a própria prefeitura apresenta**\nAo mesmo tempo, a prefeitura tenta sustentar outra narrativa: a de recuperação social.\nEm ações recentes divulgadas oficialmente, o município mostrou casos de pessoas acolhidas e reinseridas socialmente após apoio da administração municipal. \n\n> O caso do morador de 64 anos divulgado pela prefeitura simboliza exatamente isso: acolhimento, assistência, reconstrução de perspectiva de vida, a gestão tenta demonstrar que não se trata apenas de retirada das ruas, mas de reestruturação social.\n\n**O impacto político**\nPoliticamente, o movimento é arriscado — mas potencialmente eficiente.\nPorque toca em um ponto emocional forte do eleitorado: sensação de ordem urbana.\nE Curitiba historicamente responde muito a esse tipo de discurso.\n\n**O reflexo em 2026**\nO tema também dialoga diretamente com o ambiente eleitoral estadual.\nEduardo Pimentel é hoje uma das peças centrais do grupo político de Ratinho Junior.\nSua atuação na capital influencia: percepção sobre gestão, ambiente político urbano, e o desempenho do grupo governista em Curitiba e Região Metropolitana. \n\n**E aí?**\nO vídeo não foi apenas uma postagem.\nFoi uma mensagem política.\nE a mensagem parece clara: a prefeitura quer mostrar ação, presença, e controle do espaço urbano.\nO problema é que, quanto mais a política entra no território da vulnerabilidade social, maior também se torna o risco de transformar sofrimento em disputa narrativa.\n\n**Fato**\nEduardo Pimentel decidiu enfrentar um dos temas mais difíceis da cidade de forma direta. Isso pode fortalecer sua imagem de gestor, ou ampliar a crítica de que Curitiba está transformando vulnerabilidade em espetáculo político.\n\nE, na política, às vezes a diferença entre firmeza e excesso, depende apenas da forma como a cena é percebida.\n',NULL,'/api/media/materia/novo-1778157414829-0xtjvmr4m/imagens/1778157415591-Eduardo_Pimentel_rua.jpeg',NULL,0,'published','2026-05-07 14:27:17.192','2026-05-07 12:38:35.055','2026-05-12 10:01:02.976','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: reprodução Instagram',16,NULL),
('535c82da-9484-4068-b613-55cb6c75562b','O último ano de Ratinho Junior não tem clima de despedida. Tem clima de continuidade.','o-ultimo-ano-de-ratinho-junior-nao-tem-clima-de-despedida-tem-clima-de-continuidade-zdfur','O último ano do governo Ratinho Junior não transmite acomodação. Transmite movimento.','Governos em reta final normalmente seguem um roteiro previsível: desaceleração política, redução de agenda, desgaste natural, disputa interna por sucessão e sensação de encerramento de ciclo. \nNo Paraná, porém, o cenário parece caminhar na direção oposta.\nO último ano do governo Ratinho Junior não transmite acomodação.\nTransmite movimento.\nE talvez esse seja hoje o principal ativo político do grupo governista.\n\n**A aprovação elevada mudou o tamanho da sucessão.**\n\n> As pesquisas mais recentes continuam mostrando índices elevados de aprovação do governador. E isso produz um efeito político relevante: a eleição deixa de ser apenas disputa entre candidatos e passa a ser também um referendo sobre continuidade administrativa.\n\nPorque governos com altos índices de aprovação, normalmente tentam transferir confiança, sensação de estabilidade e percepção de entrega. Ratinho Junior, presidente do PSD Paraná, não terá mandato politico a partir de 31 de dezembro, mas, garantindo a transferência dessa credibilidade a Sandro Alex, estará garantindo o “mando político” do Estado.  \n\n**O interior virou palco político permanente.**\nO que chama atenção neste último ano não é apenas a quantidade de obras entregues. É o ritmo. Rodovias, viadutos, hospitais, escolas, infraestrutura logística e grandes intervenções seguem sendo inauguradas em praticamente todas as regiões do estado. “O homem não para! Tá difícil acompanhar o ritmo dele”, disse um servidor que trabalha diretamente com o governador.\nA verdade é que, o governo age como quem ainda está expandindo e não como quem encerra mandato. E isso, no último ano de mandato, altera completamente a percepção de fim de ciclo.\n\n**Sandro Alex aparece como peça central dessa narrativa.**\nOutro ponto importante: Sandro Alex acompanha praticamente todas as agendas estratégicas do governo. Isso não parece casual. Politicamente, o movimento constrói uma mensagem simples: associar o pré-candidato diretamente às entregas do governo.\nNisso, a lógica é clara: Ratinho Junior entrega - Sandro Alex acompanha - e a continuidade passa a ganhar rosto político. \n\n**A sucessão deixou de ser apenas partidária.**\nO governo trabalha para construir algo maior do que uma candidatura.\nTenta consolidar a ideia de continuidade administrativa.\nE isso aparece especialmente em grandes obras estruturantes:\n- **infraestrutura rodoviária** \n- **modernização logística** \n- **investimentos regionais** \n- **e projetos simbólicos como a Ponte da Guaratuba.** \n- \nA mensagem implícita é tão clara, quanto as ações do governo: *“o estado avançou e não pode parar”.*\n\n**Não há ambiente de transição enfraquecida.**\nEsse talvez seja o ponto mais relevante. Muitos governos chegam ao último ano administrando crises internas, perda de força política ou esvaziamento gradual. \nNo Paraná, o cenário parece diferente. O governo mantém:\n•	agenda intensa \n•	presença regional \n•	articulação política \n•	e alta exposição pública. \n\n> O grupo não atua como quem está saindo. Atua sim como quem quer permanecer. Entregar o comando político do Estado para o grupo adversário, passa longe dos planos de Ratinho Junior.\n\n O embate da campanha virá. É só aguardar para constatar as ações dos adversários, que até agora parecem “amiguinhos”. \nEssa suposta paz política, que a oposição se esforça para mostrar, nada mais é do que a falta de argumentos fortes e plausíveis para criticar o governo. Daqui a pouco o jogo sujo deve começar.  \n\n**O desafio real continua sendo eleitoral.** \nMesmo com aprovação elevada, a transferência de votos nunca é automática.\nE o próprio cenário eleitoral mostra isso.\nHoje, Ratinho Junior mantém força política elevada, mas Sandro Alex ainda está em processo de crescimento e consolidação pública. Isso significa que o governo trabalha contra o relógio. É preciso transformar aprovação administrativa em competitividade eleitoral.\n\n**E aí?**\nO último ano do governo Ratinho Junior talvez seja menos sobre encerramento de mandato e mais sobre construção de legado político.\nAs viagens pelo interior, a intensificação das entregas e a presença constante de Sandro Alex nas agendas revelam um governo determinado a transmitir uma ideia específica: o ciclo ainda não terminou.\n\n**Fato.**\nO Paraná não vive hoje um clima clássico de final de governo. Vive um ambiente de continuidade em construção.\nE, na política, quando um governo chega ao último ano ainda entregando obras, ampliando agenda e ocupando território político, a sucessão deixa de ser apenas disputa eleitoral.\nPassa a ser disputa sobre quem representa o próximo capítulo do mesmo projeto.\n',NULL,'/api/media/materia/novo-1778336648756-t336b4227/imagens/1778336651781-Expoing_.jpg',NULL,0,'published','2026-05-13 12:15:17.446','2026-05-09 14:26:47.733','2026-05-23 04:51:46.230','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ari Dias/AEN',20,NULL),
('53cf0ecc-5ee4-4206-b616-47a2ab6abd33','Paraná se mantém no topo dos estados que mais crescem no Brasil, aponta Banco Central','parana-se-mantem-no-topo-dos-estados-que-mais-crescem-no-brasil-aponta-banco-central-jx8vj','De dezembro de 2025 a fevereiro de 2026, a atividade econômica do Estado do Paraná cresceu 1,6%, segundo dados do Banco Central','De dezembro de 2025 a fevereiro de 2026, a atividade econômica do Estado do Paraná cresceu 1,6%, segundo dados do Banco Central. Eles são do Índice de Atividade Econômica Regional (IBCR) e foram organizados pelo Instituto Paranaense de Desenvolvimento Econômico e Social (Ipardes). \n\n> Esse resultado, ajustado sazonalmente, é o melhor entre os estados da região Sul, o segundo melhor do Brasil e superior à média do País (1,1%).\n\nComparado com o resultado do período de setembro a novembro de 2025 (trimestre imediatamente anterior), a atividade econômica do Rio de Janeiro cresceu 2,8%, do Paraná, 1,6%, Espírito Santo, 1,2%, São Paulo, 0,9%, e Santa Catarina e Rio Grande do Sul, 0,5% cada. No âmbito do País, foi contabilizado crescimento da ordem de 1,1%. Bahia (-1,6%) e Goiás (-0,1%) apontaram queda no IBCR.\n\nJorge Callado, diretor-presidente do Ipardes, ressalta que o crescimento do Paraná decorre das políticas implementadas nos últimos anos e de um bom ambiente econômico. Ele também cita os bons números de setores-chave da economia, como o comércio. A Pesquisa Mensal de Comércio (PMC) de fevereiro apontou o Paraná na liderança do crescimento do setor em todo o País e no maior patamar de circulação de vendas da história da série do Instituto Brasileiro de Geografia e Estatística (IBGE), iniciada em janeiro de 2000.\n\nO IBCR é uma prévia do PIB. Em 2025 a economia do Estado cresceu 2,8%, superando a taxa de 2,3% que foi registrada pela economia brasileira. O resultado é 22% acima do desempenho do País. A alta da economia do Paraná decorreu das taxas de crescimento da agropecuária e dos serviços.  \n',NULL,'/api/media/materia/53cf0ecc-5ee4-4206-b616-47a2ab6abd33/imagens/1777321290837-Expo_Londrina.jpg',NULL,0,'published','2026-04-28 17:57:49.408','2026-04-27 19:24:31.657','2026-05-04 21:42:49.941','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Geraldo Bubniak/AEN',2,NULL),
('58c90808-64aa-4f5c-bc42-75e8c7f5c318','Começa a semana que pode mudar a eleição','comeca-a-semana-que-pode-mudar-a-eleicao-n8pok','A eleição de 2026 no Paraná ainda não começou para o eleitor. Mas pode ter começado para quem disputa. E essa mudança de fase tem um marco claro: a inauguração da Ponte de Guaratuba — Ponte da Vitória.','**O fato que reorganiza o cenário.**\nA entrega da ponte não foi apenas mais uma obra. Foi um evento político completo. Mais de 20 mil pessoas, vindas de diversas regiões do estado, ocuparam o espaço, caminharam sobre a estrutura e participaram de um gesto simbólico incomum: \n\n> a população foi convidada a “tomar posse” da obra.\n> Esse tipo de construção de imagem não é acidental. É narrativa organizada.\n\n**O consenso que chama atenção.**\nNo mesmo dia da inauguração e já nos dias seguintes, o movimento foi ainda mais revelador. Políticos de diferentes campos — inclusive possíveis adversários na eleição — se manifestaram positivamente sobre a entrega. Um raro momento de convergência. Mas esse tipo de consenso não significa alinhamento. Significa outra coisa: dificuldade de enfrentamento imediato.\nA obra, neste momento, é difícil de ser atacada.\n\n**O deslocamento do eixo da eleição.**\nAté aqui, o debate eleitoral estava disperso.\nCom a ponte, há um risco — ou uma oportunidade, dependendo do lado: o eixo da eleição pode migrar para a gestão. Se isso acontecer, o cenário muda.\n\n> Porque eleições centradas em entrega concreta, geram resultados imediatos:\n\n•	reduzem espaço para discurso abstrato \n•	aumentam o peso da comparação administrativa \n•	favorecem quem já governou \n\n**O movimento esperado do governo.**\nApós um gesto de alto impacto, o próximo passo tende a ser claro. O governador Ratinho Junior deve intensificar uma agenda de continuidade:\n•	circulação pelo interior \n•	destaque para outras obras \n•	aproximação com prefeitos \n•	ampliação da presença política do seu grupo. \nO objetivo, claro, será transformar um evento em sequência, capitalizar o momento positivo para o governo e, consequentemente, para o potencializar a candidatura de Sandro Alex.\nPorque um fato isolado marca.\nMas uma sequência, consolida.\n\n**O ponto mais sensível: a sucessão.**\nA inauguração resolve uma questão: demonstra capacidade de entrega, mas abre outra — mais complexa: quem herda essa entrega?\n\n> A eleição passa a exigir algo específico:\n> •	transformar obra em voto \n> •	associar gestão a candidatura \n> •	converter aprovação em transferência política \n> E esse processo nunca é automático.\n\n**O tempo da reação.**\nA oposição tende a reagir.\nMas o tempo importa.\nQuanto mais demora, mais o fato se consolida.\nOs próximos movimentos devem tentar:\n•	deslocar o debate para outros temas \n•	relativizar o impacto da obra \n•	ou reconfigurar o eixo da disputa. \nPorque, se o debate permanecer onde está, o campo da disputa já começa inclinado.\n\n**O que realmente mudou.**\nA semana não muda quem está na frente.\nMas muda o ambiente.\n\n> Sai o cenário abstrato e entra o cenário concreto. E isso altera a lógica da eleição.\n> \n\n**E aí?**\nA inauguração da ponte não decide a eleição. Mas pode ter definido o terreno onde ela será disputada. E isso, na política, é decisivo. Porque quem disputa no terreno mais favorável, não precisa apenas crescer. Precisa manter.\n\n**Fato.**\nA ponte foi entregue e o efeito não é apenas físico. É político. E, a partir desta semana, a eleição deixa de ser uma projeção e começa a ser uma disputa real.\n',NULL,'/api/media/materia/58c90808-64aa-4f5c-bc42-75e8c7f5c318/imagens/1777900884424-Ponte_com_Ratinho_e_Sandro_III.png',NULL,0,'published','2026-05-04 13:21:28.927','2026-05-04 12:34:46.959','2026-05-09 07:59:53.956','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura/AEN',12,NULL),
('58dab7c4-fcd4-495d-9a4b-5df471518e0d','A campanha do governo Ratinho Junior revela algo maior: o Paraná funciona','a-campanha-do-governo-ratinho-junior-revela-algo-maior-o-parana-funciona-eltok','A campanha institucional lançada pelo Governo do Paraná não é apenas publicidade oficial.','É, na prática, uma tentativa de consolidar politicamente a narrativa de que o estado vive um ciclo consistente de transformação econômica, estrutural e social. \n\n> E esse é o aspecto mais relevante, justamente porque o governo não escolheu vender promessa. Escolheu vender resultado.\n\n**A estratégia.**\nHá uma diferença importante entre propaganda emocional vazia e comunicação baseada em indicadores.\nO governo decidiu ancorar a campanha em dados concretos:\n\n- menor desemprego da história \n- quarta maior economia do Brasil \n- liderança nacional no Ideb \n- redução histórica da criminalidade \n- crescimento de investimentos \n- obras estruturantes \n- programas habitacionais \n- e expansão da infraestrutura.\n\nIsso revela confiança política.\nPorque governos que enfrentam desgaste, normalmente evitam transformar números em peça central de comunicação.\n\n**Estado eficiente.**\nA campanha também mostra algo maior: o governo Ratinho Junior quer posicionar o Paraná como referência nacional de gestão pública.\n\n> A mensagem transmitida é clara: equilíbrio fiscal, investimento pesado, capacidade de execução e presença regional.\n \nNão por acaso, a campanha utiliza a Ponte de Guaratuba, rodovias em concreto, programas de pavimentação, habitação, educação tecnológica e infraestrutura urbana como símbolos visuais do governo. \n\n**Inteligência política**\nTalvez a principal sacada da campanha esteja na forma como ela conecta: obra pública + impacto cotidiano. Ou seja, o governo não comunica apenas pontes, estradas ou escolas. Comunica emprego, mobilidade, segurança, moradia e oportunidade. Isso aproxima a gestão da vida real da população.\n\n**Construção de legado**\nEsse é outro ponto evidente. No último ano de mandato, Ratinho Junior não atua como um governador em despedida. Pelo contrário: intensifica entregas, amplia presença no interior, lança campanhas institucionais e reforça indicadores positivos. Tudo isso ajuda a consolidar um legado administrativo.\nE, inevitavelmente, prepara o terreno político para a sucessão estadual.\n\n**Comunicação baseada em alta performance.**\nMas existe um ponto importante. Quando um governo escolhe comunicar resultados em larga escala, ele também aumenta o nível de cobrança pública. Porque quanto maior a narrativa de eficiência, maior será a expectativa da população.\nE isso vale especialmente para a saúde, educação, mobilidade, segurança e desigualdade regional. \n\n> Ou seja, a campanha fortalece o governo, mas também cria obrigação política de manter o desempenho elevado.\n\n**A importância da percepção**\nNa política moderna, não basta realizar. É preciso, comunicar, repetir, simboliza e transformar gestão em percepção coletiva. E o governo Ratinho Junior compreendeu isso perfeitamente.\nA campanha da harpia — símbolo de visão estratégica e força — tenta justamente construir essa ideia: um Paraná moderno, conectado, competitivo e eficiente. \n\n**O impacto político é inevitável.**\nHá também uma leitura eleitoral impossível de ignorar. Toda campanha institucional em fim de mandato inevitavelmente reforça marca de governo, aprovação administrativa e capital político do grupo governista. \nEspecialmente quando os indicadores divulgados são positivos. \n\n> E isso se conecta diretamente ao ambiente de pré-campanha que envolve o nome de Sandro Alex. \n\nAfinal, a mensagem subliminar se encaixa perfeitamente: se um governo é bom, é preciso ter continuidade\n\n**E aí?**\nA campanha do Governo do Paraná não vende apenas obras.\nVende a ideia de um estado que cresceu, investiu e se organizou. E, politicamente, isso possui enorme valor. Porque o eleitor costuma premiar governos que conseguem transmitir sensação de funcionamento e estabilidade.\n\n**Fato**\nDurante muitos anos, governos brasileiros aprenderam a administrar crise. O Paraná apresenta outra narrativa: gestão de resultado. E a campanha da Harpia deixa isso claro: não se trata apenas de mostrar obras.\nTrata-se de convencer a população de que o estado vive um ciclo de transformação contínua.\n***E, na política, quando um governo consegue transformar números em percepção popular, ele deixa de comunicar apenas administração. Passa a comunicar legado.***\n',NULL,'/api/media/materia/novo-1779191063836-re5dv2rtp/imagens/1779191092393-Harpia.jpg',NULL,0,'published','2026-05-19 13:00:57.274','2026-05-19 11:50:31.459','2026-05-29 12:48:22.977','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: SECOM',6,NULL),
('59f4b84e-e709-4af4-bddd-fa6cc42f3869','Semana do feriado terá sol e temperaturas amenas, com chuva fraca apenas no Litoral','semana-do-feriado-tera-sol-e-temperaturas-amenas-com-chuva-fraca-apenas-no-litoral-s7gsm','De acordo com o Simepar, há previsão apenas de registro de chuva fraca ocasional entre a Serra do Mar e as praias em alguns dos dias.','A primeira semana de junho será de trégua nas tempestades e amplitude térmica típica de outono: temperaturas mais amenas no amanhecer, e mais agradáveis no fim da tarde. De acordo com o Simepar, Sistema de Tecnologia e Monitoramento Ambiental do Paraná, há previsão apenas de registro de chuva fraca ocasional entre a Serra do Mar e as praias em alguns dos dias. Nas outras regiões do Estado, com predomínio de sol, as temperaturas máximas voltam a ultrapassar os 25°C principalmente em cidades no Norte, Noroeste e Oeste do Paraná. \n\nA estabilidade no tempo chega depois de um fim de semana com muita chuva no interior do estado. No domingo (31), a estação meteorológica do Simepar em Laranjeiras do Sul registrou 20,8 mm de chuva. No sábado (30), os maiores valores acumulados foram em General Carneiro (13,8 mm) e Palmas (7,6 mm). Na sexta-feira (29), a chuva foi mais volumosa, chegando a 37,2 mm em Pato Branco, 24,4 mm em Santa Helena, 18 mm em Laranjeiras do Sul, 15,8 mm em Toledo e Guaíra, e 15 mm em Palotina. \n\nAo longo desta semana, as temperaturas no amanhecer ficam em torno de 12°C e 13°C no Oeste, Noroeste e Norte; entre 7°C e 8°C no Centro Sul e Sul, e entre 9°C e 10°C na Região Metropolitana de Curitiba. À tarde, podem chegar aos 26°C em cidades do Norte e Noroeste, aos 25°C em cidades do Oeste, e não passa dos 20°C no Centro Sul e Região Metropolitana de Curitiba. ',NULL,'/api/media/materia/novo-1780321602771-jhynsr8ui/imagens/1780321608621-IP_S.jpg',NULL,0,'published','2026-06-02 11:05:22.532','2026-06-01 13:48:06.196','2026-06-07 06:02:33.983','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Denis Ferreira Netto/SEDEST',6,NULL),
('5fa1db67-1d6c-46fb-8291-40ff3f0731ae','Ratinho Junior transforma interiorização em força política e aproxima Sandro Alex e Alexandre Curi do eleitor paranaense','ratinho-junior-transforma-interiorizacao-em-forca-politica-e-aproxima-sandro-alex-e-alexandre-curi-do-eleitor-paranaense-gmuuc','E o resultado é visível, ginásios lotados, praças cheias, lideranças mobilizadas, prefeitos alinhados e uma recepção calorosa em cada município visitado.','O governo Ratinho Junior encontrou uma fórmula política extremamente eficiente: governar perto das pessoas.\n\nEnquanto muitos governadores concentram agendas na capital ou em grandes cidades, Ratinho Junior decidiu transformar o interior do Paraná no centro da gestão estadual.\n\nE o resultado é visível, ginásios lotados, praças cheias, lideranças mobilizadas, prefeitos alinhados e uma recepção calorosa em cada município visitado. \n\n> Nas pequenas cidades, como Altamira do Paraná e Laranjal, a 450 kms de Curitiba, a chegada do governador vira acontecimento regional.\n\nE isso não ocorre apenas por questão política. Ocorre porque o governo leva obras, pavimentação, máquinas, barracões industriais, escolas, estradas rurais e investimentos concretos. \n\nO governador Carlos Massa Ratinho Junior autorizou em Altamira do Paraná, a execução da pavimentação asfáltica da estrada que liga o município a Laranjal, na região Central do Estado. \n\nA obra, considerada uma demanda histórica da população local, terá investimento de R$ 156,4 milhões para pavimentação de cerca de 30 quilômetros. \n',NULL,'/api/media/materia/novo-1779919400815-4dcgxgzwj/imagens/1779919403709-Ratinho__Sandro__Alexandre_Laranjal.jpg',NULL,0,'published','2026-05-31 22:30:55.978','2026-05-27 22:04:51.292','2026-06-03 06:12:11.009','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ricardo Zanoncini/AEN',8,NULL),
('60a51417-fe9a-4310-905f-edff10a1dcf2','A campanha do governo Ratinho Junior revela algo maior: o Paraná funciona','a-campanha-do-governo-ratinho-junior-revela-algo-maior-o-parana-funciona-3z8xb','A campanha institucional lançada pelo Governo do Paraná não é apenas publicidade oficial.','É, na prática, uma tentativa de consolidar politicamente a narrativa de que o estado vive um ciclo consistente de transformação econômica, estrutural e social. \n\n> E esse é o aspecto mais relevante, justamente porque o governo não escolheu vender promessa. Escolheu vender resultado.\n\n**A estratégia.**\nHá uma diferença importante entre propaganda emocional vazia e comunicação baseada em indicadores.\nO governo decidiu ancorar a campanha em dados concretos:\n- menor desemprego da história \n- quarta maior economia do Brasil \n- liderança nacional no Ideb \n- redução histórica da criminalidade \n- crescimento de investimentos \n- obras estruturantes \n- programas habitacionais \n- e expansão da infraestrutura. \nIsso revela confiança política.\nPorque governos que enfrentam desgaste, normalmente evitam transformar números em peça central de comunicação.\n\n**Estado eficiente.**\nA campanha também mostra algo maior: o governo Ratinho Junior quer posicionar o Paraná como referência nacional de gestão pública.\n\n> A mensagem transmitida é clara: equilíbrio fiscal, investimento pesado, capacidade de execução e presença regional.\n \nNão por acaso, a campanha utiliza a Ponte de Guaratuba, rodovias em concreto, programas de pavimentação, habitação, educação tecnológica e infraestrutura urbana como símbolos visuais do governo. \n\n**Inteligência política**\nTalvez a principal sacada da campanha esteja na forma como ela conecta: obra pública + impacto cotidiano. Ou seja, o governo não comunica apenas pontes, estradas ou escolas. Comunica emprego, mobilidade, segurança, moradia e oportunidade. Isso aproxima a gestão da vida real da população.\n\n**Construção de legado**\nEsse é outro ponto evidente. No último ano de mandato, Ratinho Junior não atua como um governador em despedida. Pelo contrário: intensifica entregas, amplia presença no interior, lança campanhas institucionais e reforça indicadores positivos. Tudo isso ajuda a consolidar um legado administrativo.\nE, inevitavelmente, prepara o terreno político para a sucessão estadual.\n\n**Comunicação baseada em alta performance.**\nMas existe um ponto importante. Quando um governo escolhe comunicar resultados em larga escala, ele também aumenta o nível de cobrança pública. Porque quanto maior a narrativa de eficiência, maior será a expectativa da população.\nE isso vale especialmente para a saúde, educação, mobilidade, segurança e desigualdade regional. \n\n> Ou seja, a campanha fortalece o governo, mas também cria obrigação política de manter o desempenho elevado.\n\n**A importância da percepção**\nNa política moderna, não basta realizar. É preciso, comunicar, repetir, simboliza e transformar gestão em percepção coletiva. E o governo Ratinho Junior compreendeu isso perfeitamente.\nA campanha da harpia — símbolo de visão estratégica e força — tenta justamente construir essa ideia: um Paraná moderno, conectado, competitivo e eficiente. \n\n**O impacto político é inevitável.**\nHá também uma leitura eleitoral impossível de ignorar. Toda campanha institucional em fim de mandato inevitavelmente reforça marca de governo, aprovação administrativa e capital político do grupo governista. \nEspecialmente quando os indicadores divulgados são positivos. \n\n> E isso se conecta diretamente ao ambiente de pré-campanha que envolve o nome de Sandro Alex. \n\nAfinal, a mensagem subliminar se encaixa perfeitamente: se um governo é bom, é preciso ter continuidade\n\n**E aí?**\nA campanha do Governo do Paraná não vende apenas obras.\nVende a ideia de um estado que cresceu, investiu e se organizou. E, politicamente, isso possui enorme valor. Porque o eleitor costuma premiar governos que conseguem transmitir sensação de funcionamento e estabilidade.\n\n**Fato**\nDurante muitos anos, governos brasileiros aprenderam a administrar crise. O Paraná apresenta outra narrativa: gestão de resultado. E a campanha da Harpia deixa isso claro: não se trata apenas de mostrar obras.\nTrata-se de convencer a população de que o estado vive um ciclo de transformação contínua.\n***E, na política, quando um governo consegue transformar números em percepção popular, ele deixa de comunicar apenas administração. Passa a comunicar legado.***\n',NULL,'/api/media/materia/novo-1779191063836-re5dv2rtp/imagens/1779191092393-Harpia.jpg',NULL,0,'archived','2026-05-19 11:50:50.988','2026-05-19 11:50:50.989','2026-05-19 11:51:55.636','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: SECOM',0,NULL),
('62351d99-c857-40c7-9c09-3749ff0feae0','Acabamentos finais: falta um dia para a inauguração da Ponte de Guaratuba','acabamentos-finais-falta-um-dia-para-a-inauguracao-da-ponte-de-guaratuba-7hkzg','Além da cerimônia oficial, a inauguração também vai contar com um show de drones e fogos de artifício. No sábado (2) e domingo (3), a Ponte de Guaratuba estará no itinerário da Maratona Internacional do Paraná (MIP)','A espera de 40 anos está chegando ao fim. Falta apenas um dia para a inauguração da Ponte de Guaratuba, que será entregue à população pelo governador Carlos Massa Ratinho Junior no fim da tarde desta sexta-feira (1º). \n\n> Dois anos após a implantação da primeira estaca, a estrutura que conecta Guaratuba a Matinhos, no Litoral do Paraná, dará fim à travessia com o ferry boat pela Baía de Guaratuba.\n\nAlém da cerimônia oficial com autoridades, a inauguração da obra, batizada oficialmente de Ponte da Vitória, também vai contar com um show de drones e fogos de artifício. No sábado (2) e domingo (3), a Ponte de Guaratuba estará no itinerário da Maratona Internacional do Paraná (MIP), que deve reunir cerca de 20 mil atletas. A liberação do tráfego de veículos vai acontecer no domingo, às 13h, após o encerramento da maratona.\n\nNesta quinta-feira (30) que antecede o grande momento há trabalhos apenas de acabamentos. A sinalização e a instalação de guarda-corpos e barreiras já foi foram concluídas, assim como as ciclovias e calçadas, além das alças de acesso nos dois lados. Também está em fase final de acabamento o paisagismo com plantio de gramas, a iluminação e a preparação da estrutura para o transporte definitivo de veículos.',NULL,'/api/media/materia/62351d99-c857-40c7-9c09-3749ff0feae0/imagens/1777629047999-ponte..jpg',NULL,0,'published','2026-05-03 21:50:08.584','2026-04-30 12:32:32.815','2026-05-06 09:42:29.507','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Arnaldo Neto/AEN',6,NULL),
('636853a1-9767-4b88-a2af-57873bcf331e','O efeito \"Dark Horse\" - Futura/Apex: Lula tem 42,7%, e Flávio, 35,6% no 1º turno','o-efeito-dark-horse-futuraapex-lula-tem-427percent-e-flavio-356percent-no-1o-turno-o66og','Foram testados outros dois cenários. Em um deles, Flávio Bolsonaro ficou de fora do questionamento, onde Lula lidera com 39% das intenções de voto','Segundo pesquisa Futura/Apex divulgada nesta sexta-feira (22), o presidente Luiz Inácio Lula da Silva (PT) tem 42,7% das intenções de voto em um eventual cenário de primeiro turno. Já o senador Flávio Bolsonaro (PL-RJ) aparece com 35,6%.\n\nA seguir, uma sequência de candidatos aparecem empatados tecnicamente: Romeu Zema (Novo) tem 3,9%; Ronaldo Caiado (PSD), 3,3%; Renan Santos (Missão), 1,7%; Cabo Daciolo (Mobiliza), 1%; Augusto Cury (Avante), 0,9%; e Aldo Rebelo (DC), 0,4%.\n\nForam testados outros dois cenários. Em um deles, Flávio Bolsonaro ficou de fora do questionamento, onde Lula lidera com 39% das intenções de voto.\n\nA seguir, Romeu Zema registra 13,3%; Ronaldo Caiado, 13,1%; Renan Santos, 3,1%; Cabo Daciolo, 2,9%; Augusto Cury, 2,6%; e Aldo Rebelo, 1,6%.\n\nVotos em branco, nulos e ninguém são 18,3%. Já os indecisos correspondem a 6,1%.\n\nNo último cenário testado, agora com Michelle Bolsonaro (PL) no lugar de Flávio, Lula continua na liderança, com 40% das intenções de voto. A ex-primeira-dama aparece logo em seguida, com 27,4%.\n\nPor sua vez, Zema assinala 13,3%, contra 13,1% de Caiado. Augusto Cury e Renan Santos têm 2% cada; Cabo Daciolo, 1,3%; e Aldo Rebelo, 0,4%.\n\nVotos em branco, nulos e ninguém equivalem a 9,7%. Outros 3,1% não souberam responder.\n\nMetodologia\n\nA Futura/Apex entrevistou 2.000 eleitores de 878 cidades brasileiras entre os dias 15 e 20 de maio, por meio de entrevistas por telefone. A margem de erro do levantamento é de 2,2 pontos percentuais, para mais ou para menos, com intervalo de confiança de 95%.\n\nA pesquisa foi realizada com recursos do próprio instituto e está registrada no TSE (Tribunal Superior Eleitoral) sob o protocolo BR-06529/2026.\n\nDo Portal cnnbrasil\n',NULL,'/api/media/materia/novo-1779478968207-tmojtbsa9/imagens/1779478968976-Lula_flavio.jpg',NULL,0,'published','2026-05-22 19:44:13.377','2026-05-22 19:43:20.454','2026-05-31 22:07:03.818','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,6,NULL),
('63ebe751-f4db-4c4c-8b62-7085343c99c6','Portos do Paraná bate recorde histórico e ultrapassa 70 milhões de toneladas em 2025','portos-do-parana-bate-recorde-historico-e-ultrapassa-70-milhoes-de-toneladas-em-2025-fyc36','A expectativa é aumentar ainda mais essa escala de movimentação, com previsão de alcançar entre 72 e 73 milhões de toneladas até o dia 31 de dezembro.','A Portos do Paraná, o Ministério de Portos e Aeroportos (MPor) e a Agência Nacional de Transportes Aquaviários (Antaq), em parceria com o Instituto Superior do Litoral do Paraná (Isulpar), realizam a 7ª edição da Caravana de Inovação Portuária. \n\n> A iniciativa conecta diferentes setores ao ambiente logístico portuário, com o objetivo de estimular soluções que tornem o setor mais eficiente, sustentável e competitivo\n\nA programação teve início nesta terça-feira (5), com atividades voltadas exclusivamente às equipes técnicas do MPor, Antaq e Portos do Paraná. Amanhã, quarta-feira (6), o evento será aberto ao público e os representantes da Portos do Paraná, do MPor e da Antaq estarão disponíveis para atendimento à imprensa no saguão de entrada do auditório do Isulpar, das 8h às 8h30. Haverá palestras, painéis temáticos e apresentações de startups.',NULL,'/api/media/materia/novo-1777989892895-apexu54f9/imagens/1777989894134-Portos_do_Paran_.jpg',NULL,0,'published','2026-05-05 14:07:52.500','2026-05-05 14:06:33.122','2026-05-11 05:40:23.579','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Claudio Neves/Portos do Paraná',7,NULL),
('66c83773-b60f-4bf5-893c-3f309c02ba36','Rafael Greca: o candidato que não lidera — mas muda o jogo','rafael-greca-o-candidato-que-nao-lidera-mas-muda-o-jogo-ei0bm','Um candidato com base — e limite. Greca carrega ativos relevantes','A entrada de Rafael Greca na disputa pelo governo do Paraná não altera quem está na frente.\nMas altera o que está em disputa.\nE isso, neste momento, pode ser mais importante.\n\n**1. Um candidato de reposicionamento**\nNa pesquisa Genial/Quaest divulgada em 27/04, Greca aparece com cerca de 15% das intenções de voto, em empate técnico com Requião Filho, enquanto Sérgio Moro lidera com 35%. \n\nÀ primeira vista, é um desempenho intermediário.\nMas, na prática, revela outra coisa:\nGreca entra como candidato de reorganização do tabuleiro\n\n> Ele não lidera.\n> Mas impede que a eleição se simplifique.\n> \n\n**2. O efeito mais relevante: mexer no segundo turno**\nA própria leitura da Quaest indica que a presença de Greca pode alterar o desenho do segundo turno, inclusive afastando a esquerda de uma eventual disputa direta com Moro. \nIsso mostra um ponto central:\nGreca não disputa apenas votos\nEle disputa quem chega ao segundo turno\nE isso o coloca em uma posição estratégica.\n\n**3. Um candidato com base — e limite.\nGreca carrega ativos relevantes:**\n•	três mandatos como prefeito de Curitiba \n•	forte identificação com a capital \n•	trajetória administrativa consolidada. \nMas os dados da Quaest mostram um limite claro:\n•	34% dizem que votariam nele \n•	33% não o conhecem \n•	33% conhecem e não votariam. \nOu seja:\nele tem base — mas também tem teto\n\n**4. O fator político mais delicado: isolamento**\nOs acontecimentos recentes indicam um problema estrutural.\nGreca segue como pré-candidato, mas ainda busca um alinhamento mais claro com o grupo de Ratinho Junior — algo que, até agora, não se concretizou plenamente. \nIsso cria uma posição ambígua:\n•	não é candidato do governo \n•	não é oposição ideológica clara \n•	não lidera o campo alternativo. \nFica no meio.\nE, na política, o meio pode ser espaço —\nou pode ser isolamento.\n\n**5. Onde Greca pode crescer — e onde pode travar**\nA pesquisa mostra que há espaço eleitoral aberto:\n•	84% indecisos no cenário espontâneo \n•	67% admitem que ainda podem mudar o voto \nIsso favorece candidatos com capacidade de crescimento.\nMas exige algo específico:\nNarrativa clara de candidatura.\nE aqui está o desafio de Greca.\n\n> Ele ainda não se apresenta como:\n> •	continuidade \n> •	ruptura \n> •	ou alternativa ideológica \n\nGreca ainda é uma possibilidade.\nGreca não uma escolha definida\n\n**E aí?**\nRafael Greca não entra na eleição como favorito.\nMas entra como variável.\nUma variável que:\n•	impede a polarização imediata \n•	reorganiza o segundo turno \n•	e disputa um espaço ainda indefinido. \nNo cenário atual, sua candidatura representa menos uma ameaça direta à liderança de Moro — e mais um fator de instabilidade no equilíbrio da disputa.\nE, em eleições abertas, instabilidade não é detalhe. É caminho.\n\n**Fato**\nGreca não lidera.\nMas atrapalha quem quer liderar com conforto.\nE, às vezes, na política, isso já é suficiente para mudar o resultado.\n',NULL,'/api/media/materia/novo-1777468020343-lds3y9b6u/imagens/1777468023147-RAFAEL_GRECA.jfif',NULL,0,'published','2026-04-29 13:14:21.415','2026-04-29 13:07:47.347','2026-05-26 21:21:15.450','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Rodrigo Fonseca/CMC',13,NULL),
('679ba9c7-d191-4e78-8bff-198ffb67c736','Policia Civil participa de operação nacional de combate à violência contra crianças e adolescentes','policia-civil-participa-de-operacao-nacional-de-combate-a-violencia-contra-criancas-e-adolescentes-7jxk0','Em 2025, a corporação realizou 180 prisões de foragidos da justiça por crimes cometidos contra crianças e adolescentes.','A Polícia Civil do Paraná (PCPR) participa da Operação Caminhos Seguros, coordenada pela Secretaria Nacional de Segurança Pública. \n\n> A ação tem como objetivo combater a violência e proteger crianças e adolescentes, ocorrerá até 18 de maio.\n\nEsta é a segunda edição com a participação da PCPR. Em 2025, a corporação realizou 180 prisões de foragidos da justiça por crimes cometidos contra crianças e adolescentes.\n\nA ação, que faz alusão à campanha Maio Laranja, tem como objetivo direcionar esforços para a implementação de ações policiais de natureza preventiva, educativa, ostensiva e repressiva para o enfrentamento de todas as formas de violência contra crianças e adolescentes em todo o Paraná.\n\nPara a delegada-chefe da Divisão de Polícia Especializada da PCPR, Luciana Novaes, a segurança pública do Paraná tem se empenhado em fortalecer estratégias de proteção às crianças e adolescentes. “Esse esforço que se concretiza por meio da participação em ações nacionais, na criação e implementação de protocolos de atendimento humanizados, além da capacitação de nossos policiais para que atuem em casos desta natureza”.\n\nDurante os dias de operação, a PCPR vai reforçar as ações de polícia judiciária nos Núcleos de Proteção às Crianças e Adolescentes Vítimas de Crime (Nucrias), nas Delegacias da Mulher, além de outras unidades policiais em todo o Estado. Todas elas atuarão de forma coordenada para o cumprimento de mandados de prisão em aberto de indivíduos condenados ou investigados por crimes contra menores.\n\nAo longo de todo o mês, também estão previstas ações de conscientização em escolas públicas e privadas por meio de palestras e rodas de conversa direcionadas para o público estudantil. A ideia é orientar crianças e jovens para que consigam reconhecer situações de perigo e saibam como pedir ajuda.',NULL,'/api/media/materia/novo-1778068393839-rv79dv52h/imagens/1778068395644-PCPR_I.jpg',NULL,0,'published','2026-05-06 11:54:55.174','2026-05-06 11:54:55.200','2026-05-10 04:34:20.672','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: PCPR',5,NULL),
('69bd2349-1a7d-46bd-a7d1-de485504a025','Paraná Pesquisas e IRG irão dizer se a disputa está no caminho certo ou se será preciso mudar de estratégia  ','parana-pesquisas-e-irg-irao-dizer-se-a-disputa-esta-no-caminho-certo-ou-se-sera-preciso-mudar-de-estrategia-98smp','O principal ponto de atenção dos dois institutos será observar se Sandro Alex continua crescendo','A entrada simultânea de dois institutos — Paraná Pesquisas e IRG Pesquisa e Marketing — para medir a corrida ao Palácio Iguaçu e ao Senado não é apenas mais uma rodada de levantamentos.\nÉ um sinal político.\nE o sinal é claro: o ambiente pré-eleitoral começou a acelerar.\n\n**As pesquisas agora passam a mover o jogo**.\nAté aqui, as pesquisas serviam mais para identificar tendências.\nA partir de agora, elas começam a produzir consequências práticas:	movimentam alianças, influenciam prefeitos, alteram comportamento partidário, pressionam candidaturas. \n\n> Uma pesquisa deixa de apenas medir, e passa a interferir diretamente na disputa\n\n.\n**O foco principal será Sandro Alex**.\nO principal ponto de atenção dos dois institutos será observar se Sandro Alex continua crescendo. E isso ocorre por alguns fatores recentes:\n\n   **1 - intensificação da presença do governador Ratinho Junior;**\n \n   **2 - impacto político da inauguração da Ponte da Vitória**;\n\n   **3 - aumento da exposição do PSD**; \n\n   **4 - aproximação cada vez maior entre governo estadual e Curitiba**.\n\nO dado mais relevante não será apenas o percentual. Será a velocidade do crescimento.\n\n**Moro, principal adversário, entra em um novo teste**.\nAté agora, Sérgio Moro lidera com relativa vantagem nas pesquisas conhecidas. Mas os novos levantamentos podem começar a responder outra pergunta: a liderança está estabilizada ou começou a sofrer desgaste?\nPorque existe uma diferença importante entre:\n•	liderar por notoriedade \n•	e liderar sob pressão crescente de campanha. \n\n**O Senado pode reorganizar a eleição**.\nOutro elemento decisivo será a disputa ao Senado.\nEla tende a revelar: acomodações partidárias, distribuição de forças regionais, e o peso político de nomes ligados ao grupo governista.\nEspecialmente após a entrada de figuras como Cristina Graeml no PSD e o fortalecimento do eixo político em Curitiba.\n\n**O fator Curitiba ganha ainda mais peso**.\nAs próximas pesquisas também devem medir o impacto do alinhamento entre:\ngoverno estadual; prefeitura de Curitiba \nPSD; e o grupo político liderado por Ratinho Junior.\nCom Eduardo Pimentel consolidado na capital, o grupo governista tenta transformar Curitiba em centro de sustentação da pré-campanha.\nIsso pode alterar a dinâmica da Região Metropolitana inteira.\n\n**O reflexo imediato na pré-campanha**.\nAs consequências serão rápidas:\n\n- **Se Sandro Alex crescer:** o PSD acelera o discurso de continuidade, Ratinho Junior amplia presença política e prefeitos tendem a se aproximar ainda mais do projeto governista. \n\n- **Se Moro mantiver vantagem confortável**: oposição ganha confiança, cresce pressão para polarização antecipada e a candidatura se fortalece como favorita inicial. \n\n- **Se houver aproximação**: o clima político muda completamente, a disputa deixa de ser previsível, e o Paraná entra oficialmente em cenário competitivo. \n\n**E aí?**\nA entrada da Paraná Pesquisas e do IRG não representa apenas novos números. E é verdade que a ansiedade será grande por esses números.\nRepresenta sim o início de uma nova etapa da eleição.\nPorque campanhas ainda podem ser construídas.\n\n> Mas percepções de crescimento ou enfraquecimento começam agora a influenciar todo o sistema político.\n\n**Fato**.\nAté aqui, o Paraná tinha favoritos.\nAs próximas pesquisas vão mostrar se começa a surgir algo mais perigoso para quem lidera: competitividade real.\nE, na política,\no momento em que uma candidatura deixa de apenas existir\ne passa a ameaçar, muda completamente a eleição.\nAguardemos!\n',NULL,'/api/media/materia/69bd2349-1a7d-46bd-a7d1-de485504a025/imagens/1778196590930-candidato_e_Ratinho.png',NULL,0,'published','2026-05-07 23:29:55.184','2026-05-07 21:40:00.688','2026-05-12 09:40:14.387','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: reprodução/montagem',15,NULL),
('6e4af98c-57e3-4d4e-a04b-939ad5c6eace','O teste da coerência','o-teste-da-coerencia-319os','o comportamento político acompanha a imagem construída? ','Toda candidatura passa por um teste silencioso.\nNão é o teste do discurso.\nÉ o teste da coerência.\n\nO que foi defendido antes sustenta o que está sendo proposto agora? \n•	as posições se mantêm ou se adaptam conforme o cenário? \n•	o comportamento político acompanha a imagem construída? \n\nQuando essas respostas começam a oscilar, o eleitor percebe.\nE, mais importante:\nComeça a desconfiar da consistência do projeto.\n\n> Porque política não é apenas o que se diz.\n> É a capacidade de manter uma linha — mesmo quando o contexto muda.\n\nSem isso, o que resta é ajuste constante de discurso.\nE ajuste constante, na política, tem outro nome:\ninsegurança estratégica.\n',NULL,'/api/media/materia/6e4af98c-57e3-4d4e-a04b-939ad5c6eace/imagens/1777556579054-coer_ncia.png',NULL,0,'published','2026-04-30 13:43:03.381','2026-04-30 11:48:47.402','2026-06-04 01:03:59.233','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,35,NULL),
('7084589b-fba6-47bc-a2db-450b70fe55e7','Sandro Alex começa a reação. A nova pesquisa mostra que Ratinho Junior é quem dá e quem dará as cartas nessa eleição.','sandro-alex-comeca-a-reacao-a-nova-pesquisa-mostra-que-ratinho-junior-e-quem-da-e-quem-dara-as-cartas-nessa-eleicao-oeeqj','A pesquisa do Instituto Veritá divulgada nesta quarta-feira (06/05) reforça algo que o cenário político já começa a perceber: Sérgio Moro lidera, mas o ambiente eleitoral ainda está longe de consolidado.','**O cenário principal**\n\nNo principal cenário estimulado: Sérgio Moro aparece com 58,6% dos votos válidos; Requião Filho tem 20%; Rafael Greca aparece com 9,8%; Sandro Alex surge com 9,6%. \n\nÀ primeira vista, parece um cenário confortável para Moro.\nMas a pesquisa tem um dado ainda mais importante.\n\n**O número que muda a leitura da eleição**\n\n> Na pesquisa espontânea: 71,7% dos eleitores dizem não saber em quem votar. Esse dado altera completamente a interpretação do cenário.\n> Porque mostra que:\n> •	existe liderança \n> •	mas ainda não existe consolidação eleitoral \n\n**Moro lidera — mas lidera uma eleição que ainda não começou completamente**\nMoro entra com vantagens evidentes:\n•	alto conhecimento nacional \n•	eleitorado consolidado \n•	presença forte em Curitiba e Região Metropolitana \n•	associação ainda forte à Lava Jato. \nHoje, ele é o nome mais conhecido da disputa.\nMas há um detalhe importante: conhecimento não elimina volatilidade.\n\n**O dado escondido de Sandro Alex**\nO crescimento de Sandro Alex começa a chamar atenção porque: na Quaest aparecia entre 5% e 6%. Agora chega perto de 10%. \nIsso acontece antes mesmo da campanha entrar de fato nas ruas.\nE há um fator central nisso: a associação ao governo Ratinho Junior.\n\n**A eleição da estrutura contra a eleição da notoriedade**\nO Paraná parece caminhar para uma disputa entre dois modelos políticos:\n\n**Moro**\n•	notoriedade nacional \n•	voto mais consolidado \n•	imagem pública já formada\n\n**Sandro Alex**\n•	estrutura partidária \n•	apoio do governador \n•	prefeitos \n•	máquina política regional \n•	associação às obras do governo. \n\nClaramente, uma disputa entre reconhecimento imediato e construção gradual.\n\n**O fator Ratinho Junior continua sendo decisivo**\nMesmo sem poder disputar novamente, Ratinho Junior continua no centro da eleição.\nPorque existe um paradoxo claro: o governador mantém altíssima aprovação, mas seu sucessor ainda está em processo de consolidação. \nE é exatamente aí que o jogo político começa.\n\n**O que essa pesquisa realmente mostra**\nA nova pesquisa não indica apenas liderança de Moro.\nEla mostra algo mais profundo: a sucessão ainda está aberta.\nPorque eleições altamente indefinidas, como ocorre no momento aqui no Paraná, costumam favorecer:\n•	quem cresce \n•	quem estrutura narrativa \n•	quem ocupa espaço ao longo da campanha.\n\n**E aí?**\nHoje, Moro lidera, dentro da bolha pesquisada.\nMas a eleição ainda pertence aos indecisos.\nE, quando mais de 70% do eleitorado ainda não escolheu um caminho,\no que parece consolidado pode mudar rapidamente. \n',NULL,'/api/media/materia/novo-1778079425376-vspaa2gcs/imagens/1778079428396-Sandro_com_Ratinho_Jr.jpg',NULL,0,'published','2026-05-06 17:13:26.744','2026-05-06 14:58:22.056','2026-05-11 11:57:28.816','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Divulgação PSD',42,NULL),
('74712aaa-6211-4f5b-acd5-3d51737e1644','Sandro Alex cresce e Moro começa a sentir o peso do ambiente nacional.','sandro-alex-cresce-e-moro-comeca-a-sentir-o-peso-do-ambiente-nacional-vmqff','E isso ocorre justamente no momento em que Ratinho Junior intensifica presença no interior','As últimas pesquisas eleitorais do Paraná mostram uma mudança política importante: Sandro Alex deixou de ser apenas um nome competitivo e começou a se consolidar como principal adversário de Sergio Moro. \nE isso ocorre justamente no momento em que Ratinho Junior intensifica presença no interior, quando Sandro Alex passa a acompanhar permanentemente o governador e o ambiente nacional do PL começa a sofrer desgaste político. \n> A disputa mudou de patamar.\n### **O crescimento é estrutural.**\nÉ perceptível que existe uma grande diferença entre crescer por exposição momentânea e crescer por construção política.\nO avanço de Sandro Alex nas pesquisas mostra crescimento estrutural.\nIsso porque ele passou a reunir simultaneamente o apoio do governador mais aprovado do Paraná, presença constante nas entregas de obras, associação direta com resultados administrativos, apoio de prefeitos e forte inserção regional no interior. \nA pesquisa IRG mostrou exatamente isso: quando o eleitor associa Sandro Alex a Ratinho Junior, o crescimento é imediato e consistente. \n### **Moro perdeu o controle absoluto da disputa.**\nSergio Moro ainda lidera. Sua notoriedade permanece, quando o eleitor lembra da Lava Jato, quando esse eleitor é do campo conservador consolidado e tem forte presença em Curitiba. \nMas o cenário já não é o mesmo do início da pré-campanha. As pesquisas recentes apontam que Moro deixou de ampliar vantagem e Sandro começou a encurtar distância. \nIsso tem explicação política clara.\n### **O ambiente nacional e o campo bolsonarista.**\nO crescimento de Sandro Alex coincide com o desgaste nacional envolvendo o entorno político de Flávio Bolsonaro.\nA divulgação de informações envolvendo empresários ligados ao financiamento de estruturas políticas bolsonaristas **(Vorcaro)** e operações em paraísos fiscais ampliou o desgaste do núcleo conservador nacional. \nA reportagem da Folha de S.Paulo reforçou esse ambiente ao revelar conexões empresariais e financeiras envolvendo apoiadores do campo bolsonarista em estruturas offshore. \nIsso produz reflexo político direto, porque Moro passou a ficar mais vinculado ao projeto nacional do PL, enquanto Ratinho Junior mantém distância estratégica de Brasília.\nEsse detalhe virou diferencial eleitoral.\n### **Ratinho Junior e a blindagem política baseada em gestão.**\nO governador evita radicalização ideológica, confrontos nacionais e guerras políticas de Brasília. Tem insistido nesse discurso de que é preciso evitar que os problemas de Brasilia venham para o Paraná. \nSeu foco permanece em obras, infraestrutura, emprego, investimentos, educação e interiorização administrativa. \nIsso protege politicamente Sandro Alex. Enquanto Moro aparece conectado ao debate nacional, ao bolsonarismo e aos desgastes recentes envolvendo aliados, Sandro cresce associado ao governo que entrega resultados.\n### **Sandro Alex virou símbolo de continuidade administrativa.**\nOutro fator decisivo é que Sandro Alex não surgiu agora. Ele foi secretário de Infraestrutura de Ratinho Junior e participou diretamente da expansão rodoviária, das concessões, das pontes, das pavimentações e das grandes obras estaduais. \nGrande parte das entregas atuais carrega participação direta de Sandro Alex. Isso fortalece a narrativa de continuidade.\nO eleitor começa a enxergar Ratinho como liderança consolidada e Sandro como continuidade natural da gestão. \n\n### **Moro enfrenta dificuldade crescente no interior.**\nAs pesquisas começam a revelar outro movimento importante: o interior do Paraná pesa cada vez mais e nesse terreno, Ratinho Junior domina, prefeitos apoiam o governo, Sandro Alex cresce rapidamente e o PSD ocupa politicamente todas as regiões do estado. \nMoro continua com força nos grandes centros, mas, eleição estadual no Paraná, não se vence apenas em Curitiba.\n\n> O experiente Roberto Requião sabe como funciona a eleição nos grandes e nos pequenos municípios.\n\nNa eleição de 2006, quando disputava a reeleição para governador, obteve 50,1% dos votos válidos, apenas 10 mil votos à frente de Osmar Dias, do PDT.\nE qual foi a explicação para essa pequena diferença? Osmar Dias venceu a disputa em todas as cidades com mais de 200 mil habitantes. \n\nEm Curitiba, onde Requião havia sido prefeito, Dias venceu com 470,283 mil votos (50,03%), enquanto Requião obteve 469,696 mil (49,97%). A explicação da época, para essa surpresa de última hora, foi a demora para a chegada dos votos das pequenas cidades para a totalização no TRE, em Curitiba.\n\nDiante dos telões instalados para mostrar a apuração em tempo real, na absoluta maior parte do tempo, Osmar Dias aparecia na frente e, a cada nova parcial, o time dele gritava o proclamava governador. Muitos saíram em carreatas pela cidade, comemorando a vitória.\n\nNos 45 do segundo tempo, quando a diferença começava a diminuir, o time de Osmar foi se acalmando e o time adversário (Requião) começou esticar o pescoço para ver melhor o telão, sem acreditar no que estava acontecendo. Resultado final: os votos dos pequenos municípios deram a vitória a Requião.\n\n> Ratinho Junior conhece bem essa história e está levando ao pé da letra.\n\nAs entregas em pequenas cidades, como Prado Ferreira, que na eleição de 2024 elegeu Silvio Damaceno com 1.445 votos, 52,99% dos votos válidos e em outras tantas, o governador tem sido abraçado, fotografado e recebido o carinho para si e para o seu candidato Sandro Alex. \nOu seja, esse eleitorado pode ser decisivo na eleição deste ano.\n\n### **Enquanto isso, o eleitor compara duas narrativas.**\nA disputa ganha formato muito claro:\n**De um lado:** Sergio Moro, PL, bolsonarismo, ambiente nacional polarizado e desgaste político vindo de Brasília. \n**Do outro:** Ratinho Junior, Sandro Alex, interiorização, gestão, obras e continuidade administrativa. \nE as pesquisas mostram que esse segundo campo começou a crescer com velocidade.\n### **O que as pesquisas realmente revelam.**\nOs levantamentos recentes mostram que:\n✅ Moro ainda lidera;\n✅ Sandro Alex cresce em ritmo consistente;\n✅ Ratinho Junior conseguiu iniciar transferência política real;\n✅ e o ambiente nacional passou a produzir desgaste indireto sobre o campo do PL. \n\n**Fato.**\nSergio Moro continua sendo um candidato forte, mas a eleição do Paraná deixou de ser uma disputa desequilibrada. Sandro Alex entrou definitivamente no jogo, e entrou sustentado pela força política de Ratinho Junior, pela aprovação do governo, presença no interior e a associação direta com obras e entregas. \n***Enquanto Moro tenta administrar os desgastes do ambiente nacional do PL e do entorno político de Flávio Bolsonaro, Sandro Alex cresce vinculado à estabilidade, à gestão e à continuidade. E isso começa a aparecer de forma cada vez mais clara nas pesquisas.***\n',NULL,'/api/media/materia/74712aaa-6211-4f5b-acd5-3d51737e1644/imagens/1779717130485-Ratinho_Jr__Sandro_e_Curi_II.jpeg',NULL,0,'published','2026-05-25 18:56:46.608','2026-05-25 13:40:55.568','2026-05-31 03:27:10.638','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos/Aen',16,NULL),
('829d6a83-c156-4cd3-8443-46041e62cc70','Paraná Pesquisas: o número que realmente importa e que definirá a eleição de 2026','parana-pesquisas-o-numero-que-realmente-importa-e-que-definira-a-eleicao-de-2026-trade','O que chama atenção é outra coisa: Sandro cresce antes mesmo da campanha começar oficialmente.','A nova pesquisa divulgada nesta segunda-feira (11) pelo Paraná Pesquisas confirma algo importante sobre a eleição de 2026 no Paraná: Sérgio Moro continua liderando com ampla vantagem, dentro de um cenário totalmente indefinido, mas Sandro Alex começa a entrar em outro estágio político.\nE esse talvez seja o dado mais relevante do levantamento.\n\n**O crescimento existe — mesmo antes da campanha.**\nNos cenários estimulados, Sandro Alex aparece entre 8,6% e 11% das intenções de voto. \nÀ primeira vista, o número ainda parece distante de Moro, mas a política raramente é analisada apenas pela fotografia do momento.\nO que chama atenção é outra coisa: Sandro cresce antes mesmo da campanha começar oficialmente.\nE isso importa porque ainda tem baixo nível de conhecimento estadual, ainda não entrou em campanha massiva e ainda depende fortemente da associação com Ratinho Junior. \n\n**O dado escondido da pesquisa**.\nO principal ativo de Sandro Alex talvez não esteja apenas na intenção de voto.\nEstá na rejeição.\nSegundo a Paraná Pesquisas: apenas 7,1% dizem que não votariam nele de jeito nenhum. Esse é um número politicamente muito baixo, especialmente quando comparado aos adversários mais conhecidos.\nIsso revela algo importante: Sandro ainda não é um candidato consolidado, mas também não carrega desgaste consolidado. E eleições abertas costumam favorecer candidatos com espaço de crescimento e baixa rejeição.\n\n**O número que realmente muda a eleição.**\nMas há um dado ainda mais importante no levantamento: **71,5% dos eleitores ainda não sabem em quem votar, não opinaram ou afirmam que não pretendem votar em nenhum dos candidatos apresentados.**\nE esse é o principal campo político da eleição.\nPorque esse percentual mostra algo central: o Paraná ainda não consolidou emocionalmente sua disputa eleitoral.\nExiste liderança.\nMas ainda não existe definição coletiva.\n\nO que significa um índice tão alto de indecisos?\nNa prática, esse número revela três fenômenos:\nA campanha ainda não começou de verdade para grande parte do eleitorado. O debate político ainda está muito concentrado em grupos politizados, redes sociais, bastidores partidários e cobertura política especializada. \nO eleitor comum ainda observa à distância.\n\n**A força do governo ainda vai entrar mais forte na disputa.**\nEnquanto Ratinho Junior mantém aprovação elevada e intensifica agendas pelo interior, parte desse eleitorado ainda não associou diretamente Sandro Alex ao projeto de continuidade. E é exatamente aí que o governo pretende atuar nos próximos meses.\nA liderança de Moro ainda não virou consolidação definitiva.\nNeste cenário apresentado, Moro lidera com folga, mas, com mais de 70% de indefinição espontânea, a liderança ainda pode sofrer oscilações importantes quando:\n•	a campanha ganhar intensidade \n•	o horário eleitoral começar \n•	e o confronto político aumentar. \n\n**A força invisível da campanha já começou.**\nHá outro elemento relevante: Sandro Alex acompanha praticamente todas as agendas estratégicas do governo Ratinho Junior.\nObras, inaugurações, viagens ao interior e entregas regionais passaram a funcionar como pré-campanha indireta.\nO governo entrega, Sandro aparece ao lado e a associação política começa a se consolidar.\nA Ponte da Vitória talvez tenha sido o exemplo mais simbólico desse movimento.\n\n**Moro lidera — mas já entrou na fase de defesa.**\nA pesquisa mostra Moro acima de 40% em alguns cenários.\nIsso demonstra força evidente, mas também muda sua posição política.\nQuem lidera cedo deixa de apenas crescer e passa a precisar se sustentar.\nE sustentar liderança durante uma campanha longa costuma ser mais difícil do que conquistar espaço.\n\n**O fator Ratinho Junior continua no centro.**\nO dado estrutural da eleição continua sendo o mesmo: Ratinho Junior mantém aprovação próxima de 80%, e isso cria uma situação rara:\nUm governador extremamente forte, tentando construir uma sucessão, enquanto ainda mantém presença política intensa em todo o estado. \nAs muitas viagens pelo interior, as muitas entregas de obras e a agenda acelerada não indicam clima de despedida. Indicam tentativa clara de continuidade.\n\n**O Paraná começa a viver duas eleições.**\nHoje existem duas disputas acontecendo simultaneamente:\nA eleição da notoriedade, representada por Moro, que em seus discursos discute apenas as questões nacionais, o PT, o Lula, etc, que detém esse reconhecimento nacional, tem uma presença relativamente consolidada e essa liderança de momento. \nA eleição da construção, representada por Sandro Alex, que está em pleno crescimento, mantém associação com o governo, conta com boa estrutura política do PSD, tem apoio de prefeitos e presença constante ao lado de Ratinho Junior. \n\n**E aí?**\n**A nova Paraná Pesquisas ainda mostra Moro como favorito inicial.**\nMas também começa a revelar algo importante: Sandro Alex deixou de ser apenas um nome secundário.\nAgora, começa a ser observado como candidatura em movimento.\nE o dado dos 71,5% de indefinição eleitoral mostra que a eleição ainda não entrou plenamente na casa do eleitor paranaense.\nPorque, na política, quando a maioria ainda não decidiu emocionalmente seu voto, o cenário continua aberto — mesmo quando existe um favorito.\n\n\n\n---\n###### #### Para a realização desta pesquisa, registrada no Tribunal Superior Eleitoral sob o n.º PR-00323/2026, foi utilizada uma amostra de 1500 eleitores em 57 municípios. Tal amostra representativa do Estado do Paraná atinge um grau de confiança de 95,0% para uma margem estimada de erro de aproximadamente 2,6 pontos percentuais para os resultados gerais. ',NULL,'/api/media/materia/829d6a83-c156-4cd3-8443-46041e62cc70/imagens/1778504798550-eleitor_indeciso.png',NULL,0,'published','2026-05-14 15:23:05.217','2026-05-11 12:50:59.520','2026-06-06 05:50:18.269','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,14,NULL),
('83ef2b59-98c5-4d23-9d4c-f28a6e7164f8','IPVA 2026: última parcela começa a vencer nesta semana','ipva-2026-ultima-parcela-comeca-a-vencer-nesta-semana-6on9d','Termina entre os dias 11 e 15 de maio o prazo para o pagamento da quinta e última parcela do imposto, a depender do final da placa.','Os mais de 1,16 milhão contribuintes que ainda estão com cotas do Imposto sobre a Propriedade de Veículos Automotores (IPVA) 2026 em aberto terão até esta semana para quitar o tributo. Termina entre hoje, dia 11 e 15 de maio, o prazo para o pagamento da quinta e última parcela do imposto, a depender do final da placa.\n\nDe acordo com balanço da Receita Estadual do Paraná, até o último dia 4 de maio o IPVA 2026 arrecadou cerca de R$ 3,4 bilhões — número que representa 73,5% dos R$ 4,53 bilhões lançados para o atual exercício. \n\nA novidade para este ano foi justamente a redução da alíquota de 3,5% do valor venal dos veículos para 1,9%. A redução de cerca de 45% deixou o imposto mais barato, trouxe alívio para o bolso dos paranaenses e fez muita gente quitar o IPVA o quanto antes. Ao todo, 2,05 milhões de veículos já estão com o tributo inteiramente pago — ou seja, metade da frota tributada (4,1 milhões).\n\nA inadimplência pode trazer consequências, já que o débito pode ser inscrito na Dívida Ativa, com inclusão do nome do proprietário no Cadin Estadual e o impedimento de usar de créditos do Nota Paraná, além de gerar restrições como nome negativado, dificuldade para obter empréstimos, acessar linhas de crédito e assumir cargos públicos. Quem deixa o IPVA em atraso também não consegue licenciar o veículo.\n\nO atraso também pesa no bolso. A multa é de 0,33% ao dia, acrescida de juros de mora com base na taxa Selic. Após 30 dias de inadimplência, a multa passa a ser fixa em 20% do valor do imposto.\n',NULL,'/api/media/materia/novo-1778498972966-uc4ff93uc/imagens/1778498974323-IPVA.jpg',NULL,0,'published','2026-05-11 11:32:28.952','2026-05-11 11:31:13.439','2026-05-14 11:53:18.474','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: José Fernando Ogura/Arquivo AEN',2,NULL),
('843ba1dc-d73f-4763-bd74-0929948f2d78','A educação no Paraná entrou na era da infraestrutura em larga escala','a-educacao-no-parana-entrou-na-era-da-infraestrutura-em-larga-escala-p06yt','O volume atual de investimentos mostra uma intenção clara de modernização estrutural da rede estadual. ','Durante muitos anos, falar em educação pública no Brasil significava quase sempre discutir: falta de estrutura, escolas deterioradas, obras paradas, improviso e manutenção precária. \nO Paraná constrói uma narrativa diferente.\nE o anúncio da entrega de 28 novas escolas, com outras 16 em construção e investimentos que ultrapassam R$ 2 bilhões, revela exatamente isso: o estado passou a tratar infraestrutura educacional como política estratégica de governo. \n\n**O governo decidiu investir pesado — e visivelmente.**\nHá um aspecto político importante nesse movimento: escolas são obras que permanecem. \n\n> Diferente de ações administrativas pouco perceptíveis, uma nova unidade escolar muda o bairro, a rotina da comunidade, a percepção da população e o ambiente educacional ao redor.\n \nO volume atual de investimentos mostra uma intenção clara de modernização estrutural da rede estadual. \n\n**O Paraná tenta romper com a lógica da manutenção mínima.**\nEsse é o ponto mais relevante. Historicamente, muitos estados administraram a educação apenas no limite da sobrevivência estrutural. Reformava-se o necessário, remendava-se o urgente e adiava-se o restante.\nO Paraná, visivelmente, segue outro caminho: novas unidades, ampliação de capacidade, modernização tecnológica e projetos estruturais de longo prazo. \n\n**A educação virou também símbolo de gestão.**\nExiste um componente político evidente nisso tudo.\nO governo Ratinho Junior tenta consolidar uma imagem baseada em obra, presença regional, infraestrutura e modernização administrativa. \nA educação se encaixa perfeitamente nessa narrativa.\n\n> Porque escola pública nova gera um efeito imediato e a população vê, utiliza\n> e associa diretamente ao governo.\n> \n\n**O modelo de expansão também revela ousadia administrativa.**\nOutro ponto importante é o uso de modelos como PPPs para novas escolas estaduais. O governo tenta separar gestão pedagógica da operação estrutural e manutenção. A proposta é controversa para alguns setores. Mas revela algo importante: o Paraná busca acelerar capacidade de expansão sem depender exclusivamente do modelo tradicional estatal.\n\n**A crítica positiva: infraestrutura não resolve tudo.**\nExiste, obviamente, um limite importante. Construir escolas modernas não resolve automaticamente a aprendizagem, o desempenho educacional, a valorização docente ou desigualdade educacional. \nE esse é o próximo desafio do estado: transformar infraestrutura forte em resultado pedagógico consistente. Porque educação não se sustenta apenas em concreto. Precisa produzir qualidade de ensino.\n\n**O impacto político é inevitável.**\nMesmo assim, o efeito político dessas entregas é evidente. As novas escolas reforçam uma percepção já consolidada no Paraná, de um governo permanentemente em movimento.\n\n> No último ano de mandato, Ratinho Junior não atua como quem administra encerramento de ciclo. Atua como quem ainda amplia presença administrativa no estado\n\nE isso fortalece diretamente a narrativa de continuidade construída ao redor de Sandro Alex.\n\n**E aí?**\nO Paraná parece viver uma das maiores modernizações físicas de sua rede educacional. E isso produz dois efeitos simultâneos: melhora estrutural concreta e fortalecimento político do grupo governista. \nA questão agora será outra: transformar investimento em aprendizagem de longo prazo.\n\n**Fato.**\nO Paraná deixou de tratar escola pública apenas como obrigação administrativa. Passou a tratá-la como símbolo de investimento estatal.\n***E, na política, quando um governo entrega escolas em larga escala,\nnão constrói apenas prédios. Constrói percepção de futuro.***\n',NULL,'/api/media/materia/novo-1778851549815-p56qy5ehn/imagens/1778851558005-Escola_nova_IA.png',NULL,0,'published','2026-05-15 14:10:47.097','2026-05-15 13:27:28.395','2026-06-01 08:58:31.579','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: montagem AEN',6,NULL),
('8a579264-ac2d-4196-b87e-3634b2dfaa0e','Alexandre Curi fortalece a base municipalista do grupo','alexandre-curi-fortalece-a-base-municipalista-do-grupo-ya8ie','Alexandre Curi possui uma das maiores redes políticas do interior do Paraná.','Outro personagem importante nas viagens do governador Ratinho Junior, pelo interior do Estado, é Alexandre Curi. \n\n> O presidente da Assembleia Legislativa e pré-candidato ao Senado vem participando ativamente das agendas do governador\n\n\nIsso reforça unidade política do grupo, aproximação com prefeitos e fortalecimento da base municipalista. \nAlexandre Curi possui uma das maiores redes políticas do interior do Paraná.\n\nSua presença nas viagens amplia articulação regional, fortalece alianças e ajuda a consolidar o projeto político liderado por Ratinho Junior. \n\n**A oposição enfrenta enorme dificuldade nesse ambiente.**\nEnquanto Ratinho Junior percorre o interior entregando obras, a oposição enfrenta dificuldade para competir nesse terreno.\n\nPorque notoriedade nacional não substitui presença regional, discurso ideológico não substitui investimento concreto e judicialização não substitui proximidade popular. \n\n> O governo conseguiu transformar administração em força eleitoral.\n\n**Fato.**\nRatinho Junior criou no Paraná um modelo político baseado em interiorização, presença regional, obras e proximidade com a população. \n\nNas pequenas cidades, o governador é recebido com carinho, multidões e reconhecimento popular.\nSandro Alex acompanha essas agendas e cresce politicamente ao se associar diretamente às entregas do governo.\nAlexandre Curi reforça a articulação municipalista e amplia a força regional do grupo.\nEnquanto parte da política nacional vive crises e polarização, Ratinho Junior percorre o interior inaugurando obras, ouvindo moradores e fortalecendo seu projeto político para 2026.\n',NULL,'/api/media/materia/novo-1779921450191-bcnrnhsvx/imagens/1779921450753-Alexandre_CURI_II.jpg',NULL,0,'published','2026-05-29 19:09:58.790','2026-05-27 22:38:28.707','2026-06-03 00:50:40.591','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ari Dias/AEN',7,NULL),
('8e21df2d-606c-45bd-8120-7ea3f11a90fc','Essa primeira semana de junho será de pressão para Moro e de consolidação para Sandro Alex no Paraná','essa-primeira-semana-de-junho-sera-de-pressao-para-moro-e-de-consolidacao-para-sandro-alex-no-parana-34bcn','O cenário eleitoral do Paraná entrou em uma nova fase, com Sergio Moro que continua líder, pelo menos nas pesquisas e Sandro Alex que deixou de ser apenas coadjuvante','A semana será de pressão para Moro e de consolidação para Sandro Alex no Paraná\nA semana tende a aprofundar ainda mais o movimento político que começou a aparecer nas últimas pesquisas.\nO cenário eleitoral do Paraná entrou em uma nova fase, com Sergio Moro que continua líder, pelo menos nas pesquisas e Sandro Alex que deixou de ser apenas coadjuvante e passou a ocupar o centro da disputa.\n\n> As pesquisas mais recentes mostraram algo que alterou completamente os bastidores políticos: Sandro Alex cresce quando associado a Ratinho Junior, a distância para Moro diminui em cenários de segundo turno e o PSD passa a enxergar uma disputa efetivamente competitiva.\n \n**Sandro Alex entra na semana em clima de crescimento.**\nO grupo de Ratinho Junior chega fortalecido e o motivo é simples: a transferência política começa a aparecer nos números.\n\n> A pesquisa IRG mostrou que Sandro Alex praticamente dobra seu desempenho quando aparece ligado ao governador Ratinho Junior, chegando a 26,2% das intenções de voto.\n \nIsso produz um efeito imediato, com prefeitos mais confiantes, lideranças regionais se aproximam e a estrutura política do PSD que ganha entusiasmo. \nNa política, crescimento gera crescimento. Quando uma candidatura começa a demonstrar viabilidade eleitoral, o entorno político se movimenta rapidamente.\n\n**Ratinho Junior deve intensificar ainda mais as agendas.**\nA tendência é que a semana seja marcada por novas viagens ao interior, entregas de obras, encontros regionais (tem reunião do PSD em Pinhais, nesta terça-feira (02)) e agendas conjuntas entre Ratinho Junior e Sandro Alex. \n\n> O governo percebeu que a principal força da pré-campanha está justamente na associação entre aprovação administrativa e continuidade política.\n\nPor isso, o interior continuará sendo prioridade. Ratinho Junior construiu sua maior força eleitoral fora da capital e Sandro Alex cresce exatamente nesse ambiente. \n\n**Moro entra na semana sob pressão inédita.**\nSergio Moro ainda lidera as pesquisas, mas o foco político mudou.\nAté pouco tempo atrás, o debate era quanto Moro venceria. Agora a pergunta começa a ser: Sandro Alex conseguirá encostar?\nEssa mudança altera completamente a dinâmica da pré-campanha. Moro passa a ter que administrar simultaneamente a liderança nas pesquisas, o crescimento do adversário e os reflexos do ambiente nacional do PL. \n\n**O desgaste nacional continua sendo problema para o campo de Moro.**\nOutro fator importante para esta semana é o debate nacional que não desapareceu. O campo político ligado a Flávio Bolsonaro continua convivendo com repercussões envolvendo empresários, banqueiros e financiadores próximos ao universo bolsonarista.\nIsso não destrói a força eleitoral de Moro, mas cria desgaste narrativo.\nEspecialmente porque Ratinho Junior mantém posição oposta e evita conflitos nacionais, concentra discurso em gestão e mantém foco em obras e investimentos. \n\n> Enquanto Moro aparece associado ao debate nacional do PL (leia-se, Vorcaro), Sandro Alex aparece associado ao governo estadual. \n\n**Sandro Alex deve explorar cada vez mais a imagem de continuidade.**\nOutro movimento esperado para os próximos dias é o reforço da narrativa de continuidade.\nO PSD percebeu que esse discurso funciona e Sandro Alex tende a aparecer cada vez mais como sucessor político de Ratinho Junior, como o nome ligado à infraestrutura, o responsável por parte das grandes obras do estado e representante da continuidade administrativa. \nEsse é hoje o principal eixo estratégico da pré-campanha governista.\n\n**Moro deve endurecer o enfrentamento político.**\nDo lado do PL, a tendência é aumentar o tom dos ataques.\nIsso já começou a aparecer, nos discursos, nas ações judiciais, nas críticas às agendas do governo e na tentativa de limitar a associação entre Ratinho Junior e Sandro Alex. \nO PL percebe que a imagem conjunta dos dois começa a produzir resultado eleitoral. Por isso, a disputa tende a ficar mais agressiva politicamente.\n\n**Alexandre Curi também ganha protagonismo.**\nOutro nome que deve aparecer com frequência nesta semana é Alexandre Curi. O presidente da Assembleia Legislativa acompanha todas as agendas do governador e fortalece a construção política do grupo para o Senado.\n\n> A estratégia é clara: apresentar unidade do bloco liderado por Ratinho Junior.\n\nEnquanto o PL concentra esforços na candidatura de Moro, o PSD mostra união do grupo político, estrutura, prefeitos, interior e projeto de continuidade. \n\n**O que observar nos próximos dias.**\nA semana deve girar em torno de quatro fatores:\n**Para Sandro Alex.**\n•	consolidação do crescimento nas pesquisas; \n•	fortalecimento no interior; \n•	ampliação da associação com Ratinho Junior; \n•	e atração de novas lideranças. \n**Para Sergio Moro.**\n•	manutenção da liderança; \n•	resposta ao crescimento de Sandro; \n•	contenção do desgaste nacional do PL; \n•	e reforço do eleitorado conservador. \n**Para Ratinho Junior.**\n•	intensificação das agendas; \n•	fortalecimento do sucessor; \n•	e manutenção da alta aprovação. \n**Para a oposição**\n•	aumento dos ataques; \n•	judicialização; \n•	e tentativa de impedir que a eleição se transforme em plebiscito do governo. \n\n**E aí?**\nA próxima semana será uma das mais importantes da pré-campanha até agora.\nSergio Moro segue como líder nas pesquisas, mas entra pressionado pelo crescimento de Sandro Alex.\n\nEnquanto isso, Ratinho Junior percorre o interior e arrasta multidões, entrega obras, fortalece alianças e acelera a transferência política para seu candidato.\n**Está muito claro que, a eleição do Paraná deixou de ser apenas uma disputa de notoriedade e começa a virar uma disputa entre força regional, gestão aprovada, continuidade política e capacidade de mobilização do interior do estado.** \n',NULL,'/api/media/materia/novo-1780327872839-h6cc719pe/imagens/1780327876277-Ratinho_Sandro_e_Moro_preocupado.png',NULL,0,'published','2026-06-01 15:32:30.556','2026-06-01 15:31:52.782','2026-06-05 20:47:56.765','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',11,NULL),
('8e60a68c-95d5-4076-86de-c1a451a00d3c','Inauguração da Ponte de Guaratuba: veja como vai funcionar o evento e os melhores lugares para assistir','inauguracao-da-ponte-de-guaratuba-veja-como-vai-funcionar-o-evento-e-os-melhores-lugares-para-assistir-cqmya','Show de drones e fogos marca a entrega da ponte para a população. A transmissão oficial acontecerá na TV Paraná Turismo e nas redes sociais do Governo do Paraná.','A inauguração da Ponte de Guaratuba será no dia 29 de abril (quarta-feira) com uma grande festa voltada para a população do Litoral. O evento vai contar com dois momentos: uma cerimônia com autoridades e responsáveis pela construção, a partir das 16h, e um show de luzes, drone e fogos de artifício para o público já mais perto do anoitecer, depois das 19h. A transmissão oficial acontecerá na TV Paraná Turismo e nas redes sociais do Governo do Paraná.\n\nA cerimônia oficial de inauguração vai ocorrer na cabeceira da ponte do lado de Guaratuba. Logo após a cerimônia, o governador Carlos Massa Ratinho Junior e o vice-governador Darci Piana vão hastear a bandeira do Paraná perto da parte estaiada e em seguida haverá um grande show de drones, fogos de artifício e luzes.\n\nA população poderá continuar circulando pela estrutura até as 22h, quando ela será fechada para desmobilização da estrutura. As forças de segurança vão orientar a movimentação.\n\nO ferry boat vai funcionar durante todo o dia 29 de abril e estará à disposição da população também no dia 30 de abril, mesmo após a liberação do tráfego de veículos. A liberação para os veículos vai acontecer no dia 30 de abril, logo no começo da manhã, marcando o início definitivo da ligação que foi aguardada por décadas pela população do Paraná. \n\nAo longo dos finais de semana de maio também vão ocorrer outros eventos festivos envolvendo a Ponte de Guaratuba.\n\nInformações importantes:\n\n- O acesso da população à Ponte de Guaratuba vai acontecer apenas após o show de fogos e drones. Antes disso haverão bloqueios nas proximidades das cabeceiras.\n\n- Os locais mais indicados para a visualização dos shows são Caieiras e Prainha, que terão telões e arquibancadas.\n\n- O ferry boat continuará funcionando durante todo o período, mantendo o deslocamento entre os municípios.',NULL,'/api/media/materia/novo-1777165198002-c41ixp72c/imagens/1777165198876-ponte..jpg',NULL,0,'published','2026-04-26 20:01:35.558','2026-04-26 01:02:23.234','2026-05-27 00:33:10.871','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: AEN',18,NULL),
('8f281d38-d1e0-4c4a-9883-2365d6e63354','Ratinho Junior: a força silenciosa que chega a 2026 — e o teste definitivo do poder','ratinho-junior-a-forca-silenciosa-que-chega-a-2026-e-o-teste-definitivo-do-poder-pnuiu','Ratinho Junior já venceu o teste da gestão. Agora enfrenta outro — mais difícil: o teste da sucessão.','A política brasileira costuma ser ruidosa.\nMas, no Paraná, a principal liderança dos últimos anos se consolidou de outra forma.\nRatinho Junior chega a 2026 não apenas como um governador bem avaliado.\nChega como um dos políticos mais fortes do país.\nE essa força tem base concreta.\n\n**1. Os números que sustentam o poder**\nAs pesquisas mais recentes não deixam margem para dúvida.\nO governo Ratinho Junior registra índices de aprovação que raramente aparecem em final de mandato:\n•	cerca de 80% de aprovação na pesquisa Quaest (abril/2026) \n•	83,8% de aprovação segundo o Paraná Pesquisas \n•	chegando a 88,2% em outros levantamentos. \n\n> Além disso, mais de 70% dos eleitores avaliam o governo como positivo. \n> Não é aprovação pontual.\n> É consistência ao longo do tempo.\n> E, na política, consistência gera algo mais importante que popularidade:\n> gera autoridade.\n\n**2. A força política que ultrapassa o governo**\nA pesquisa Quaest traz um dado ainda mais relevante:\ncerca de 64% dos eleitores acreditam que Ratinho Junior merece eleger o sucessor. \nEsse número traduz algo raro:\nnão apenas aprovação administrativa —\nmas legitimidade política.\nÉ a transição de um governo bem avaliado,\npara um governo com capacidade de continuidade.\n\n**3. A construção dessa força**\nEssa posição não surgiu por acaso.\nEla foi construída sobre três pilares claros:\n- **gestão orientada à entrega:**\nInfraestrutura, concessões, obras estruturantes e investimentos privados se tornaram a marca do governo.\n- **administração pragmática:**:\nFoco em resultado, redução de conflitos e previsibilidade institucional.\n- **distanciamento do conflito ideológico:**\nEnquanto o país se polarizou, Ratinho Junior escolheu outro caminho:\ngovernar sem transformar a política em confronto permanente.\nEssa escolha ampliou sua base e reduziu rejeição.\n\n**4. O paradoxo de 2026**\nMas há um dado que tensiona esse cenário.\nApesar da aprovação elevada, a pesquisa Quaest mostra que\no candidato apoiado pelo governador ainda não herdou essa força.\nIsso revela um ponto central:\naprovação não se transfere automaticamente.\nEla precisa ser construída politicamente.\n\n**5. O verdadeiro teste de poder**\nÉ aqui que a eleição de 2026 ganha sentido.\nRatinho Junior já venceu o teste da gestão.\nAgora enfrenta outro — mais difícil:\no teste da sucessão.\nPorque, na política, existem dois níveis de liderança:\n•	quem governa bem \n•	e quem consegue fazer seu projeto continuar. \nE nem sempre eles coincidem.\n\n**6. O legado**\nIndependentemente do resultado eleitoral, há um conjunto claro de marcas deixadas:\n•	investimentos estruturantes \n•	ambiente econômico estável \n•	gestão com alto índice de aprovação \n•	modelo administrativo menos ideológico e mais operacional.\nMas o legado não é apenas material.\nÉ também de método: \n\n- Governar com menos ruído - e mais execução.\n\n\n**E ai?**\nRatinho Junior chega ao fim do mandato com algo raro:\n•	aprovação elevada \n•	baixa rejeição \n•	base política estruturada.\nE um ativo ainda mais importante:\nlegitimidade para influenciar a eleição.\nMas influência não é garantia.\nÉ potencial.\n\n**Fato**\nRatinho Junior construiu um governo forte.\nAgora precisa provar que essa força\nnão termina nele.\nPorque, na política,\no verdadeiro legado não é governar bem.\nÉ conseguir continuar governando —\nmesmo quando já não se está no cargo.\n',NULL,'/api/media/materia/novo-1777572760624-l4n9rzvt2/imagens/1777572765586-gabinete_II_Foto_Jonathan_Campos_AEN.jpg',NULL,0,'published','2026-04-30 18:28:48.418','2026-04-30 18:16:14.387','2026-05-06 17:37:46.817','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos/Secom',22,NULL),
('8fb412b4-15bb-43d3-be18-d194086a8827','Sandro Alex X Moro em Curitiba: onde a eleição pode mudar de direção','sandro-alex-x-moro-em-curitiba-onde-a-eleicao-pode-mudar-de-direcao-ah4bl','A eleição estadual passa por todo o Paraná. Mas pode ser definida em Curitiba. E é na capital que o contraste entre Sandro Alex e Sérgio Moro se torna mais claro — e mais decisivo.','**1. Ponto de partida desigual**\nEm Curitiba, Moro entra com uma vantagem evidente:\n*Alto nível de reconhecimento.\n*Identificação consolidada com parte do eleitorado urbano.\n*Presença nacional já convertida em voto inicial.\n\nSandro Alex entra em outra condição:\n*Ainda precisa se tornar conhecido\n*Ainda precisa construir identidade política na capital.\nÉ uma largada desigual.\n\n**2. O tipo de eleitor que define Curitiba**\nA capital tem um perfil específico:\n\n> •	eleitor mais informado \n> •	mais volátil \n> •	menos dependente de estruturas tradicionais.\n\n*Decide mais tarde.*\n*Muda mais facilmente.*\nIsso cria um ambiente diferente do interior.\nEm Curitiba, reconhecimento ajuda — mas não resolve.\n\n**3. A vantagem de Moro — e seu limite**\nA força de Moro está no que já está consolidado: Imagem - Discurso - Posicionamento político.\n\nMas essa força carrega um limite:\ndepende da manutenção da percepção atual.\n\n> Ele entra para defender posição.\n> E defender, em política, pode ser mais difícil do que crescer.\n\n**4. O caminho de Sandro Alex na capital**\nSandro Alex não disputa Curitiba hoje.\nEle disputa Curitiba ao longo do tempo.\nE entra com três ativos relevantes:\n•	associação com o governo de Ratinho Junio;r \n•	presença em obras e investimentos; \n•	apoio político estruturado, incluindo o prefeito Eduardo Pimentel.\nSua estratégia não é dominar de imediato. É ocupar espaço gradualmente.\n\n**5. O papel de Curitiba na virada**\nCuritiba tem uma característica decisiva:\nnão apenas reflete a eleição, mas pode alterá-la.\nUm crescimento consistente na capital:\n•	muda narrativa \n•	reduz distância \n•	amplia competitividade no estado. \nQuem cresce em Curitiba passa a existir no Paraná inteiro.\n\n**6. Onde o confronto se define**\nO confronto entre os dois não será direto no início.\nMas será inevitável: Moro precisa manter e Sandro Alex precisa crescer.\nE, nesse tipo de disputa, o fator decisivo é o tempo:\n•	quem sustenta posição \n•	quem acelera crescimento. \n\n**E aí?**\nCuritiba não vai decidir sozinha a eleição.\nMas pode decidir quando ela muda.\nHoje, teoricamente, Moro é mais forte na capital.\nMas Sandro Alex ainda não chegou lá.\nE essa diferença importa.\nPorque, em eleições abertas, o que ainda não aconteceu, \npode pesar mais do que o que já está posto.\n\n**Fato**\nMoro já ocupa Curitiba.\nSandro Alex ainda precisa conquistá-la.\nE, na política, quem conquista no momento certo, \nmuda a eleição inteira.\nNo momento em que Ratinho Junior e Eduardo Pimentel entrarem pra valer no jogo, a realidade ganhará novos contornos. \n',NULL,'/api/media/materia/novo-1777983695890-crqe522nr/imagens/1777983696701-Sandro_X_Moro_confronto.png',NULL,0,'published','2026-05-05 13:16:24.444','2026-05-05 12:22:57.203','2026-06-06 08:39:48.437','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Montagem ',9,NULL),
('97e20214-3495-42ad-9f1e-8db152f0f03f','Entre o discurso e o movimento','entre-o-discurso-e-o-movimento-3v9it','A versão oficial é de normalidade. O discurso público insiste em estabilidade, alinhamento institucional e compromisso com agendas que, ao menos no papel, seguem previsíveis','O discurso público insiste em estabilidade, alinhamento institucional e compromisso com agendas que, ao menos no papel, seguem previsíveis. Mas, como quase sempre na política, o que se diz em público não revela completamente o que se constrói nos bastidores.\n\nNo Paraná, assim como no Brasil, o cenário recente tem sido marcado por uma movimentação silenciosa — daquelas que não aparecem em coletivas, nem em notas oficiais, mas que se manifestam em agendas paralelas, encontros reservados e mudanças sutis de posicionamento. Nada disso é, por si só, incomum.\n\n> A política se organiza justamente nesse espaço: entre o que é anunciado e o que é articulado. O ponto de atenção está no descompasso.\n\nEnquanto o discurso projeta continuidade, os sinais indicam reorganização. \n\nLideranças que até então orbitavam o mesmo campo começam a recalibrar suas posições. Interlocutores mudam, prioridades são revistas, e alianças — ainda que não rompidas — passam a operar sob novas condições.\n\nEsse tipo de movimento raramente é explicado de forma direta. Em vez disso, ele aparece diluído em expressões genéricas:\n“ajustes”, “diálogo permanente”, “reavaliação de cenário”.\n\nTermos que, na prática, funcionam mais como proteção narrativa do que como explicação.\n\nE é justamente aí que o contexto local encontra o nacional. O que se observa no Paraná não está isolado. Há uma sintonia com o ambiente político mais amplo, em que a antecipação de cenários futuros começa a influenciar decisões presentes. \n\nA política, afinal, raramente reage apenas ao agora — ela se antecipa ao que pode vir.\nNesse processo, o discurso cumpre um papel central.\n\nNão apenas como instrumento de comunicação, mas como ferramenta de construção de realidade. Ao afirmar estabilidade, busca-se produzi-la. Ao evitar conflitos, tenta-se contê-los antes que se tornem visíveis. Mas o discurso tem limites.\nEle organiza a percepção, mas não elimina a dinâmica real do poder — que segue em movimento, ainda que de forma discreta.\n\nNo fim, o que se vê é um cenário duplo.\nDe um lado, a narrativa pública de equilíbrio. De outro, a reorganização silenciosa que antecipa novos arranjos.\nE como quase sempre na política, entender o que está acontecendo passa menos pelo que é dito — e mais pelo que, cuidadosamente, não é.\n',NULL,'/api/media/materia/novo-1777162907290-2v2z22gp1/imagens/1777162908115-falando-a-plateia.jpg',NULL,0,'published','2026-04-27 14:12:44.978','2026-04-26 00:22:13.739','2026-05-07 03:26:09.441','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',13,NULL),
('a0517a82-14dd-48be-8c63-d635b3bb6336','Com aumento de 66% em 7 anos, PIB per capita do Paraná chega a R$ 64,3 mil em 2025','com-aumento-de-66percent-em-7-anos-pib-per-capita-do-parana-chega-a-rdollar-643-mil-em-2025-39f2v','O montante é 7,8% superior ao resultado nacional, cujo PIB per capita foi de R$ 59.687,49, e representa um aumento nominal de 65,97% em relação a 2018','A melhoria na economia e o crescimento de 2,8% do Produto Interno Bruto (PIB) do Paraná em 2025 impactou também no avanço do PIB per capita do Estado, que atingiu o valor de R$ 64.350,94 ano passado. O montante é 7,8% superior ao resultado nacional, de R$ 59.687,49, e representa um aumento nominal de 65,97% em relação a 2018, quando o PIB per capita paranaense chegou a R$ 38.772,74.\n\nO cálculo feito pelo Instituto Paranaense de Desenvolvimento Econômico e Social (Ipardes) e considera o PIB de R$ 765,17 bilhões de 2025, dividido por uma população de 11,89 milhões de pessoas, conforme as projeções do Instituto Brasileiro de Geografia e Estatística (IBGE).\n\n> “O Paraná se tornou a quarta maior economia do País, com avanço em todos os setores da economia e sem deixar de lado a parte social”\n\nafirmou o governador Carlos Massa Ratinho Junior. “Vamos entregar o governo praticamente dobrando o PIB paranaense desde quando assumimos o Estado. O avanço na economia reflete diretamente na qualidade de vida dos paranaenses, porque também representa mais investimentos e ampliação dos empregos e movimenta todas as áreas”.\n\nO crescimento relevante em relação a 2018 refletiu a expansão de todas as atividades econômicas, tendo em vista que o PIB da agropecuária paranaense evoluiu nominalmente 116,25% no período, de R$ 36 bilhões em 2018 para R$ 79 bilhões em 2025. A indústria progrediu 96,81% (de R$ 94 bilhões para R$ 184 bilhões) e os serviços cresceram 63,54%, passando de R$ 253 bilhões para R$ 413 bilhões.\n\nO diretor-presidente do Ipardes, Jorge Callado, ressalta que a ampliação do PIB per capita do Estado é resultado da eficiência e da produtividade dos segmentos produtivos do Estado. “O nível de excelência do agronegócio local, a diversificação do setor industrial e o avanço de serviços tecnológicos mais que compensam a inexistência de determinadas atividades por questões naturais, como a extração de petróleo e minério de ferro, que favorece outras regiões do País”, explica.\n\n“A produção primária do Paraná cresce continuamente, com muito ganho de produtividade na agropecuária, a indústria agrega cada vez mais valor e os serviços avançam em inovação, com o apoio do Governo do Estado, que disponibiliza eficiente infraestrutura e elevado capital humano”, complementa Callado.\n',NULL,'/api/media/materia/novo-1778110237061-u5zrem7l1/imagens/1778110238048-PIB_PER_CAPTA.jpg',NULL,0,'published','2026-05-06 23:32:29.639','2026-05-06 23:32:29.657','2026-05-11 10:29:48.261','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Fonte: IPARDES/IBGE',3,NULL),
('a3ee154d-5e26-4ed3-b4a7-0900c566c967','A vantagem que não aparece nas pesquisas','a-vantagem-que-nao-aparece-nas-pesquisas-tme6u','Enquanto o debate público ainda se organiza em torno de números e projeções, a política real já começou a se mover. E, neste momento, ela se move com um sinal claro.','A reunião conduzida pelo governador Ratinho Junior, na Fazenda Ubatuba, ao lado de centenas de prefeitos e com a apresentação de Sandro Alex como candidato, \n\n> não foi apenas um ato político\n\n.\n\nFoi a demonstração de uma vantagem que não aparece nas pesquisas.\nOrganização antes da disputa\nHá candidaturas que começam pela exposição.\nOutras começam pela estrutura.\nO movimento do governo indica uma escolha consciente:\n\n**- organizar primeiro**\n\n**- disputar depois**\n\nAo reunir prefeitos — a base mais capilarizada da política estadual — o governo não apenas demonstra força.\nEle constrói caminho.\n\nPrefeitos não são apenas apoiadores.\nSão operadores políticos no território.\nSão eles que traduzem decisões em presença, presença em percepção e percepção em voto.\n\nA diferença entre intenção e operação\nPesquisas medem intenção.\nMas eleição se decide na operação.\nE é nesse ponto que o gesto político ganha relevância.\n\nEnquanto parte do debate se concentra em cenários ainda instáveis, o grupo governista avança em um terreno mais concreto:\n- alinhamento político\n- mobilização territorial\n- construção de rede.\n\nEssa diferença raramente aparece no início da disputa.\nMas costuma pesar no final.\n\n**Continuidade como projeto — não como discurso**\n\nA apresentação de Sandro Alex nesse ambiente não foi simbólica.\nFoi estratégica.\nEla associa o candidato diretamente a um ciclo de gestão que o governo pretende preservar:\n•	obras estruturantes \n•	investimentos em infraestrutura \n•	presença administrativa no estado \n\nNão se trata apenas de defender continuidade, mas de demonstrar que ela já está organizada.\n\n**O que ainda não está no radar**\n\nHá um dado que passa despercebido no momento:\n\n> Quem organiza primeiro, reduz incerteza interna. \n> E, em eleições abertas, reduzir incerteza é ganhar tempo.\n\n- Tempo para estruturar campanha.\n- Tempo para consolidar alianças.\n- Tempo para transformar nome em escolha.\n\nEnquanto isso, quem ainda opera no campo da expectativa precisa, simultaneamente:\n•	se afirmar \n•	se expandir \n•	e se defender \n\n**E aí?**\n\nA eleição no Paraná ainda não começou para o eleitor.\nMas já começou para quem disputa.\nE, neste momento, a diferença não está nos números.\nEstá na capacidade de organização.\nA reunião na Fazenda Ubatuba não define o resultado.\nMas define algo essencial:\nQuem entrou na disputa com o jogo já estruturado.\n\nE, na política, começar organizado não garante vitória mas, quase sempre, evita derrota precoce.\n',NULL,'/api/media/materia/novo-1777300009525-elfxnbe1z/imagens/1777300009723-Ratinhoi-Sandroi-Curi-mãos-dadas.jpeg',NULL,0,'published','2026-04-27 23:46:32.819','2026-04-27 14:28:59.911','2026-05-09 10:37:56.963','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Rodrigo Felix Leal',8,NULL),
('a64a764e-a79d-4d8c-a267-6fb54f380d60','Os 3 erros que podem custar a eleição no Paraná','os-3-erros-que-podem-custar-a-eleicao-no-parana-anrg5','Três movimentos que têm potencial real de alterar o rumo da disputa','Eleições raramente são decididas apenas por acertos.\nNa maioria das vezes, o resultado é definido por erros — especialmente aqueles que não são percebidos a tempo.\nNo Paraná, três movimentos têm potencial real de alterar o rumo da disputa.\n\n**1. Confundir aprovação com transferência de voto**\nO governo chega forte.\nIsso é inegável.\nMas há uma diferença crítica:\naprovação não é transferência automática\nO eleitor pode reconhecer uma gestão eficiente e, ainda assim, optar por outro caminho.\nQuando campanhas tratam apoio político como garantia eleitoral, criam uma falsa zona de conforto.\nE eleições punem conforto.\n\n**2. Antecipar uma vitória que ainda não existe**\nLiderar no início é importante.\nMas pode ser perigoso.\nQuando uma candidatura passa a se comportar como favorita consolidada antes do tempo, ela:\n•	reduz intensidade de campanha \n•	evita enfrentamentos necessários \n•	subestima movimentos do adversário. \nLiderança precoce, mal administrada, vira fragilidade\nPorque transforma disputa em expectativa — e expectativa cobra.\n\n**3. Deixar o adversário definir o campo da eleição**\nEsse é o erro mais sutil — e mais decisivo.\nToda eleição tem um “tema dominante”:\n•	gestão \n•	mudança \n•	ideologia \n•	continuidade \nQuem define esse tema, ganha vantagem estrutural.\nSe um lado impõe o debate e o outro apenas reage, a eleição já começa desigual.\n👉 não é sobre responder melhor\n👉 é sobre decidir sobre o que se discute.\nE muitos perdem eleições sem perceber que já perderam esse controle.\n\n🔍 **E aí?**\nNo fim, eleições não são apenas disputas de força.\nSão disputas de leitura.\n\n> E quem erra na leitura, erra no movimento.\n> E quem erra no movimento, dificilmente recupera o tempo perdido.\n',NULL,'/api/media/materia/a64a764e-a79d-4d8c-a267-6fb54f380d60/imagens/1777158823071-Bandeira-do-Paraná.jpg',NULL,0,'published','2026-04-27 14:48:42.251','2026-04-25 23:06:10.119','2026-05-23 05:54:37.517','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,14,NULL),
('a73c0552-7f77-4955-8afe-0a6085b62716','Celebração de Corpus Christi e pelo centenário da Arquidiocese de Curitiba reúne autoridades','celebracao-de-corpus-christi-e-pelo-centenario-da-arquidiocese-de-curitiba-reune-autoridades-d8cpi','A celebração católica é considerada a maior do mundo em extensão e faz parte do calendário oficial de Curitiba e do calendário oficial turístico do Estado do Paraná.','Milhares de pessoas lotaram as ruas do centro de Curitiba nesta quinta-feira (04) para acompanhar a tradicional celebração de Corpus Christi. O evento também marcou o centenário da arquidiocese com o tema “100 anos anunciando a luz do evangelho”. O governador Carlos Massa Ratinho Junior participou das festividades ao lado de outras autoridades e lideranças religiosas.\n\nA celebração católica na capital paranaense é considerada a maior do mundo em extensão e faz parte do calendário oficial de Curitiba e do calendário oficial turístico do Estado do Paraná. O governador, que participou da Santa Missa conduzida por dom José Antônio Peruzzo, com participação do padre Reginaldo Manzotti, destacou a relevância do momento.\n\n\"Este dia tem muita representatividade para todos nós. É um dia de celebração da fé. E, Curitiba, hoje, é uma referência para o mundo na comemoração, reconhecida pela Igreja Católica como o maior Corpus Christi do Brasil e um dos maiores do mundo\", ressaltou o governador.\n\nO prefeito de Curitiba, Eduardo Pimentel, participou da celebração desde cedo. \"Pela manhã estive com a minha mulher e meus filhos na confecção dos tapetes, verdadeiras obras-primas. Neste ano, o evento tem um tempero especial, a comemoração dos 100 anos da Arquidiocese da nossa cidade. É bom ver a cidade vibrando, e é uma alegria poder participar desse momento de fé\".\n\n',NULL,'/api/media/materia/novo-1780608284581-0n2nrz9tf/imagens/1780608287142-Composi__o_prociss_o_II.png',NULL,0,'published','2026-06-04 21:25:50.879','2026-06-04 21:25:50.897','2026-06-06 00:48:42.928','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos',14,NULL),
('ae2164cd-053f-4c4c-88c2-475cf7d4b4a4','Um dos maiores do mundo: Corpus Christi da Capital do Paraná reunirá 130 mil pessoas','um-dos-maiores-do-mundo-corpus-christi-da-capital-do-parana-reunira-130-mil-pessoas-ps7ht','A edição de 2026 tem um significado especial por integrar as comemorações do centenário da Arquidiocese de Curitiba. ','O Paraná recebe neste dia 4 de junho a maior celebração de Corpus Christi do Brasil, com os tradicionais tapetes coloridos e ações de solidariedade. Realizado em Curitiba, a expectativa da organização é que o evento reúna mais de 130 mil pessoas ao longo de 10 horas de programação, entre missas, procissão e apresentações musicais. O governador Carlos Massa Ratinho Junior confirmou participação.\n\nA edição de 2026 tem um significado especial por integrar as comemorações do centenário da Arquidiocese de Curitiba. O tema do ano jubilar é “100 anos anunciando à luz do Evangelho”, enquanto o lema da celebração será “Um século partilhando o Pão que ilumina o mundo”.\n\nA celebração na capital paranaense tem reconhecimento internacional do Vaticano como uma das maiores celebrações de Corpus Christi do mundo. O evento já faz parte do calendário oficial da cidade através da Lei 15.219, de 22 de maio de 2018, bem como do calendário oficial turístico do Estado do Paraná, através da Lei 19.466, de 23 de abril de 2018.',NULL,'/api/media/materia/novo-1780427134458-r6rxdrwd7/imagens/1780427134973-Corpus_Christi.jpg',NULL,0,'published','2026-06-02 19:07:39.879','2026-06-02 19:07:39.899','2026-06-05 20:32:57.391','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos/AEN',6,NULL),
('ae92d8ad-661c-4021-a3f2-65f1638d361e','Diferentes níveis de experiência e escolaridade: Paraná tem 21 mil vagas de empregos','diferentes-niveis-de-experiencia-e-escolaridade-parana-tem-21-mil-vagas-de-empregos-yny22','A Regional de Cascavel concentra o maior volume de oportunidades do Estado, com 4.566 vagas. Na sequência aparece a Regional de Curitiba,','O Paraná inicia junho com 21.042 vagas de emprego com carteira assinada disponíveis nas Agências do Trabalhador em todas as regiões do Estado. As oportunidades abrangem diferentes níveis de escolaridade e experiência profissional e podem ser consultadas presencialmente nas unidades ou pelo site da Secretaria do Trabalho, Qualificação e Renda.\n\nA função com maior número de oportunidades é a de alimentador de linha de produção, com 6.019 vagas abertas. Na sequência aparecem as ocupações de abatedor (1.430 vagas), magarefe, posto destinado aos especialistas em cortes de carnes, com 1.007 vagas e operador de caixa (905).\n\nA Regional de Cascavel concentra o maior volume de oportunidades do Estado, com 4.566 vagas. Entre as principais funções oferecidas estão alimentador de linha de produção (1.412 vagas), abatedor (996), operador de caixa (168) e repositor de mercadorias (100).\n\nNa sequência aparece a Regional de Curitiba, com 4.122 vagas disponíveis. Os destaques são para alimentador de linha de produção (540), operador de caixa (319), auxiliar de logística (252) e repositor de mercadorias (234). Somente a Agência do Trabalhador de Curitiba reúne 812 oportunidades.\n\nA Regional de Campo Mourão soma 3.352 vagas, segue a tendência do Estado com a concentração das vagas principalmente para as funções de alimentador de linha de produção (1.033), magarefe (667) e abatedor (209). Já a Regional de Foz do Iguaçu conta com 2.517 oportunidades, principalmente para alimentador de linha de produção (1.093), abatedor (140), repositor de mercadorias (107) e operador de caixa (94).\n\nTambém existem oportunidades para as regionais de Pato Branco, com 2.129 vagas, Maringá, com 1.232, Londrina, com 1.164, e Umuarama, com 930 oportunidades abertas. As demais vagas estão distribuídas entre Guarapuava (438), Paranaguá (350), Ponta Grossa (193) e Jacarezinho (49).\n\n**VAGAS TÉCNICAS** - Além das vagas operacionais e do setor de serviços, as Agências do Trabalhador ofertam oportunidades para profissionais com formação técnica e superior. A primeira semana de junho começa com vagas principalmente para técnico de equipamentos elétricos, técnico eletromecânico, analista contábil, analista de marketing, supervisor de logística, supervisor de contabilidade e consultor técnico comercial.\n\nHá ainda vagas de estágio para estudantes de pedagogia, marketing, administração, psicologia, magistério e engenharia mecânica.\n\n**COMO SE CANDIDATAR** - Os interessados devem procurar a Agência do Trabalhador de seu município para orientação e encaminhamento às entrevistas. Também é possível consultar as vagas pela internet.',NULL,'/api/media/materia/novo-1780321005633-bt50fsjgz/imagens/1780321008669-EMPREGO_Ari_Dias_AEN.jpg',NULL,0,'published','2026-06-01 13:38:26.141','2026-06-01 13:38:26.165','2026-06-01 19:59:56.396','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ari Dias/AEN',4,NULL),
('b21262b9-c1f4-42c8-ab64-e8ac45d42627','Número de emplacamentos cresce 38% no 1º quadrimestre no Paraná, após redução de IPVA','numero-de-emplacamentos-cresce-38percent-no-1o-quadrimestre-no-parana-apos-reducao-de-ipva-6p9l1','Foram 229.400 registros no 1º quadrimestre de 2026, contra 165.659 no ano passado','A redução da alíquota do Imposto sobre a Propriedade de Veículos Automotores (IPVA) segue refletindo no número de registros e emplacamentos no Paraná. De janeiro a abril deste ano, o crescimento foi de 38,5% na comparação com o mesmo período de 2025. Foram 229.400 registros no 1º quadrimestre de 2026, contra 165.659 no ano passado, segundo dados do Departamento de Trânsito do Paraná (Detran/PR).\n\nDos quatro meses analisados, a alta mais expressiva ocorreu no mês de março, com 54%, quando 67.556 veículos foram registrados no Paraná, 23.671 a mais que no mesmo mês de 2025, com 43.885. Foram 44.302 novos veículos (primeiro emplacamento) e 23.254 registros de outro estado (quando o proprietário transfere o “domicílio” do automóvel). É como se 2.179 veículos por dia recebessem “placas paranaenses” registrados junto ao Detran.\n\nNa sequência, abril teve 66.314 veículos emplacados – 45.517 primeiros emplacamentos e 20.797 registros de outro estado –, 35% a mais que os 48.945 dos quatro primeiros meses de 2025. Fevereiro teve alta de 31%, de 40.148 para 52.841, e janeiro teve 30% de veículos a mais registrados entre os períodos – de 32.681 no ano passado para 42.689 em 2026.\n\n\"Esse é um movimento que aguardávamos desde o anúncio da nova legislação tributária. Estamos gerando negócios, estimulando a economia e deixando dinheiro nas mãos das pessoas para reinvestimentos. \n\n> Esse salto nos emplacamentos é uma mostra de mercado aquecido, o que ajuda a economia do Paraná a continuar em grande ritmo de crescimento\", afirma o secretário da Fazenda, Norberto Ortigara.',NULL,'/api/media/materia/novo-1778499676643-5ulllssrp/imagens/1778499678183-EMPLACAMENTOS_PR.jpg',NULL,0,'published','2026-05-11 11:41:45.914','2026-05-11 11:41:45.923','2026-05-14 12:08:21.586','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Detran/PR',2,NULL),
('b3b4873b-1686-4490-a638-6dfb5701d814','A eleição que parece decidida — mas ainda não começou','a-eleicao-que-parece-decidida-mas-ainda-nao-comecou-57vwp','Cerca de 70% do eleitorado ainda não decidiu em quem votar.','As pesquisas dizem que Sérgio Moro lidera com folga a disputa pelo governo do Paraná, chegando a mais de 50% das intenções de voto em alguns cenários. \nMas há um dado que desmonta essa aparente vantagem:\nCerca de 70% do eleitorado ainda não decidiu em quem votar.\n\nE isso muda tudo.\nPorque uma eleição com esse nível de indefinição não está consolidada — está aberta.\nO que se vê hoje é um cenário que parece estável, mas não é.\n\n> Moro lidera.\n> Mas lidera em um ambiente ainda em formação.\n\nDo outro lado, o candidato apoiado por Ratinho Junior entra na disputa com outro tipo de ativo:\nGestão, estrutura e capacidade de crescimento.\n\nA eleição, portanto, não está onde parece.\nEla não está nos números atuais.\nEstá no que ainda não apareceu.\nPorque, quando a maioria do eleitorado não decidiu, a vantagem deixa de ser garantia e passa a ser apenas ponto de partida.\n\nA pergunta não é quem está na frente hoje.\nÉ quem será escolhido quando o eleitor finalmente decidir.\nE esse momento ainda não chegou.\n',NULL,'/api/media/materia/b3b4873b-1686-4490-a638-6dfb5701d814/imagens/1777398926182-TRE.png',NULL,0,'published','2026-04-30 12:47:43.687','2026-04-28 17:54:24.479','2026-06-04 05:58:18.109','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','71ebd93b-cb43-4e7f-b8eb-5a50515633e3','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,9,NULL),
('b76d431d-9050-4234-820d-7a5e7f87c30e','Moro quer briga! O PL tenta impedir Sandro Alex de aparecer ao lado de Ratinho Junior, o que revela medo político.','moro-quer-briga-o-pl-tenta-impedir-sandro-alex-de-aparecer-ao-lado-de-ratinho-junior-o-que-revela-medo-politico-tkhgk','O que realmente incomoda a oposição é a força política da associação entre Ratinho Junior e Sandro Alex','A ação apresentada pelo PL de Sergio Moro e pelo Novo no TRE do Paraná diz mais sobre o cenário eleitoral do que sobre a própria legislação eleitoral.\nNo fundo, o que está em discussão não é apenas propaganda institucional, atos de governo ou presença em eventos oficiais. \nO que realmente incomoda a oposição é a força política da associação entre Ratinho Junior e Sandro Alex, que cresce a cada pesquisa e tende a crescer mais nos próximos dias.\n\n**A ação tenta criminalizar a sucessão política natural.**\nHistoricamente, governadores sempre constroem sucessores. Isso acontece no Paraná, em São Paulo, Minas Gerais, Bahia, Pernambuco e praticamente em todos os estados. \nÉ absolutamente natural que um governador apresente ao eleitor o grupo político que pretende manter no poder, principalmente, quando o governante que está para sair, tem aprovação elevada, obras espalhadas pelo estado e capital político acumulado. \n\n> O problema para o PL parece ser justamente esse: Ratinho Junior possui hoje uma das maiores aprovações do Brasil e Sandro Alex aparece cada vez mais ligado a infraestrutura, entregas, obras e interiorização do governo\n\n\n\n**A fragilidade jurídica da tese.**\nA Justiça Eleitoral negou o pedido do PL e do Novo e isso produz um efeito político importante.\nO TRE sinaliza que a presença institucional, por si só, não configura automaticamente irregularidade eleitoral. Aliás, se fosse assim, prefeitos não poderiam aparecer com secretários, governadores não poderiam apresentar aliados e praticamente toda sucessão política seria proibida. \n\n**Sandro cresce com Ratinho.**\nTalvez esse seja o verdadeiro ponto central, o maior problema do PL. Durante muito tempo, a oposição apostou que Sergio Moro venceria apenas pela notoriedade.\nMas os bastidores mostram uma crescente preocupação com a transferência de capital político de Ratinho Junior, o peso do interior, a máquina municipalista e o avanço gradual e consistente de Sandro Alex. \n\nA ação judicial revela exatamente essa dificuldade de enfrentar politicamente a exposição conjunta entre governador e sucessor. ***O tapetão, dessa vez, não funcionou e expôs o medo e a vontade de brigar.***\n\n**A contradição do PL**\né o aspecto mais curioso da situação. O próprio bolsonarismo sempre utilizou intensamente imagem política, atos públicos, motociatas, eventos oficiais e associação direta entre líderes e candidatos. \nAgora, no Paraná, o PL parece defender que o governador não possa sequer aparecer ao lado do pré-candidato apoiado por ele. Politicamente, isso soa menos como defesa da legalidade e mais como tentativa de limitar artificialmente a força do adversário. Uma espécie de censura.\n\n**O isolamento político do PL no Paraná**\né um detalhe importante: o PL rompeu com o governo Ratinho Junior após a entrada de Sergio Moro no partido e desde então perdeu espaço institucional, deixou a base aliada, endureceu discurso e passou a atuar como oposição permanente. \nO problema é que boa parte dos prefeitos e lideranças regionais continua próxima do governador.\n\n> Ou seja, o PL tenta judicializar aquilo que não conseguiu neutralizar politicamente e, mais do que isso, inaugura a briga que se desenha pela frente.\n\n Moro quer briga sim. Acabou aquela fala mansa de elogiar o governador e tentar até tirar proveito de obras entregues. Agora é briga. \n\n**Um líder político em atividade plena.**\nA irritação da oposição também decorre de outro fator: Ratinho Junior não age como governador em fim de mandato. Pelo contrário. Ele intensificou viagens, acelerou entregas, ampliou presença no interior, atua para fortalecer cada vez mais o PSD e passou a apresentar Sandro Alex em praticamente todos os encontros políticos. \n\n> Isso cria percepção de continuidade. E continuidade eleitoral assusta adversários.\n> Nisso, qual é o erro, o crime de Ratinho Junior? Nenhum! Como dito, qualquer governante bem avaliado tem o direito e deve lutar para eleger o sucessor.\n\n**A oposição (Moro) é contra as obras?**\nExiste ainda um efeito colateral perigoso para o PL.\nQuando tenta impedir divulgação de entregas, presença em inaugurações ou associação política com obras, a oposição corre o risco de transmitir ao eleitor o desconforto com o próprio sucesso administrativo do governo.\nE isso é delicado. Porque o eleitor do interior normalmente valoriza estrada pronta, investimento liberado, hospital entregue, escola inaugurada e presença física do governo. \n\n**E aí?**\nA ação do PL no TRE revela muito mais sobre o momento eleitoral do Paraná do que sobre direito eleitoral. Ela mostra preocupação crescente com o avanço político de Sandro Alex, reconhecimento da força de Ratinho Junior, e dificuldade da oposição em conter a associação entre governo aprovado e sucessão estadual. \n\n**Fato.**\nQuando a oposição tenta impedir que um governador apareça ao lado do próprio sucessor político, está admitindo uma coisa: a imagem conjunta funciona.\nO PL saiu da base do governo, perdeu espaço, mudou o discurso e agora tenta no TRE limitar aquilo que Ratinho Junior construiu politicamente no interior: presença, aprovação, obras e continuidade. \n***Porque, no fundo, o problema para o PL e Sergio Moro, não é Sandro Alex aparecer ao lado de Ratinho. O problema é o eleitor gostar da imagem. Moro quer briga sim.***\n',NULL,'/api/media/materia/novo-1779365637225-5n27qcm1k/imagens/1779365640795-com_raiva.png',NULL,0,'published','2026-05-21 12:25:38.666','2026-05-21 12:15:18.380','2026-06-02 13:37:39.798','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,16,NULL),
('ba35a419-790e-4ac9-b290-1cc84aece4b3','A queda de Flávio Bolsonaro nas pesquisas muda o ambiente político nacional e atinge o coração de Sergio Moro ','a-queda-de-flavio-bolsonaro-nas-pesquisas-muda-o-ambiente-politico-nacional-e-atinge-o-coracao-de-sergio-moro-psika','O impacto político foi imediato e os reflexos já começam a aparecer no Paraná.','A nova pesquisa nacional divulgada nesta semana consolidou um movimento político importante: Flávio Bolsonaro perde força eleitoral e sofre desgaste direto após os recentes episódios envolvendo empresários, banqueiros (Vorcaro) e financiadores ligados ao entorno bolsonarista.\nO impacto político foi imediato e os reflexos já começam a aparecer no Paraná.\nSergio Moro, embora tente manter discurso estadual, está profundamente ligado ao mesmo campo político do PL nacional.\n\n> Nesse contexto, fica claro que a eleição paranaense deixou de ser apenas regional. Passou a sofrer influência direta do desgaste do bolsonarismo em Brasília.\n\n**O bolsonarismo e o discurso anti-sistema.**\nEsse é o principal problema político do momento dos integrantes dessa linha politica que se diz da direita ou da extrema direita. Durante anos, o bolsonarismo sustentou discurso moral, combate ao sistema, crítica às elites; enfrentamento ao establishment financeiro e político. \nMas os recentes episódios envolvendo banqueiros, empresários, fundos, paraísos fiscais e articulações financeiras, atingiram justamente o coração dessa narrativa.\nA queda de Flávio Bolsonaro nas pesquisas mostra isso claramente, pois, parte do eleitorado conservador começou a demonstrar desconforto. E quando o núcleo principal sofre desgaste, os reflexos chegam automaticamente aos aliados estaduais.\n\n**Ratinho Junior aparece blindado do desgaste nacional.**\nEnquanto o ambiente do PL enfrenta turbulência, o habilidoso Ratinho Junior ocupa posição completamente diferente.\nO governador evita guerras ideológicas nacionais, mantém distância estratégica das crises de Brasília, não transforma o governo em palanque ideológico e sustenta discurso focado em gestão. \nIsso virou enorme ativo político. O eleitor do Paraná começa a fazer uma comparação muito clara: de um lado, conflitos nacionais e desgaste político e do outro, obras, investimentos e estabilidade administrativa. \nE Sandro Alex cresce exatamente dentro desse segundo ambiente.\n\n**Sandro Alex se fortalece.**\nAs pesquisas recentes mostraram um movimento objetivo, que mostra Sandro Alex crescendo de forma consistente.\nE esse crescimento ocorre justamente porque Ratinho Junior mantém alta aprovação, o governo continua entregando obras, o interior permanece mobilizado e Sandro aparece associado diretamente à gestão. \nO eleitor começa a enxergar continuidade administrativa.\nEnquanto o PL entra no debate nacional e nas turbulências políticas de Brasília, o grupo governista ocupa o espaço da estabilidade.\n\n**Moro enfrenta o peso da nacionalização da disputa.**\nSergio Moro continua forte eleitoralmente, mas a mudança no ambiente nacional produz desgaste inevitável.\nPorque Moro pertence ao PL, depende do eleitorado bolsonarista e se apoia fortemente no campo conservador nacional. O detalhe é que esse eleitorado começa a pensar, a raciocinar sobre os acontecimentos. \nEsse desgaste do núcleo bolsonarista começa a contaminar os aliados regionais.\nIsso ocorre especialmente quando o debate sai do campo ideológico e entra no campo moral e financeiro. \n\n**A queda de Flávio Bolsonaro não é apenas um detalhe estatístico.**\nEla representa enfraquecimento narrativo do bolsonarismo nacional.\nNo Paraná, a ordem é manter distância de Brasília e focar na gestão estadual\nOutro movimento importante é que o eleitor paranaense demonstra crescente interesse em estabilidade administrativa.\n\nIsso favorece diretamente Ratinho Junior, Sandro Alex e o grupo do PSD. \n\n> Porque o governo estadual, ao invés de usar os dois mandatos para discussões ideológicas e brigas com adversários, construiu imagem baseada em obras, infraestrutura, emprego, educação e presença regional. \n\nEnquanto o debate nacional mergulha em escândalos, confrontos e desgaste político, o Paraná observa quem entrega resultado concreto.\n\n**O PL entrou em posição defensiva.**\nO cenário político nacional também mudou o comportamento da oposição no Paraná.\nO PL começa a endurecer ataques, deve ampliar a judicialização e passa a tentar limitar politicamente o crescimento de Sandro Alex. \nIsso ficou evidente nas ações eleitorais, nas críticas às agendas do governo e na tentativa de impedir associação entre Ratinho Junior e seu pré-candidato. \nEsse movimento revela preocupação clara: o crescimento de Sandro Alex ameaça fortemente a liderança que até então era relativamente confortável para Moro.\n\n**Muito mais do que esquerda e direita.**\nA polarização atual deixou de ser apenas direita contra esquerda ou bolsonarismo contra petismo. \nAgora existe outro eixo gestão versus desgaste político nacional. E isso beneficia diretamente Ratinho Junior e Sandro Alex.\nPorque o governo estadual conseguiu construir aprovação, presença no interior e sensação concreta de eficiência. \n\n**O que a nova pesquisa realmente mostra.**\nA queda de Flávio Bolsonaro possui efeito político muito maior do que parece.\nEla mostra: desgaste do ambiente nacional do PL, perda de força da narrativa moral bolsonarista, fortalecimento do discurso administrativo de Ratinho Junior e crescimento consistente de Sandro Alex no Paraná.\nEnquanto Brasília vive turbulência política, Ratinho Junior aparece entregando obras, viajando pelo interior e fortalecendo seu sucessor.\n\n**E aí?**\nClaramente, o cenário nacional começou a mudar. E essa mudança chegou ao Paraná. A queda de Flávio Bolsonaro enfraquece o ambiente político do PL e produz desgaste indireto importante sobre Sergio Moro.\nAo mesmo tempo Ratinho Junior mantém alta aprovação, Sandro Alex cresce nas pesquisas e o grupo governista ocupa o espaço da estabilidade administrativa. \n***A eleição começa a deixar de ser disputa de notoriedade e passa a ser confronto entre gestão aprovada e desgaste político nacional.***\n',NULL,'/api/media/materia/novo-1779799765911-3qjr8lgfd/imagens/1779799797225-Sandro_x_Moro_soco.png',NULL,0,'published','2026-05-27 13:02:51.976','2026-05-26 12:50:17.451','2026-06-01 08:41:47.129','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8',NULL,10,NULL),
('bc36979e-7d41-4fd3-9a10-fb51e730c43f','O que ninguém está vendo na eleição do Paraná','o-que-ninguem-esta-vendo-na-eleicao-do-parana-fy3pt','A eleição de 2026 parece, à primeira vista, organizada.','\nHá nomes postos, pesquisas divulgadas, outras que serão divulgadas já nos próximos dias, movimentos visíveis.\nMas o que realmente define o resultado ainda não está completamente exposto.\nE é justamente isso que passa despercebido.\n\n**1. A eleição ainda não tem identidade**\nHoje, o Paraná vive uma indefinição silenciosa:\nEssa é uma eleição local — ou nacional?\nEnquanto essa resposta não se consolida, o cenário permanece instável.\nPorque candidatos estão jogando jogos diferentes:\n\n•	um tenta estadualizar \n\n•	outro tende a nacionalizar\n \nE o eleitor ainda não decidiu qual jogo quer jogar\n\n**2. O voto ainda não é emocional**\nEm muitas eleições, o voto se define cedo por identificação.\nAqui, isso ainda não aconteceu.\nO eleitor observa mais do que se posiciona.\nIsso gera um efeito importante: *o voto ainda é racional — e, portanto, volátil*.\nE votos voláteis mudam rápido quando o ambiente muda.\n\n**3. A eleição será decidida tarde**\nEsse talvez seja o ponto mais ignorado.\nTudo indica que o eleitor paranaense vai decidir seu voto mais próximo da eleição.\nNão agora.\nNão nas primeiras pesquisas, mas no momento em que o cenário estiver completamente formado.\nIsso muda completamente a dinâmica da campanha.\n\n> Quem cresce cedo pode não sustentar.\n> Quem aparece depois pode surpreender\n\n.\n\n**4. O excesso de análise pode estar distorcendo o cenário**\nHá um volume grande de leitura política sendo feito agora.\nMas parte dessas análises parte de premissas ainda instáveis.\nAnalisa-se um cenário que ainda não se consolidou.\nE isso gera conclusões apressadas.\nA eleição ainda está em construção — e construir não é o mesmo que consolidar.\n\n **E aí?**\nO maior erro neste momento é achar que o jogo já está claro.\nEle não está.\nO que existe hoje é uma disputa em formação, com variáveis ainda abertas e comportamento eleitoral indefinido.\nE, na política, o que não está definido ainda pode mudar.\nE o que pode mudar, decide eleição.\n',NULL,'/api/media/materia/novo-1777160070442-j1fxxl7vp/imagens/1777160071102-Binóculo.jpg',NULL,0,'published','2026-04-28 13:36:24.226','2026-04-25 23:36:28.751','2026-05-24 07:56:33.719','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto IA',14,NULL),
('bcc9f32b-638c-4c71-b1a5-c40727cd91f4','\"A misoginia dá lucro\", denuncia Ministério das Mulheres em audiência no STF','a-misoginia-da-lucro-denuncia-ministerio-das-mulheres-em-audiencia-no-stf-dv1y2','Em debate sobre o Marco Civil da Internet, a assessora especial e advogada Ísis Menezes Táboas aponta omissão das plataformas digitais diante de conteúdos que propagam discurso de ódio contra mulheres','Aassessora especial do Ministério das Mulheres (MMulheres), advogada Ísis Menezes Táboas, defendeu a necessidade de garantir mecanismos de enfrentamento à violência contra as mulheres nas plataformas digitais. Ela representou a pasta na audiência pública convocada pelo Supremo Tribunal Federal (STF), para debater o Marco Civil da Internet (MCI). Para Táboas, o enfrentamento à misoginia deve ser central nos debates sobre as regras do MCI que legislam sobre a responsabilidade de provedores de aplicativos — ou de ferramentas de internet — pelo conteúdo gerado por usuários, bem como sobre a possibilidade de remoção de conteúdos que possam ofender direitos, incitar o ódio ou difundir notícias fraudulentas.\n\nEm seu discurso, Táboas destacou que a pasta vem acompanhando com extrema preocupação a discussão sobre a chamada \"machosfera\", onde \"a misoginia reina\" em discursos de ódio propagados por \"influenciadores de masculinidade\". Além de trechos de falas misóginas, a assessora do MMulheres apresentou exemplos de mensagens que circularam livremente por tempo considerável, de forma anônima, até que fossem removidas pelas plataformas.\n\n>  \"Esses conteúdos são graves violações aos direitos humanos e políticos das mulheres, e, embora pertencentes ao meio virtual, repercutem sobremaneira na vida concreta, material, politica, profissional e pessoal de incontáveis mulheres\".\n\nAlém de denunciar a omissão das redes sociais digitais — diante de violações sistemáticas aos direitos humanos e políticos das mulheres — Táboas denunciou que as plataformas que hospedam contas ou canais de organizações misóginas lucram com essa prática. Em sua fala, apontou um estudo realizado pela agência de checagem Aos Fatos, que analisou 80 canais do tipo no YouTube: \"35 são monetizados pela própria plataforma e outros 36 utilizam diferentes estratégias, como vendas de cursos e de e-books para lucrar. Ou seja, a misoginia dá lucro\", denunciou.',NULL,'/api/media/materia/novo-1777234352926-43bytr43s/imagens/1777234353514-Misoginia.jpeg',NULL,0,'published','2026-04-26 20:13:44.256','2026-04-26 20:13:44.261','2026-05-07 00:04:31.973','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Carlos Moura (SCO/STF)',8,NULL),
('c03b165f-1b02-4554-b559-e5dae492fe25','Integração e desenvolvimento: autoridades destacam impacto histórico da Ponte de Guaratuba','integracao-e-desenvolvimento-autoridades-destacam-impacto-historico-da-ponte-de-guaratuba-w8ltu','Considerada uma das maiores intervenções de infraestrutura da história do Estado, a ponte passa a simbolizar um novo momento de desenvolvimento para o Litoral. O investimento do Governo do Paraná foi de R$ 400 milhões.','A entrega da Ponte de Guaratuba, à população, foi marcada não apenas pela celebração popular, mas também pelo reconhecimento, por parte de autoridades de diferentes áreas, da importância estratégica e do impacto da obra para o Paraná. \nO prefeito de Matinhos, Eduardo Dalmora, afirmou que a data marca o fim de um ciclo histórico e o início de uma nova fase para o Litoral. “\n\n> Esta obra de mais de R$ 400 milhões é a comprovação de um sonho acalentado há décadas, que hoje se materializa\n\npara abrir um novo tempo de prosperidade. Estamos testemunhando o fim do isolamento e o nascimento de uma nova era\", disse.\n\nO prefeito de Guaratuba, Mauricio Lense, enfatizou o significado histórico da obra para a cidade e para a integração do Litoral. “Ouvimos falar desta ponte por gerações. Muitas vezes ela foi motivo de descrença, uma ‘ponte invisível’. Hoje, ela representa o fim do isolamento. \n\n> É o comércio que vai girar o ano todo, o turista que chega com conforto e a ambulância que chega mais rápido\n\nConsolidamos um corredor estratégico e turístico, integrando de vez o nosso litoral ao Porto de Paranaguá e à capital\", avaliou.\n\nO presidente da Assembleia Legislativa do Paraná, o deputado estadual Alexandre Curi, ressaltou a união institucional como fator decisivo para a concretização da obra. “\n\n> Tenho que agradecer a todo o time da infraestrutura do Paraná e, também, a toda a sociedade que acreditou neste sonho, que hoje é uma realidade\n\nA Assembleia teve um papel importante, mas o grande mérito foi a pacificação dos poderes. Foi a união do Tribunal de Justiça, da Assembleia Legislativa e do Governo do Estado\", salientou.\n\nO presidente do Movimento Pró-Paraná, Marcos Domakoski, ressaltou o impacto estrutural da obra para o desenvolvimento da região. “Esta é a terceira maior ponte sobre o oceano do Brasil, mas é, sem dúvida, um marco extraordinário na nossa história. A partir dela, teremos um novo litoral, mais pujante, gerando emprego, renda e qualificando a população\".\n\nPara o chefe da Casa Civil, João Carlos Ortega, a entrega representa uma mudança estrutural para toda a região. “\n\n> Um dia histórico, que vai transformar todo o Litoral\n\ne a vida das pessoas, a mobilidade, e vai trazer mais valorização para o Litoral. É uma obra emblemática, que estava prevista desde a Constituição do Estado e hoje é uma realidade\", lembrou.\n\nPara o presidente do Sistema Ocepar, José Roberto Ricken, a nova estrutura representa a integração total do Litoral do Paraná. “É uma obra estratégica, que atende aos anseios do setor produtivo paranaense, porque integra Matinhos a Guaratuba, facilita o comércio de mercadorias, os serviços e faz a ligação até Santa Catarina. Foram mais de 40 anos de espera para que finalmente pudéssemos celebrar este momento”, disse.\n\n**PONTE** – Com investimento superior a R$ 400 milhões, a ponte é considerada uma das maiores obras de infraestrutura já realizadas no Paraná. São quatro faixas de tráfego, ciclovia e áreas para pedestres, além de acessos que totalizam mais de três quilômetros de extensão.\n\nProjetada para substituir o ferry boat, a travessia entre os municípios passa a ser feita em cerca de dois minutos. A travessia pelo mar, no entanto, será descontinuada de maneira gradual.\n\nMas os planos para o local já têm projeto certo: a construção de um complexo náutico com espaços de convivência, lazer, serviços além de vagas para embarcações atracadas na baía e também alocadas internamente. \n\nO projeto começou a sair do papel em 2019, com a elaboração do Estudo de Viabilidade Técnica, Econômica e Ambiental (EVTEA). As obras tiveram início em outubro de 2023 e chamaram atenção pela rapidez, com frentes de trabalho operando 24 horas por dia.\n\nDecisões estratégicas também marcaram o projeto, como a definição de que não haverá cobrança de pedágio e a restrição ao tráfego de veículos pesados.\n',NULL,'/api/media/materia/novo-1777844698677-hxzv58qgt/imagens/1777844700480-AUTORIDADES_PONTE.jpg',NULL,0,'published','2026-05-03 21:46:27.630','2026-05-03 21:46:27.656','2026-05-26 02:40:34.004','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',8,NULL),
('c070f402-b1fa-4f33-b123-ee66532b299f','Do amor ao ódio: o PL do Paraná e a política das conveniências','do-amor-ao-odio-o-pl-do-parana-e-a-politica-das-conveniencias-dszhx','A política raramente consegue esconder por muito tempo suas relações de interesse.','O comportamento recente da bancada do PL na Assembleia Legislativa do Paraná talvez seja um dos exemplos mais claros dessa política das conveniências.\n\nDurante anos, parte importante do PL ocupou espaço confortável dentro da base do governo Ratinho Junior. Havia cargos, espaço político, influência administrativa, proximidade institucional e acesso ao poder. \n\n> Nesse período, predominavam elogios, alinhamento, fidelidade pública e demonstrações quase permanentes de apoio ao governo.\n\nMas bastou a ruptura política causada pela pré-candidatura de Sérgio Moro ao governo pelo PL para que o cenário mudasse completamente e rapidamente.\nA saída da base expôs a fragilidade da relação.\n\nO PL deixou oficialmente a base aliada após a consolidação do projeto eleitoral de Moro. Com isso, vieram perda de espaços no governo, redução de influência, afastamento político e o encerramento de privilégios que parte do partido desfrutava dentro da estrutura estadual. \n\n> A mudança de comportamento foi imediata. Deputados que antes exaltavam o governo passaram a assumir postura agressiva e oposicionista.\n\nO episódio na Alep, nesta segunda-feira (11) envolvendo o pedido para convocar secretário do governo para explicar convênios ligados a Guto Silva, simboliza exatamente essa nova fase. \n\nO deputado Jacovós chegou a requerer em plenário a criação da bancada independente, o que foi de imediato negado pelo presidente Alexandre Curi, que conduzia a sessão naquele momento, que afirmou não haver previsão regimental. \n\n**Não se trata de uma oposição, propriamente dita, mas sim, de uma oposição ressentida.**\nEsse talvez seja o ponto mais delicado. Porque a nova postura do PL não transmite exatamente divergência programática. Transmite ruptura de interesses. E isso fica evidente pela velocidade da transformação.\n- **O que antes era “gestão eficiente”, virou “problema grave”**.\n- **O que antes era “parceria”, virou “suspeita**”.\n- **O que antes era “base”, virou “oposição”.**\n\nNa prática, o comportamento da bancada acaba revelando algo constrangedor para a própria política: a aliança não era sustentada por convicção, mas por participação no poder.\n\n**O efeito Moro desorganizou completamente o PL.**\nA entrada de Sérgio Moro no centro da disputa estadual obrigou o PL paranaense a fazer uma escolha: permanecer próximo do governo Ratinho Junior ou construir um palanque competitivo para 2026. Escolheu o confronto.\n\nE confronto exige discurso oposicionista.\nO problema é que parte da bancada ainda carrega o peso do passado recente, porque muitos dos atuais críticos eram defensores entusiasmados do mesmo governo há poucos meses.\n\n**O contraste fortalece Ratinho politicamente**.\nParadoxalmente, essa mudança brusca pode até fortalecer o governador politicamente. Na prática, ajuda a consolidar uma narrativa simples: enquanto Ratinho mantém agenda intensa de obras, entregas e viagens pelo interior, parte da oposição parece movida mais por perda de espaço do que por projeto alternativo. E isso tem impacto importante na percepção pública.\n\n**A política do interesse explícito**.\nO episódio também revela uma característica antiga da política brasileira: muitos grupos permanecem “fiéis” enquanto participam do governo.\nQuando deixam de participar: mudam o discurso, alteram a postura e descobrem repentinamente problemas que antes ignoravam. \nA diferença agora é que isso ocorre de forma muito mais visível, acelerada pelas redes sociais e pelo ambiente pré-eleitoral.\n\n**E aí?**\nA ruptura entre PL e o governo Ratinho Junior parece menos uma divergência ideológica profunda e mais uma disputa por espaço político (leia-se, cargos) dentro da sucessão estadual.\nE talvez o comportamento recente da bancada tenha revelado algo importante ao eleitor: parte da relação nunca foi construída sobre lealdade política real, mas apenas e tão somente sobre conveniência.\n\n**Fato**.\nNa política, alianças costumam durar enquanto o poder é compartilhado.\nO problema é que, quando o “amor” termina imediatamente após a perda dos cargos e das benesses, a oposição deixa de parecer convicção e começa a parecer ressentimento.\n',NULL,'/api/media/materia/novo-1778539375851-cbhwxoydb/imagens/1778539376211-Plen_rio_Alep_II.webp',NULL,0,'published','2026-05-12 12:24:29.223','2026-05-11 22:48:09.926','2026-06-06 18:38:16.748','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Valdir Amaral/Alep',15,NULL),
('c28fe71b-b03c-40b7-a9be-2b22d411c3b9','Prefeitura de Curitiba amplia o número de vagas para tratamento da dependência química','prefeitura-de-curitiba-amplia-o-numero-de-vagas-para-tratamento-da-dependencia-quimica-ui7l5','O edital vai habilitar nove entidades, que ofertarão para a Secretaria Municipal de Desenvolvimento Humano até 61 novas vagas durante nove meses','Dia seguinte a publicação do vídeo que deu o que falar, na abordagem de pessoas em situação de rua, o prefeito Eduardo Pimentel lançou, o edital de credenciamento para comunidades terapêuticas acolhedoras. \n\nO objetivo do chamamento público é ampliar a oferta de vagas destinadas ao município para reabilitação de pessoas em situação de dependência química que, assim, podem avançar na proposta terapêutica rumo à reinserção social e autonomia.\n\n> “Estamos destinando R$ 1 milhão para ampliar a nossa rede de vagas nas comunidades e isso é só o começo. Vamos continuar lutando todos os dias para salvar vidas e incluir pessoas também pelo acesso ao trabalho digno”, disse o prefeito.\n\n**Mais vagas**\nO edital vai habilitar nove entidades, que ofertarão para a Secretaria Municipal de Desenvolvimento Humano (SMDH) até 61 novas vagas durante nove meses. Para isso, o município pagará entre R$ 1,8 mil a R$ 2 mil mensais por vaga, de acordo com a personalização do atendimento oferecida a cada acolhido. O valor é maior que o pago pelos convênios firmados com o governo estadual e a União, fixados em R$ 1,7 mil por vaga.\n\nAs comunidades terapêuticas são os espaços que recebem as pessoas que desejam, espontaneamente, se livrar do consumo de drogas. Elas podem vir de trajetórias diversas, como a internação hospitalar para estabilização ou das unidades de acolhimento da Fundação de Ação Social (FAS). Ao saírem, podem voltar para as suas famílias ou morar temporariamente no hotel social da SMDH.\n\nAlém do lançamento do edital, Eduardo Pimentel assinou termos de cooperação com a Federação Paranaense de Comunidades Terapêuticas (Fepact) e outro com as Comunidades Terapêuticas Associadas do Brasil (Compacta), destinados a ações de capacitação, orientação institucional e fortalecimento de políticas públicas sobre drogas.\n',NULL,'/api/media/materia/novo-1778241363050-cgezugb2q/imagens/1778241364372-Curitiba_edital_comunidades.jpg',NULL,0,'published','2026-05-08 11:58:46.312','2026-05-08 11:58:46.348','2026-05-23 04:17:04.999','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Pedro Ribas/SECOM',9,NULL),
('c92c535a-4cbc-4b51-952b-7e5fd45e49f1','Nova pesquisa Meio/Ideia confirma desgaste do bolsonarismo nacional e muda o ambiente político no Paraná.','nova-pesquisa-meioideia-confirma-desgaste-do-bolsonarismo-nacional-e-muda-o-ambiente-politico-no-parana-hdrom','A pesquisa mostra que esse campo começa a perder estabilidade e isso altera completamente o ambiente político nacional.','A nova pesquisa Meio/Ideia para a presidência da República consolidou um movimento político importante e inevitável no atual cenário nacional: Flávio Bolsonaro perdeu força e Lula voltou a abrir vantagem.\n\nO ambiente político do PL começou a sofrer desgaste mais intenso e os números mostram uma mudança relevante no humor do eleitorado brasileiro. \n\n> Os reflexos já começam a aparecer diretamente no político-eleitoral do Paraná.\n\n**O desgaste de Flávio Bolsonaro.**\nO levantamento mostrou que Lula voltou a liderar a disputa contra Flávio Bolsonaro após os recentes episódios envolvendo empresários, banqueiros e o entorno político do PL. \nIsso possui enorme impacto político, porque Flávio Bolsonaro vinha sendo tratado como principal herdeiro eleitoral do bolsonarismo, como representante direto do núcleo conservador e principal referência nacional do PL para 2026. \nA pesquisa mostra que esse campo começa a perder estabilidade e isso altera completamente o ambiente político nacional.\n\n**O desgaste nacional do PL atinge Sergio Moro no Paraná.**\nNo Paraná, esse movimento possui consequência direta: Sergio Moro passa a sentir o peso do desgaste do campo bolsonarista nacional.\nMesmo tentando estadualizar o discurso, Moro pertence ao PL, depende fortemente do eleitor conservador e está conectado ao ambiente político liderado por Bolsonaro e Flávio. \n\nO problema é que o debate nacional saiu do campo ideológico e entrou no campo moral e financeiro. As recentes notícias envolvendo banqueiros, empresários e financiadores ligados ao entorno bolsonarista começaram a produzir desgaste no eleitorado moderado. \n\n> Ratinho Junior surfa tranquilo na popularidade e aparece cada vez mais distante das crises nacionais\n> Enquanto o PL enfrenta turbulência, Ratinho Junior consolida posição oposta.\n\nO governador e mantém distante dos confrontos nacionais, não mergulha nas guerras ideológicas de Brasília, mantém foco administrativo e fortalece presença no interior do Paraná. \nIsso virou um enorme diferencial político e o eleitor começa a perceber que Ratinho Junior construiu um modelo baseado em gestão, obras e estabilidade. Sandro Alex surfa essa onda, na mesma prancha de Ratinho e cresce justamente dentro desse ambiente.\n\n**Sandro Alex ocupa espaço do eleitor moderado.**\nAs pesquisas recentes do Paraná mostram um movimento importante, com Sandro Alex crescendo de forma consistente.\nE esse crescimento ocorre exatamente no momento em que o bolsonarismo sofre desgaste nacional, com o PL enfrentando turbulência política e parte do eleitorado conservador moderado começa a buscar alternativa menos ideológica. \n\n> Sandro Alex aparece associado às obras, às entregas do governo, à infraestrutura e à continuidade administrativa. Isso amplia em muito a sua competitividade.\n\n**O bolsonarismo perde força narrativa.**\nOutro detalhe importante da pesquisa Meio/Ideia é que o discurso anti-sistema, que parecia tão forte no meio da direita e da extrema direita, perdeu potência.\n\n> Durante anos, o bolsonarismo sustentou narrativa baseada em moralidade, combate às elites, enfrentamento ao sistema político e oposição ao mercado financeiro tradicional.\n \nMas os recentes episódios envolvendo o banqueiro Vorcaro, fundos, offshores, empresários e financiadores políticos atingiram exatamente esse discurso. \nA consequência política começa a aparecer nas pesquisas.\n\n**O Paraná vive realidade política diferente do Brasil.**\nAqui existe um fator importante: o eleitor paranaense separa cada vez mais Brasília da gestão estadual.\nEnquanto a política nacional vive polarização, desgaste, ataques e crises, o Paraná acompanha obras, investimentos, interiorização, emprego e entregas do governo Ratinho Junior. \nEsse ambiente fortalece Sandro Alex, Alexandre Curi e todo o grupo político do governador. \n\n**Moro enfrenta dificuldade crescente fora dos grandes centros.**\nO reflexo nacional também começa a afetar a dinâmica regional.\nSergio Moro segue forte em Curitiba, nas redes sociais e entre o eleitorado ideológico, mas enfrenta dificuldade crescente no interior do estado.\nPorque o PSD ocupa prefeituras, lideranças regionais, agendas municipais e entregas de obras.  Ratinho Junior conseguiu transformar presença regional em ativo eleitoral.\n\n**A eleição do Paraná começa a mudar de eixo.**\nNo início da pré-campanha, a disputa parecia baseada em notoriedade, fama nacional e recall político. \nAgora o cenário muda.\nO debate começa a girar em torno de gestão, estabilidade, continuidade, presença regional e capacidade administrativa. \nE isso favorece diretamente Ratinho Junior e Sandro Alex.\n\n**O que a pesquisa realmente revela.**\nA nova pesquisa Meio/Ideia mostra muito mais do que números presidenciais.\nEla revela:\n\n✅ desgaste político do campo bolsonarista;\n\n✅ perda de força narrativa de Flávio Bolsonaro;\n\n✅ fortalecimento de modelos mais moderados e administrativos;\n\n✅ e reflexos diretos sobre a eleição do Paraná. \n\n**E aí?**\nA política nacional, sem dúvida alguma, começa a mudar de direção.\nO desgaste de Flávio Bolsonaro enfraquece o ambiente político do PL e produz reflexos diretos sobre Sergio Moro no Paraná.\nEnquanto isso, Ratinho Junior mantém alta aprovação, Sandro Alex cresce nas pesquisas e o grupo governista ocupa o espaço da estabilidade administrativa. \n***A eleição do Paraná deixa de ser apenas disputa ideológica e começa a se transformar em confronto entre desgaste nacional e gestão aprovada.***\nE viva a democracia!\n',NULL,'/api/media/materia/novo-1780009079842-4bagbfi0d/imagens/1780009081069-LULA__FL_VIO_E_VORCARO.png',NULL,0,'published','2026-05-28 22:58:55.738','2026-05-28 22:58:55.764','2026-06-03 05:53:43.343','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',10,NULL),
('c9538e61-884d-4ccd-bd79-44e7362efea3','Governo do Paraná investe R$ 160 milhões em nova ligação entre Curitiba e Pinhais','governo-do-parana-investe-rdollar-160-milhoes-em-nova-ligacao-entre-curitiba-e-pinhais-jemr7','O projeto prevê a modernização de 9,45 quilômetros de vias e a implantação de novas estruturas para melhorar a mobilidade na Região Metropolitana da Capital.','O novo complexo viário que vai ampliar a ligação entre Curitiba e Pinhais avançou mais uma etapa. O governador Carlos Massa Ratinho Junior anunciou a publicação da licitação para a execução das obras. Com investimento de R$ 160 milhões do Governo do Estado, o projeto prevê a modernização de 9,45 quilômetros de vias e a implantação de novas estruturas para melhorar a mobilidade na Região Metropolitana de Curitiba.\n\nO projeto, executado por meio da Agência de Assuntos Metropolitanos do Paraná (Amep), prevê a construção de novos viadutos, ampliação da infraestrutura para o transporte coletivo, inclusive com novas canaletas, e uma ampla requalificação urbana, com novo pavimento, iluminação pública e paisagismo ao longo de todo o trajeto.\n\n“Essa é uma obra estruturante para a Região Metropolitana, em especial para Curitiba, Pinhais e Piraquara. Ela vai criar um novo corredor de mobilidade e de transporte público. Quem sair do Terminal de Pinhais vai poder acessar o corredor exclusivo do biarticulado e seguir até o Campo Comprido. Além disso, teremos um viaduto de 800 metros, um dos maiores da Região Metropolitana, trazendo mais mobilidade, segurança e rapidez para quem se desloca entre essas cidades”, afirmou o governador.\n\nRatinho Junior destacou que o novo complexo viário integra um conjunto de investimentos voltados à mobilidade da RMC. **“Essa é uma das obras que estamos fazendo para a Região Metropolitana de Curitiba. Já temos a duplicação do Contorno Norte em andamento, a duplicação da PR-423 entre Campo Largo, Araucária e Balsa Nova, a terceira fase da Rodovia dos Minérios, as obras de ampliação da BR-277 em São José dos Pinhais, as trincheiras na BR-116 em Fazenda Rio Grande** e outros projetos que vão melhorar a mobilidade e preparar a região para o crescimento dos próximos anos”, elencou.\n\nDe acordo com a prefeita de Pinhais, Rosa Maria, a obra era aguardada há anos e deve trazer impactos diretos na rotina da população. “Essa é uma obra muito importante porque faz a integração entre os municípios, encurta distâncias e traz melhorias na mobilidade urbana, acessibilidade, segurança e qualidade de vida”, salientou.\n\nPara o prefeito de Curitiba, Eduardo Pimentel, o projeto reforça a integração entre a Capital e os municípios vizinhos. “Curitiba e a Região Metropolitana funcionam como uma cidade só e precisamos pensar a mobilidade dessa forma. Essa obra vai facilitar muito a ligação entre Curitiba e Pinhais, beneficiando moradores dos dois municípios e melhorando a qualidade de vida de quem utiliza esse eixo diariamente”, disse.\n',NULL,'/api/media/materia/novo-1780486870765-t46fam9bp/imagens/1780486873444-Ratinho_em_Pinhais_II.jpg',NULL,0,'published','2026-06-03 13:22:20.044','2026-06-03 11:42:35.102','2026-06-03 19:29:30.928','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ari Dias/AEN',7,NULL),
('c9b9bbed-8b8a-4938-8cd3-72950c7ccf93','Ponte da Vitória: a obra que conecta governo, território e legado','ponte-da-vitoria-a-obra-que-conecta-governo-territorio-e-legado-khh4t','A travessia por ferryboat nunca foi apenas uma solução logística. Era um limite.','Há obras que resolvem problemas.\nE há obras que redefinem a percepção de um governo.\nA Ponte de Guaratuba — oficialmente denominada Ponte da Vitória — se aproxima mais do segundo caso.\n\n**1. De promessa histórica a símbolo de execução**\nDurante décadas, a ligação entre Guaratuba e Matinhos foi tratada como um problema conhecido — e adiado.\nA travessia por ferryboat nunca foi apenas uma solução logística.\nEra um limite.\n•	filas longas \n•	instabilidade operacional \n•	impacto no turismo \n•	restrição ao desenvolvimento regional. \nA decisão de construir a ponte rompe esse ciclo. Transforma um problema crônico em obra concreta e, com isso, altera a percepção sobre a capacidade de execução do Estado.\n\n**2. Impacto direto na vida da população**\nA importância da ponte não está apenas no projeto.\nEstá no cotidiano.\nEla muda o deslocamento de moradores, o acesso a serviços, a dinâmica econômica do litoral, reduz tempo, aumenta previsibilidade, amplia a integração regional. \n\n> Para quem vive na região, não é uma obra abstrata. É mudança prática.\n\n**3. O efeito econômico**\nInegavelmente, a Ponte da Vitória tem um impacto que vai além da mobilidade.\nEla atua como vetor de desenvolvimento, com uma valorização gigantesca imobiliária, expansão do turismo, atração de investimentos e dinamização real do comércio local. Estabelece uma conexão entre território e economia. E isso gera um efeito multiplicador.\n\n**4. A obra como marca de governo**\nPara o governo de Ratinho Junior, a ponte vai muito além de uma entrega. Representa claramente um modelo.\n- foco em infraestrutura \n- priorização de obras estruturantes \n- parceria com investimentos privados \n- capacidade de tirar projetos do papel.\n\nResumidamente, é uma síntese da gestão. Não por acaso, tornou-se uma das principais vitrines do governo.\n\n**5. O valor político da entrega**\nA Ponte de Guaratuba, oficialmente chamada de Ponte da Vitória, é, ao mesmo tempo, uma das obras mais emblemáticas do governo de Ratinho Junior. Ela resolve um problema histórico. Não apenas de mobilidade, mas de integração.\n\n> Na política, obras como essa, têm um peso específico: são visíveis, são tangíveis e são difíceis de contestar\n\nOu alguém imagina a oposição falando mal da ponte e de seus benefícios para a população?\nDiferente de programas abstratos, uma obra dessa magnitude pode ser vista, pode ser usada, pode ser medida. Isso transforma a Ponte da Vitória em ativo político.\n\n**6. A conexão com 2026**\nA ponte também dialoga diretamente com o cenário eleitoral. Ela reforça uma narrativa: a de continuidade de um modelo de gestão baseado em entrega. Nisso, ao associar sua imagem a esse tipo de obra, o governo cria uma base concreta para sustentar seu projeto político. A entrega deixa claro que, não se trata apenas de discurso, mas de demonstração.\nA ponte cumpre um papel estratégico e materializa a ideia de gestão baseada em entrega. \n\n> Ela funciona como prova concreta de capacidade administrativa.\n\nNão é promessa. \nNão é programa. \nÉ estrutura. \nE, por isso, se torna um ativo político extremamente relevante.\n \n\n**E aí?**\nA Ponte da Vitória não é apenas uma solução de mobilidade.\nÉ um marco.\nUm marco de execução, de presença do Estado e de transformação regional.\nPara a população, representa qualidade de vida.\nPara o governo, representa legado.\nE, em um cenário político cada vez mais disputado, legado é o que sustenta continuidade.\n\n**Fato**\nA ponte resolve um problema antigo e cria algo novo: uma referência de governo.\nE, na política, quem consegue transformar obra em referência\ntransforma gestão em força.\n',NULL,'/api/media/materia/novo-1777628342992-fcbkr1oad/imagens/1777628344041-Ponte_pronta.jpg',NULL,0,'published','2026-05-05 13:38:18.701','2026-05-01 09:40:43.225','2026-05-09 10:21:33.696','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Arnaldo Neto/AEN',16,NULL),
('d0e008a7-7bde-42c7-aee3-26f075822b76','O caso Vorcaro atingiu Flávio Bolsonaro — e a nova pesquisa mostra isso claramente','o-caso-vorcaro-atingiu-flavio-bolsonaro-e-a-nova-pesquisa-mostra-isso-claramente-xv0se','Na política, especialmente no campo conservador, isso gera um dano específico: enfraquece discurso anticorrupção','A nova pesquisa presidencial divulgada nesta semana talvez tenha produzido o primeiro grande impacto político real da corrida de 2026: o desgaste eleitoral de Flávio Bolsonaro após a revelação dos contatos com o banqueiro Daniel Vorcaro.\n\nAté poucas semanas atrás, Flávio vivia seu melhor momento político com crescimento constante nas pesquisas, empate técnico com Lula, liderança em alguns cenários e consolidação como principal nome do bolsonarismo nacional. \n\nMas o cenário mudou rapidamente e a pesquisa AtlasIntel/Bloomberg divulgada após a explosão do caso mostra exatamente isso, que Flávio caiu cerca de 6 pontos em simulações de segundo turno contra Lula. \n\n**O problema não foi apenas o áudio.**\nTalvez o principal erro político tenha sido outro: a contradição narrativa. Inicialmente, Flávio Bolsonaro negou proximidade com Daniel Vorcaro. Depois, admitiu encontros e negociações ligadas ao financiamento do filme “Dark Horse”, sobre Jair Bolsonaro. \nNa política, especialmente no campo conservador, isso gera um dano específico: enfraquece discurso anticorrupção, abala imagem de coerência e aproxima o candidato da velha política financeira que o bolsonarismo historicamente combateu. \n\n**O caso atingiu exatamente o ponto mais forte de Flávio.**\nEsse foi o aspecto mais importante. Flávio Bolsonaro não crescia apenas como “filho de Bolsonaro”. Ele crescia como símbolo de continuidade ideológica, nome anti-establishment, representante do conservadorismo duro e herdeiro direto do capital político do pai. \nO caso Vorcaro atingiu exatamente essa imagem. Porque Daniel Vorcaro aparece associado a escândalos financeiros, investigações, liquidação do Banco Master e suspeitas graves envolvendo o sistema financeiro. \n\n**A pesquisa mostra que o eleitor reage rapidamente a desgaste moral.**\nO levantamento Atlas/Bloomberg revela algo ainda maior, que o eleitor conservador continua muito sensível a temas ligados à integridade e bastidores financeiros.\n\n> A queda de Flávio não ocorreu após crise econômica, debate ideológico ou proposta impopular. O recuo apareceu justamente após a exposição pública das relações com Vorcaro.\n\nIsso indica que parte do eleitorado ficou desconfortável, percebeu incoerência, ou passou a enxergar aproximação excessiva com elites financeiras. \n\n**Lula foi beneficiado pelo desgaste adversário.**\nOutro ponto importante que aparece nesse levantamento, é que Lula não cresceu apenas por méritos próprios. A pesquisa sugere claramente que parte do crescimento petista veio do enfraquecimento momentâneo do adversário. \nIsso mostra uma eleição extremamente dependente de narrativa, escândalos, percepção pública e estabilidade emocional do eleitor. \n\n**O bolsonarismo continua forte — mas menos blindado.**\nSeria exagero dizer que Flávio Bolsonaro “quebrou” eleitoralmente.\nO bolsonarismo segue muito competitivo, nacionalmente forte, altamente mobilizado e com base fiel consolidada. Mas a pesquisa revela algo novo: existe vulnerabilidade política quando o tema envolve bastidor financeiro e coerência moral.\nE isso pode preocupar o PL.\n\n**O episódio pode mudar a dinâmica da campanha.**\nAté aqui, a eleição caminhava para Lula x Flávio em polarização direta.\nAgora surgem novas dúvidas: Flávio conseguirá estabilizar o desgaste? o caso continuará produzindo efeito? surgirão novos episódios? ou o eleitor esquecerá rapidamente? \nA resposta a essas perguntas definirá muito da eleição presidencial.\n\n**O impacto psicológico da pesquisa talvez seja ainda maior.**\nNa política, pesquisas não medem apenas intenção de voto. Elas alteram humor político, reorganizam alianças, fortalecem narrativas e influenciam percepção de viabilidade. \nAté aqui, Flávio era visto como nome em ascensão constante. Agora, pela primeira vez surge a percepção de que pode haver teto, desgaste e vulnerabilidade.\n\n**E aí?**\nO caso Vorcaro, claramente produziu o primeiro grande abalo real da pré-campanha presidencial de 2026. Não necessariamente porque destruiu Flávio Bolsonaro, mas porque mostrou algo importante: até candidatos muito fortes podem sofrer desgaste rápido quando há choque entre discurso moral e bastidor político-financeiro. \n\n**Fato.**\nFlávio Bolsonaro cresceu como símbolo político de ruptura. O caso Vorcaro colocou esse discurso sob pressão, e a nova pesquisa mostra que o eleitor percebeu.\nA eleição presidencial continua aberta. Mas agora já existe uma certeza: o bolsonarismo segue forte. Só não parece mais invulnerável.\n',NULL,'/api/media/materia/novo-1779242414295-mhrzitfc5/imagens/1779242427082-Lula__Vorcaro_e_Fl_vio.png',NULL,0,'published','2026-05-20 02:01:33.628','2026-05-20 02:01:33.663','2026-06-04 17:11:06.489','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',12,NULL),
('d3bf955b-c539-4784-a3f8-9d06bb2f3cc1','Curitiba fechou o primeiro trimestre com o segundo maior saldo de empregos do País','curitiba-fechou-o-primeiro-trimestre-com-o-segundo-maior-saldo-de-empregos-do-pais-g974m','Os dados são do Cadastro Geral de Empregados e Desempregados (Caged) do Ministério do Trabalho e Emprego (MTE) divulgados nesta quarta-feira (29/4).','Curitiba fechou o primeiro trimestre com o segundo maior saldo de empregos com carteira assinada do País, com 17.686 vagas. A capital paranaense só perdeu para São Paulo, com 54.551 vagas geradas, ficou à frente de Brasília, com 16.032 vagas, e Rio de Janeiro, com 10.652. Os dados são do Cadastro Geral de Empregados e Desempregados (Caged) do Ministério do Trabalho e Emprego (MTE) divulgados nesta quarta-feira (29/4). \n\n> O saldo nos três primeiros meses é a diferença entre 159.943 admissões e 142.257 demissões no período.\n  \nO setor de serviços puxou as contratações no período, com saldo de 14.168 vagas geradas. A construção civil também foi destaque, com 3.025 novos empregos, e o comércio, com 690.',NULL,'/api/media/materia/novo-1777553020349-nis3qudl8/imagens/1777553022631-CTPS.jpg',NULL,0,'published','2026-04-30 12:45:29.924','2026-04-30 12:45:29.926','2026-05-12 14:50:07.344','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Sandra Lima/FAS',5,NULL),
('d41bf11c-31d9-4593-861b-69388a447189','Quaest em 10 estados: o alerta político que o governo Lula já não consegue ignorar','quaest-em-10-estados-o-alerta-politico-que-o-governo-lula-ja-nao-consegue-ignorar-ifc6r','A nova pesquisa Quaest divulgada nesta terça-feira (06) amplia um movimento que Brasília acompanha há meses','O desgaste do governo Lula deixou de ser localizado e passou a ter distribuição nacional.\nOs números mostram um cenário politicamente relevante:\n•	desaprovação crescente em estados estratégicos \n•	perda de sustentação em regiões urbanas \n•	dificuldade de recuperar narrativa econômica. \nE isso acontece em um momento delicado: quando a eleição de 2026 começa a deixar o campo da especulação e passa a influenciar decisões concretas de alianças, candidaturas e posicionamentos. \n\n> O problema já não é apenas econômico.\n> O governo ainda aposta no discurso da recuperação econômica.\n\nMas a pesquisa indica algo mais profundo: desgaste de percepção.\nNa política, isso importa mais do que indicadores técnicos.\nPorque governos não são avaliados apenas por números.\nSão avaliados por sensação social.\nE a sensação atual parece apontar para:\n•	cansaço político \n•	perda de confiança \n•	dificuldade de reconexão narrativa \n\n**O Sudeste continua sendo o centro do problema**\nOs dados reforçam um padrão: Lula encontra mais resistência justamente nas regiões mais urbanizadas e economicamente relevantes.\nEsse ponto é central para 2026.\nPorque eleição presidencial não se vence apenas com bases históricas.\nÉ preciso competitividade nos grandes centros.\nE é exatamente aí que aparecem os maiores sinais de desgaste.\n\n**A antecipação do ambiente eleitoral**\nOutro aspecto importante: a avaliação de governo começa a se misturar com projeção eleitoral.\nIsso muda o comportamento da política.\n•	partidos começam a recalcular alianças \n•	governadores ampliam autonomia \n•	possíveis candidatos passam a medir distância de Brasília .\n\nEsse movimento já aparece claramente no PSD, por exemplo, após o afastamento gradual de lideranças como Ratinho Junior, da disputa presidencial direta, e a consolidação de projetos regionais próprios. \n\n**O governo enfrenta um problema de narrativa**\nA oposição encontrou um eixo simples: associar o governo à ideia de desgaste e desconexão.\nE o Planalto ainda não conseguiu responder de forma consistente.\nO resultado é um cenário perigoso: o governo mantém força institucional, mas perde capacidade de empolgação política.\n \n**O impacto nos estados**\nA pesquisa também revela outro dado estratégico: governadores bem avaliados tendem a se descolar do desgaste federal.\nIsso fortalece lideranças regionais.\n\nNo Paraná, por exemplo, o contraste entre a alta aprovação de Ratinho Junior e o desgaste nacional do governo federal ajuda a consolidar um ambiente político próprio, menos dependente da polarização nacional.\nE isso tende a influenciar diretamente as disputas estaduais.\n\n**E aí?**\nA Quaest não mostra apenas queda de aprovação.\nMostra algo mais relevante: mudança de ambiente político.\nE mudanças de ambiente costumam anteceder mudanças eleitorais.\nAinda há tempo para reação. Mas o governo já não enfrenta apenas uma disputa de números. Enfrenta uma disputa de percepção.\nE, nesse contexto, percepção costuma chegar antes do resultado.\n\n**Fato**\nA pesquisa não encerra a eleição.\nMas acende um alerta.\nPorque governos conseguem sobreviver a crises.\nO que raramente sobrevivem é à perda gradual da conexão política com o eleitor.\n',NULL,'/api/media/materia/novo-1778075169874-y1kdsux0e/imagens/1778075171006-LULA.jpg',NULL,0,'published','2026-05-06 19:26:08.748','2026-05-06 13:49:39.923','2026-05-09 12:15:11.260','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: reprodução',4,NULL),
('d4e3d52f-d332-4fa7-983d-55dacb25038a','Paraná é protagonista de ranking nacional que mede bem-estar da população','parana-e-protagonista-de-ranking-nacional-que-mede-bem-estar-da-populacao-tm948','O desempenho paranaense reforça os avanços sociais registrados nos últimos anos','O Paraná alcançou a quarta colocação nacional no Índice de Progresso Social (IPS) Brasil 2026 , divulgado nesta quarta-feira (20), posicionando o Estado entre os melhores do País em qualidade de vida e desenvolvimento social. \n\n> O índice paranaense chegou a 65,21 pontos, acima da média nacional, de 63,40, e superior ao resultado obtido pelo Estado em 2025, quando registrou 63,83 pontos.\n\nO levantamento é elaborado pela plataforma IPS Brasil, que avalia o bem-estar da população a partir de 57 indicadores sociais e ambientais, organizados em três grandes dimensões: Necessidades Humanas Básicas, Fundamentos do Bem-estar e Oportunidades.\n\nNo ranking nacional, o Paraná aparece logo atrás de Santa Catarina, que registrou 65,58 pontos. Distrito Federal e São Paulo ocupam as duas primeiras posições do levantamento.\n\nO desempenho paranaense reforça os avanços sociais registrados nos últimos anos, especialmente em áreas como moradia, saneamento básico e segurança pública, indicadores que integram a dimensão de Necessidades Humanas Básicas, a melhor avaliada do IPS Brasil 2026.\n\nO Estado também apresentou desempenho acima da média nacional na dimensão Fundamentos do Bem-Estar, que avalia acesso à educação básica, internet e comunicação, além das condições para uma vida saudável e de qualidade ambiental.\n\nPara o governador Carlos Massa Ratinho Junior, os resultados refletem um conjunto de políticas públicas voltadas à melhoria da qualidade de vida da população. “O Paraná vem construindo um ambiente cada vez mais favorável ao desenvolvimento humano, com investimentos em segurança, habitação, infraestrutura, educação e geração de oportunidades. \n\n> Esse resultado mostra que crescimento econômico e desenvolvimento social precisam caminhar juntos para melhorar efetivamente a vida das pessoas”, avaliou\n\n.\n**MORADIA EM ALTA** – Entre os pontos fortes do Paraná está o componente ligado à moradia. O relatório destaca o Norte do Paraná entre as regiões com os melhores desempenhos do País. O Casa Fácil Paraná, considerado o maior programa habitacional do Brasil, já beneficiou mais de 130 mil famílias em diferentes modalidades. Ele oferece subsídios para entrada da casa própria e possui linhas específicas para idosos, com apoio de até R$ 80 mil para aquisição de imóveis.\n\n**CIDADES** – O desempenho positivo também se reflete nos municípios paranaenses. Entre as capitais brasileiras, Curitiba conquistou a melhor colocação do País no IPS Brasil 2026, com índice de 71,29, superando Brasília (70,93), São Paulo (70,64) e Campo Grande (69,77).\n\nAlém da Capital, outras cidades paranaenses aparecem entre os destaques nacionais. Cornélio Procópio, no Norte Pioneiro, alcançou IPS de 71,16 pontos, enquanto Maringá registrou 70,87 pontos, ambas entre os 20 municípios brasileiros com melhores resultados.\n\nO levantamento também traz recortes populacionais, nos quais os municípios paranaenses seguem em evidência. Quatro Pontes, na região Oeste do Estado, aparece entre os dez melhores municípios do Brasil, com IPS de 70,30. Já Londrina figura entre os dez municípios com mais de 500 mil habitantes (excluindo capitais), com melhor desempenho nacional, alcançando índice de 67,73.\n',NULL,'/api/media/materia/novo-1779301868145-0a2yf6qwm/imagens/1779301868481-Curitiba.jpg',NULL,0,'published','2026-05-20 18:32:21.626','2026-05-20 18:32:21.651','2026-06-01 20:45:59.755','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Denis Ferreira Netto/SEDEST',6,NULL),
('d4e6b841-f451-4aa8-8577-16b0d9c2ae15','Curitiba instala o \"Abrigo Amigo\" para dar mais segurança nos pontos de ônibus ','curitiba-instala-o-abrigo-amigo-para-dar-mais-seguranca-nos-pontos-de-onibus-7fn92','O prefeito Eduardo Pimentel inaugurou, nesta segunda-feira (1/6), o primeiro ponto de ônibus Abrigo Amigo de Curitiba, em parceria com a concessionária de mobiliário urbanos Eletromídia e a operadora de telefonia Claro','A pessoa que se sentir em situação de vulnerabilidade ou simplesmente desejar companhia à espera do ônibus pode acionar um botão no painel digital para iniciar uma chamada de vídeo com uma central de monitoramento dedicada. \n\n> Não é necessário se identificar – o anonimato protege o usuário e garante um ambiente seguro e livre de constrangimentos.\n\nO atendimento é conduzido por uma equipe formada por 30 mulheres, que passam por treinamentos com assistentes sociais e especialistas em violência contra a mulher, garantindo acolhimento qualificado e preparado para lidar com diferentes situações.\n\nCada unidade é equipada com câmeras de alta resolução, microfones sensíveis e alto-falantes potentes, conectados à central de monitoramento e que podem ser acessados pelo Centro de Controle Operacional (CCO) da Urbs e a Muralha Digital.  \n\nO botão de acionamento tem placa em braille e está posicionado a 1,20 metro de altura, adequado para cadeirantes, crianças e pessoas com deficiência. O atendimento remoto dispõe de comunicação em Libras, e está em andamento a implementação de legendas durante as chamadas.',NULL,'/api/media/materia/novo-1780399426265-xe0toz911/imagens/1780399428426-ABRIGO_AMIGO_CTBA.jpg',NULL,0,'published','2026-06-02 11:27:37.237','2026-06-02 11:25:32.829','2026-06-03 19:28:11.530','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Pedro Ribas/SECOM',5,NULL),
('d8d9ab8b-f18c-4223-9841-c07bf3e83265','Saúde alerta viajantes com destino a países da Copa do Mundo para vacinação contra o sarampo','saude-alerta-viajantes-com-destino-a-paises-da-copa-do-mundo-para-vacinacao-contra-o-sarampo-hvmhu','Estados Unidos, México e Canadá concentram mais de 70% dos casos de sarampo nas Américas. Brasil é considerado país livre de circulação da doença','A Secretaria Municipal da Saúde (SMS) de Curitiba alerta para que os viajantes com destino ao exterior do país confiram com antecedência se possuem o esquema vacinal completo contra o sarampo. \n\n> A orientação, referendada pelo Ministério da Saúde, é direcionada principalmente aos viajantes com destinos aos países sede da Copa do Mundo, que passam por surto da doença.\n\nEstados Unidos, México e Canadá concentram mais de 70% dos casos de sarampo nas Américas, de acordo com dados da Organização Pan-Americana da Saúde (Opas), escritório regional da Organização Mundial da Saúde (OMS). Enquanto o Brasil é considerado país livre de circulação da doença.  \n\n“Estima-se que milhões de pessoas participem da Copa o Mundo, gerando uma intensa mobilidade internacional que pode favorecer a disseminação de doenças transmissíveis. Nesse cenário, o sarampo merece atenção especial por ser uma doença viral aguda, altamente contagiosa e potencialmente grave”, alerta o diretor do Centro de Epidemiologia da Secretaria Municipal da Saúde, o médico Alcides Oliveira.',NULL,'/api/media/materia/novo-1778931119121-8r8440pry/imagens/1778931121019-vacina_agulhada.jpg',NULL,0,'published','2026-05-16 11:35:12.030','2026-05-16 11:35:12.056','2026-05-20 13:46:02.906','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Pedro Ribas/SECOM',3,NULL),
('d8f34880-a257-4dc3-b1cf-555ef0d5d7fe','Coisa di loco: Augusto Cury entra para a política e decide transformar sessão de terapia em campanha eleitoral','coisa-di-loco-augusto-cury-entra-para-a-politica-e-decide-transformar-sessao-de-terapia-em-campanha-eleitoral-2shan','O Brasil definitivamente abandonou qualquer compromisso com previsibilidade institucional.','Augusto Cury na política: o Brasil finalmente decidiu transformar sessão de terapia em campanha eleitoral.\nO Brasil já teve como candidato, sindicalista, militar, juiz, empresário, influencer político, outsider profissional, entre outros.\n\nAgora, oficialmente, entra em cena uma nova categoria: o candidato terapeuta.\nO psiquiatra e escritor Augusto Cury lançou sua pré-candidatura à Presidência da República em Belo Horizonte, pelo Avante, prometendo equilíbrio, inteligência emocional e superação da polarização. \nE talvez o Brasil realmente precise disso.\nPorque, olhando o cenário político atual, parece evidente que o país inteiro já ultrapassou qualquer estágio razoável de ansiedade coletiva.\n\n**Brasil entrou na fase da autoajuda eleitoral**.\nA entrada de Augusto Cury na política parece quase inevitável.\nDepois de anos de crise institucional, polarização permanente, redes sociais em combustão, debates transformados em surtos coletivos, a política brasileira finalmente chegou ao estágio clínico.\n\n**O discurso é curioso — e inteligente**.\nCury tenta ocupar um espaço que praticamente desapareceu no Brasil: o da antipolarização emocional.\nEnquanto uns gritam “democracia” e outros gritam “liberdade”, ele aparece dizendo: “respirem”.\nPoliticamente, isso pode parecer estranho, mas eleitoralmente, talvez faça sentido. Porque é inegável que o eleitor brasileiro está cansado. Muito cansado.\n\n**A candidatura que parece roteiro de streaming**.\nHá algo quase cinematográfico no horizonte político-eleitoral do país: o juiz virou senador, o coach virou candidato, o influencer virou liderança política, e agora o psiquiatra quer governar o país. \nO Brasil definitivamente abandonou qualquer compromisso com previsibilidade institucional.\n\n**O risco para Cury**.\nO problema é que a política brasileira não costuma premiar serenidade.\nEla premia conflito.\nE campanhas presidenciais normalmente funcionam como o exato oposto de uma sessão terapêutica.\n\n**O detalhe mais irônico**.\nTalvez Augusto Cury seja o primeiro candidato da história cujo eleitorado pode precisar menos de proposta econômica e mais de acompanhamento emocional.\nPorque, honestamente, depois dos últimos anos, não está fácil para ninguém.\n\n**E aí maluco?**\nA pré-candidatura de Augusto Cury talvez não mude a eleição, mas muda o retrato do momento político brasileiro.\nPorque ela revela um país cansado, emocionalmente exausto e procurando alguém que pareça minimamente equilibrado. \nO que, convenhamos, já seria uma inovação relevante na política nacional.\n\n**Fato.**\nO Brasil passou tanto tempo discutindo quem salvaria a democracia, que agora parece procurar alguém que salve a saúde mental coletiva.\nE talvez isso diga mais sobre o país, do que sobre Augusto Cury.\n',NULL,'/api/media/materia/novo-1778248902205-cb509q18q/imagens/1778248902521-Augusto_Cury.jfif',NULL,0,'published','2026-05-08 14:11:05.627','2026-05-08 14:03:28.929','2026-05-31 02:42:51.833','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','946db891-bb39-4065-802f-9c6c05d0aea4','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Elias Oliveira / Governo do Tocantins',8,NULL),
('d9881533-3a1f-45c0-9e38-62b24bc0ebea','Região Metropolitana de Curitiba é destaque nacional em desenvolvimento humano','regiao-metropolitana-de-curitiba-e-destaque-nacional-em-desenvolvimento-humano-1jsdz','Dados da pesquisa Radar IDHM mostram que a Região Metropolitana de Curitiba é bem avaliada em todos os quesitos: saúde e longevidade, educação e geração de renda','A Região Metropolitana de Curitiba tem o 2º maior Índice de Desenvolvimento Humano Municipal (IDHM) do país. A pesquisa Radar IDHM, divulgada pelo Programa das Nações Unidas para o Desenvolvimento (Pnud) Brasil, trouxe os dados referentes ao ano de 2024. A Região Metropolitana de Curitiba (RMC) obteve nota 0,856, estando atrás apenas da Região Metropolitana de Florianópolis (SC), que atingiu o índice 0,874. O estudo aponta que 17 das 21 regiões analisadas atingiram a faixa de “muito alto desenvolvimento humano” em 2024.\n\nPara chegar nesta pontuação são avaliados os parâmetros de saúde e longevidade, educação e geração de renda. Em 2024, o Brasil alcançou IDHM de 0,805. A escala do Pnud para classificar o desenvolvimento humano varia de 0 a 1, sendo muito alto acima de 0,800.\n\nO prefeito de Curitiba, Eduardo Pimentel, comentou os índices da RMC. \n\n> “Não é possível tratar cada município de maneira isolada. Temos uma parceria com políticas públicas vigorosas com cada cidade da região metropolitana para que o desenvolvimento venha para todos”, disse o prefeito.\n\n**RMC entre as melhor avaliadas**.\nNo índice referente à Educação, a RMC é a 2ª melhor classificada, com a pontuação 0,856, sendo a RM de São Paulo (SP) a primeira colocada, com 0,863.\n\nQuando avaliada a Renda, a região metropolitana de Curitiba também é a segunda melhor avaliada, obtendo a nota 0,827; a primeira posição ficou com a RM de Florianópolis e a nota 0,849. Em 2024, apenas cinco regiões atingiram a faixa de muito alto desenvolvimento humano em renda: Rio de Janeiro (RJ), Porto Alegre (RS), São Paulo, Curitiba e Florianópolis.\nPor fim, no quesito Longevidade, a RMC obteve a 4ª posição com índice 0,885 e a primeira colocada foi Florianópolis com 0,928.\n\n**Evolução em todos os parâmetros.**\nQuando feito o recorte por tempo, a Região Metropolitana teve crescimento do IDHM. No índice geral, a nota no ano de 2019 foi 0,835. Devido à pandemia, houve diminuição para 0,786 em 2021 e recuperou para 0,856 em 2024.\n\nNo quesito Educação, a nota da RMC em 2019 era 0,818, decresceu para 0,804 em 2021 e subiu para 0,856 em 2024. Em Saúde e Longevidade, o quadro se repetiu. \n\nA nota era 0,882 em 2019, foi prejudicada pela pandemia e desceu para 0,785 em 2021 e obteve 0,885 na última medição. Em Renda, a nota em 2019 era 0,806, na verificação de 2021 foi 0,770 e recuperou para 0,827 em 2024. Importante salientar que todas as regiões tiveram diminuição em suas avaliações no ano de 2021 devido ao covid-19 e suas consequências.  \n',NULL,'/api/media/materia/novo-1779886814405-ogsofkq4y/imagens/1779886817927-Parque_das__guas.jpg',NULL,0,'published','2026-05-27 13:01:29.738','2026-05-27 13:01:29.745','2026-05-29 11:37:25.749','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Divulgação/Prefeitura de Pinhais',5,NULL),
('da4b929c-64ab-4acb-a861-8379f2cc31d6','Meia Maratona Internacional de Curitiba deve reunir 10 mil corredores','meia-maratona-internacional-de-curitiba-deve-reunir-10-mil-corredores-m1x22','A camisa oficial da corrida deste ano presta homenagem à Seleção Brasileira de Futebol, que disputará a Copa do Mundo em junho.','O prefeito Eduardo Pimentel recebeu os organizadores da Meia Maratona Internacional de Curitiba 2026, Vilson Thomé e Filippe Thomé, da Thomé e Santos. Durante o encontro, eles entregaram ao prefeito os kits oficiais da prova, que acontece no dia 7 de junho, com largada na Pedreira Paulo Leminski (Rua João Gava, 970, Abranches).\n\nMais de 5 mil corredores já estão inscritos na corrida e a expectativa da organização é reunir cerca de 10 mil atletas - entre participantes das provas e de atividades do festival esportivo.\nA camisa oficial da corrida deste ano presta homenagem à Seleção Brasileira de Futebol, que disputará a Copa do Mundo em junho.\n\n“Curitiba tem se consolidado como palco de grandes eventos esportivos e a Meia Maratona Internacional já faz parte do calendário da cidade. É uma alegria ver uma prova deste porte crescendo a cada ano e reunindo famílias, atletas e visitantes em um ambiente de celebração e qualidade de vida”, afirmou o prefeito.\n\n**Entrega de kits**\nA entrega dos kits aos corredores será realizada exclusivamente nas sexta-feira (5/6), das 10h às 20h, e sábado (6/6), das 9h às 19h, na Pedreira Paulo Leminski.\n',NULL,'/api/media/materia/novo-1779795388273-la48l7wm0/imagens/1779795391213-Meia_maratona_de_Curitiba.jpg',NULL,0,'published','2026-05-26 11:39:11.181','2026-05-26 11:38:25.382','2026-05-31 07:34:05.981','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ricardo Marajó/SECOM',5,NULL),
('da9d3c9c-95e7-40f9-9ae9-ec89468ad35f','Começam as obras da Fábrica de Ideias, novo complexo de inovação e cultura do Paraná','comecam-as-obras-da-fabrica-de-ideias-novo-complexo-de-inovacao-e-cultura-do-parana-19e19','Ela ocupa um terreno de 50 mil metros quadrados no antigo polo industrial de Curitiba e terá 34 mil metros quadrados','O governador Carlos Massa Ratinho Junior assinou nesta quarta-feira (3) a ordem de serviço para o início das obras da Fábrica de Ideias, empreendimento que vai transformar a antiga fábrica da Brahma/Ambev, no bairro Rebouças, em Curitiba, no maior polo de inovação e economia criativa da América Latina.\n\nO investimento do Governo do Estado é de R$ 296,5 milhões para a implantação do complexo, que ocupa um terreno de 50 mil metros quadrados no antigo polo industrial de Curitiba e terá 34 mil metros quadrados de área construída, aproveitando parte das construções da antiga fábrica, que é uma Unidade de Interesse de Preservação — classificação dada a edificações antigas, casarões ou monumentos que possuem alto valor arquitetônico, histórico e cultural. Ela passará por um “retrofit sustentável\", que vai modernizar as estruturas, mantendo as fachadas históricas.\n\n> O novo espaço será destinado à instalação de empresas de tecnologia, instituições de pesquisa e escritórios governamentais, criando um ambiente colaborativo voltado ao desenvolvimento de soluções inovadoras\n\nO projeto é coordenado pela Secretaria de Estado das Cidades (Secid), com a colaboração de diversos órgãos e secretarias estaduais.\n\n“Nós escolhemos a antiga fábrica da Ambev justamente para poder ajudar na revitalização do Rebouças, um bairro importante da Capital. \n\n> A ideia é fazer um grande centro de inovação para acolher empresas de diversos segmentos, do agro ao setor automotivo, do esporte à saúde, fortalecendo essa cadeia produtiva que vem crescendo e que gera muitos empregos, em especial para os jovens”, afirmou Ratinho Junior.\n\nO governador salientou que o projeto é planejado há mais de três anos, tendo como inspiração espaços de inovação já instalados em outros locais, como o Instituto Caldeira, em Porto Alegre.\n\n>  “Nossa ideia é transformar este prédio em um centro tecnológico, onde poderemos conectar as empresas paranaenses a novas oportunidades de inovação, incentivando o networking entre elas”, disse.\n\n “Além de ser um espaço de qualificação dos nossos jovens na área de tecnologia e também fazer um trabalho cultural com os dois museus que serão instalados aqui”.\n\nO local passará por um amplo processo de engenharia e revitalização urbana para ceder lugar a um ecossistema tecnológico que, segundo o secretário das Cidades, Fernando Giacobo, vai dar início a uma nova era para o desenvolvimento urbano e tecnológico do Paraná.\n\n“A Fábrica de Ideias não é apenas uma grande obra de infraestrutura, mas sim um investimento direto no futuro dos jovens e na modernização econômica da Capital, transformando esse patrimônio histórico em um motor vivo de inovação, geração de empregos e desenvolvimento social”, disse. \n\nO polo de inovação também vai atuar em sintonia com o Vale do Pinhão, da Prefeitura de Curitiba, com a meta de ampliar exponencialmente os pontos de contato e de conexões produtivas entre startups locais, universidades de ponta, grandes corporações privadas e os entes do poder público.\n\n“O bairro do Rebouças vem sendo tratado como um espaço de inovação há algum tempo, com o Vale do Pinhão e o nosso Pinhão Hub, que incentivam novas ideias para a nossa Capital. \n\n> É um projeto que preserva o que é necessário, mas construindo a inovação no espaço público”, afirmou o prefeito Eduardo Pimentel. \n\n“Também fortalece as características do Rebouças, um bairro historicamente ligado às indústrias e à inovação, e contribui com a revitalização do nosso centro expandido”.',NULL,'/api/media/materia/novo-1780511202789-esj2u3sad/imagens/1780511203102-F_brica_de_id_ias.jpg',NULL,0,'published','2026-06-03 18:45:54.035','2026-06-03 18:27:28.119','2026-06-08 05:49:44.644','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Jonathan Campos/AEN',11,NULL),
('db8c8d9d-1ab4-4a3e-99ca-eebf9d311b12','Entre a obra e o discurso','entre-a-obra-e-o-discurso-i58up','A eleição no Paraná deixou de ser uma disputa comum. De um lado, está um projeto que governou o estado por oito anos e construiu sua base em entregas concretas. De outro,','De um lado, está um projeto que governou o estado por oito anos e construiu sua base em entregas concretas.\nDe outro, uma candidatura que chega com relativa identidade política — mas cuja relação com a gestão pública estadual é inexistente.\nA diferença não é apenas de estilo.\nÉ de natureza.\n\n**1. A política da entrega X a política da promessa**\nO nome escolhido por Ratinho Junior, o deputado federal e ex-secretário Sandro Alex, ao contrário do que muitos pensam, não surge do acaso.\nSua candidatura está diretamente vinculada a um eixo central do governo: infraestrutura.\nDurante sua passagem pela secretaria, acumulou protagonismo em obras estruturantes — como a Ponte de Guaratuba e o novo pacote de concessões rodoviárias, que somam bilhões em investimentos no estado.\nIsso define um tipo de campanha:\n\n> É baseada em resultado visível e não em promessas vazias. E as promessas virão, aguarde!\n\n**2. O contraste inevitável**\nDo outro lado, Sérgio Moro entra na disputa com outro tipo de ativo.\n•	projeção nacional \n•	associação à Lava Jato \n•	identidade política em construção \nMas há um ponto central:\nSua trajetória está totalmente dissociada da gestão direta de políticas públicas estaduais. Quem foi Sérgio Moro para o Paraná, nos últimos 4 ou 8 anos?\nIsso não é necessariamente uma fragilidade — mas muda o campo de comparação.\nA eleição passa a opor:\n•	quem executou \n•	e quem representa uma agenda \nNa prática, a disputa se dará entre “quem fez e quem não fez”.\n\n**3. A estratégia de Ratinho Junior: reduzir o debate ao concreto**\nA escolha de Sandro Alex revela uma estratégia clara:\nTirar a eleição do campo simbólico e trazer para o campo prático.\nAo fazer isso, o governo desloca o eixo da disputa:\n•	menos ideologia \n•	mais resultado \n•	menos narrativa nacional \n•	mais impacto local \nIsso significa, forçar a eleição a acontecer onde o governo é mais forte.\n\n**4. O risco do contraste**\nEsse tipo de estratégia, porém, não é isenta de risco.\nQuando a eleição se organiza em torno de contraste, ela simplifica o entendimento do eleitor.\nE simplificações favorecem decisões rápidas.\nSe o eleitor enxergar:\n•	continuidade eficiente → vantagem governista \n•	necessidade de mudança → vantagem da oposição \no resultado deixa de depender apenas de estrutura e passa a depender de percepção. Claro que, as pesquisas que avaliam o governo Ratinho Junior, não deixam dúvidas sobre o capital politico criado. \nÉ nisso que o candidato do governo, que aliás, sai de dentro do próprio governo, pode levar uma grande vantagem. O discurso da continuidade ultrapassa a mera narrativa e passa a ser uma necessidade.\n\n**5. Dois caminhos, dois tipos de voto**\nA disputa, neste momento, aponta para dois tipos distintos de decisão eleitoral:\n\n🔹 Voto por continuidade\n•	baseado em entregas \n•	associado à gestão \n•	ancorado na aprovação do governo\n \n🔹 Voto por reposicionamento\n•	baseado em uma identidade política fraca \n•	associado ao volátil cenário nacional \n•	ancorado em discurso que reafirma a boa situação do Paraná.\n\nNenhum dos dois é, por si só, dominante.\nMas cada um responde a um tipo diferente de eleitor.\n',NULL,'/api/media/materia/novo-1777161537364-gnr5k5j1g/imagens/1777161538240-entrega-recursos.jpg',NULL,0,'published','2026-04-27 21:22:40.426','2026-04-26 00:00:30.070','2026-05-09 14:25:46.935','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',23,NULL),
('dd0b51c5-7648-4f3a-83ef-abc739ab922a','Os pontos mais importantes que vão decidir a eleição no Paraná','os-pontos-mais-importantes-que-vao-decidir-a-eleicao-no-parana-r6lja',' O cenário ainda é altamente indefinido','**1. Transferência de poder é real ou superestimada?** \n\nO maior ativo político do Paraná hoje é Ratinho Junior. Alta aprovação, governo consolidado, presença institucional forte. Mas há um dado que complica a equação: o apoio do governador não garante automaticamente o voto Pesquisas indicam que boa parte do eleitorado decide mais pelo candidato do que pelo padrinho político. Isso transforma a eleição em um teste direto: o governo transfere voto ou o candidato precisa se sustentar sozinho. Esse é o primeiro ponto crítico.\n\n**2. A vantagem inicial de Moro é estrutural — ou momentânea?** \n\nSérgio Moro aparece na frente nas pesquisas, com índices que chegam a ultrapassar 50% em alguns cenários. Mas há um detalhe relevante: o cenário ainda é altamente indefinido, com grande número de eleitores sem decisão formada. Isso significa: Moro lidera, mas a eleição ainda não se consolidou.\n\n> Liderança precoce não é vitória garantida — é ponto de partida.\n\n**3. A eleição será estadual ou nacionalizada?** \n\nEsse talvez seja o ponto mais estratégico de todos. A candidatura de Moro não é apenas local. Ela está conectada a um projeto nacional, especialmente após sua entrada no PL e articulações com lideranças nacionais. \n\nJá o grupo de Ratinho opera em outra lógica: tentar manter a eleição no campo estadual. Isso cria uma disputa de enquadramento: \n\n• **eleição local** → favorece quem governou. Ratinho Jr tem alta aprovação. \n\n• **eleição nacionalizada** → favorece quem estava fora do Estado (senador Moro) e agora se volta para a eleição estadual; \n\nQuem conseguir definir o “tema” da eleição, ganha vantagem.\n\n**4. O fator desconhecimento do candidato governista** \n\nA escolha de Sandro Alex resolve um problema interno — mas abre um desafio externo. Ele não chega como nome consolidado no eleitorado. Isso cria uma corrida contra o tempo: \n\n• aumentar reconhecimento • construir identidade • evitar rejeição precoce.\n\nEnquanto isso, Moro já entra com um nível maior de conhecimento público. Isso gera uma assimetria clara no início da campanha.\n\n**5. O eleitor ainda não decidiu — e isso muda tudo.** \n\nTalvez o ponto mais subestimado. Apesar das pesquisas, o número de indecisos segue elevado, chegando a mais de 70% em cenários espontâneos.\n\n Isso indica: • a eleição ainda está aberta • o voto não está cristalizado • há espaço para mudança real de cenário.\n\n**E aí?** \n\nEstá evidente que o jogo ainda não começou de verdade. \n\n> A eleição no Paraná não será decidida apenas por quem lidera hoje\n\n**Será decidida por quem conseguir resolver cinco equações ao mesmo tempo**: • transformar aprovação em voto • consolidar liderança em vantagem real • definir o campo da disputa (local ou nacional) • construir ou sustentar identidade política • conquistar um eleitor que ainda não escolheu. \n\nNo fim, não vence quem começa na frente. Vence quem entende onde a eleição realmente está acontecendo. E, neste momento, ela ainda está em aberto.\n',NULL,'/api/media/materia/novo-1777163903157-0ds9tsqq5/imagens/1777163904266-carinho-com-as-pessoas.jpg',NULL,0,'published','2026-04-28 18:01:42.685','2026-04-26 00:38:31.643','2026-05-15 13:25:02.547','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',20,NULL),
('ddb3ab06-3a4f-41ea-b295-be5f84d11ab2','Os 5 pontos que vão decidir a eleição no Paraná','os-5-pontos-que-vao-decidir-a-eleicao-no-parana-fwe2m','O cenário ainda é altamente indefinido','\n**1. Transferência de poder é real ou superestimada?**\nO maior ativo político do Paraná hoje é Ratinho Junior.\nAlta aprovação, governo consolidado, presença institucional forte.\nMas há um dado que complica a equação:\no apoio do governador não garante automaticamente o voto\nPesquisas indicam que boa parte do eleitorado decide mais pelo candidato do que pelo padrinho político.\nIsso transforma a eleição em um teste direto:\n•	o governo transfere voto\nou \n•	o candidato precisa se sustentar sozinho \nEsse é o primeiro ponto crítico.\n\n**2. A vantagem inicial de Moro é estrutural — ou momentânea?**\nSérgio Moro aparece na frente nas pesquisas, com índices que chegam a ultrapassar 50% em alguns cenários.\nMas há um detalhe relevante:\no cenário ainda é altamente indefinido, com grande número de eleitores sem decisão formada.\nIsso significa:\n•	Moro lidera \n•	mas a eleição ainda não consolidou \nliderança precoce não é vitória garantida — é ponto de partida.\n\n**3. A eleição será estadual ou nacionalizada?**\nEsse talvez seja o ponto mais estratégico de todos.\nA candidatura de Moro não é apenas local.\nEla está conectada a um projeto nacional, especialmente após sua entrada no PL e articulações com lideranças nacionais.\nJá o grupo de Ratinho opera em outra lógica:\ntentar manter a eleição no campo estadual\nIsso cria uma disputa de enquadramento:\n•	eleição local → favorece quem governou. Ratinho Jr tem alta aprovação.\n•	eleição nacionalizada → favorece quem estava fora do Estado (senador Moro) e agora se volta para a eleição estadual; \nQuem conseguir definir o “tema” da eleição, ganha vantagem.\n\n**4. O fator desconhecimento do candidato governista**\nA escolha de Sandro Alex resolve um problema interno —\nmas abre um desafio externo.\nEle não chega como nome consolidado no eleitorado.\nIsso cria uma corrida contra o tempo:\n•	aumentar reconhecimento \n•	construir identidade \n•	evitar rejeição precoce \nEnquanto isso, Moro já entra com um nível maior de conhecimento público.\nIsso gera uma assimetria clara no início da campanha.\n\n**5. O eleitor ainda não decidiu — e isso muda tudo**\nTalvez o ponto mais subestimado.\nApesar das pesquisas, o número de indecisos segue elevado, chegando a mais de 70% em cenários espontâneos.\nIsso indica:\n•	a eleição ainda está aberta \n•	o voto não está cristalizado \n•	há espaço para mudança real de cenário \n\n **E aí?**\nEstá evidente que o jogo ainda não começou de verdade\nA eleição no Paraná não será decidida apenas por quem lidera hoje.\nSerá decidida por quem conseguir resolver cinco equações ao mesmo tempo:\n•	transformar aprovação em voto \n•	consolidar liderança em vantagem real \n•	definir o campo da disputa (local ou nacional) \n•	construir ou sustentar identidade política \n•	conquistar um eleitor que ainda não escolheu \nNo fim, não vence quem começa na frente.\nVence quem entende onde a eleição realmente está acontecendo.\nE, neste momento, ela ainda está em aberto.\n',NULL,'/api/media/materia/novo-1777146866229-6n4gbk72t/imagens/1777146866678-carinho-com-as-pessoas.jpg',NULL,0,'archived','2026-04-25 23:50:08.766','2026-04-25 19:57:46.976','2026-04-26 00:28:43.389','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Roberto Dziura Jr/AEN',8,NULL),
('e0398fa7-efcd-40d2-b798-d8bfe179a726','A aprovação de Ratinho Junior deixou de ser regional, etária ou social. Virou transversal.','a-aprovacao-de-ratinho-junior-deixou-de-ser-regional-etaria-ou-social-virou-transversal-inybv','E isso muda completamente o tamanho político do governador na sucessão de 2026.','As pesquisas mais recentes sobre o governo do Paraná mostram um fenômeno político raro: Ratinho Junior mantém alta aprovação em praticamente todos os recortes analisados.\n\nNão apenas entre os eleitores mais velhos, conservadores ou moradores do interior, mas também em diferentes faixas etárias, variados níveis de escolaridade e segmentos sociais distintos. \nE isso muda completamente o tamanho político do governador na sucessão de 2026.\n\n**O dado mais importante não é apenas o índice.**\nGovernadores populares existem, mas poucos conseguem atravessar: idade, renda, escolaridade e perfil urbano, mantendo aprovação elevada em todos os grupos.\nQuando isso acontece, a aprovação deixa de ser localizada e passa a ser estrutural.\n\n**A força da aprovação espontânea.**\nOutro ponto importante aparece justamente na pesquisa espontânea.\nNesse modelo, o eleitor não recebe opções prontas. Ele responde o que vem à cabeça, e é exatamente aí que a força política costuma aparecer de forma mais verdadeira.\n\n> Ratinho Junior continua sendo lembrado espontaneamente de forma positiva por parcela significativa do eleitorado. Isso revela algo importante: o governo conseguiu ocupar espaço permanente na percepção popular\n\n.\n**O governo rompeu bolhas políticas tradicionais.**\nSeguramente, esse é hoje o maior ativo do governador. Ratinho Junior conseguiu construir um perfil político que conversa simultaneamente com interior e capital, eleitor conservador e moderado, setores empresariais e população popular e eleitores mais jovens e mais velhos. \nIsso explica por que sua aprovação permanece elevada mesmo após anos de governo.\n\n**A política do resultado.**\nExiste um elemento central nessa construção: o governo se comunica muito mais pela ideia de entrega do que pela disputa ideológica.\nRodovias, pontes, hospitais, infraestrutura, investimentos regionais e presença constante no interior criaram uma narrativa simples: “o estado está funcionando”.\nE, na política, percepção de funcionamento costuma gerar estabilidade de aprovação.\n\n**O impacto direto em 2026**.\nEssa aprovação transversal muda completamente o cenário da sucessão.\nPorque Ratinho Junior não chega ao último ano desgastado, isolado ou administrando crise. Chega politicamente forte.\nE isso fortalece diretamente o projeto de continuidade representado por Sandro Alex.\n\n**O Paraná vive um fenômeno diferente do cenário nacional.**\nEnquanto o Brasil permanece altamente polarizado, o Paraná parece caminhar em outra direção.\nA aprovação elevada em diferentes segmentos mostra que parte importante do eleitorado estadual prioriza estabilidade, gestão, infraestrutura e sensação de avanço administrativo. \n**- Menos conflito**\n**- Mais resultado.**\n\n**E aí?**\nA força política de Ratinho Junior hoje não está apenas nos números absolutos.\nEstá na distribuição dessa aprovação. Porque governos muito aprovados em apenas um grupo social podem enfrentar limites eleitorais. Mas governos aprovados transversalmente, ampliam influência política, consolidam liderança e aumentam capacidade de interferir na sucessão.\n \n**Fato.**\nRatinho Junior deixou de ser apenas um governador popular.\nHoje, sua aprovação atravessa idade, escolaridade, perfil social e região do estado. \nE, na política, quando um governo consegue falar simultaneamente com públicos tão diferentes, a aprovação deixa de ser apenas estatística.\nVira capital político real.\n',NULL,'/api/media/materia/novo-1778508144575-cdppnzpt6/imagens/1778508147532-Reprodu__o_IA_colete_DER.png',NULL,0,'published','2026-05-14 15:11:58.001','2026-05-11 14:03:42.179','2026-06-07 14:02:52.940','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: reprodução',9,NULL),
('e0b424af-b3ea-4dc4-8d8a-abe2017852cc','A pesquisa que pode reorganizar o jogo político no Paraná','a-pesquisa-que-pode-reorganizar-o-jogo-politico-no-parana-bpqg0','A nova pesquisa do IRG, prevista para ser divulgada no dia 21, chega em um momento particularmente delicado — e decisivo — da corrida ao Governo do Paraná.','Não será apenas mais um levantamento.\nSerá uma pesquisa observada com atenção porque tentará medir três movimentos políticos simultâneos: o impacto do possível desgaste recente envolvendo Flávio Bolsonaro, com reflexos na campanha de Sergio Moro, a capacidade de transferência política de Ratinho Junior e o crescimento real de Sandro Alex no interior do estado. \n\n**O principal foco estará em Moro.**\nAté aqui, Sergio Moro vinha ocupando posição confortável nas pesquisas: alta lembrança, forte conhecimento estadual, eleitorado consolidado à direita e praticamente ausência de desgaste regional relevante. \n\n> Mas o cenário começou a mudar. O episódio envolvendo o áudio de Flávio Bolsonaro e Daniel Vorcaro colocou Moro no centro de uma turbulência política que ainda não foi efetivamente medida eleitoralmente.\n \nE esse é um dos objetivos do IRG: descobrir se houve dano real à imagem do senador ou apenas ruído momentâneo de bastidor.\n\n**A força de Moro será testada emocionalmente — não apenas numericamente.**\nExiste um detalhe importante nesse momento. Moro sempre foi um candidato muito associado à imagem pessoal, ao combate à corrupção e à credibilidade individual. \nQuando esse tipo de candidato sofre desgaste político ou passa a integrar conflitos de bastidor, a reação do eleitor costuma ser diferente da política tradicional.\nO IRG provavelmente tentará identificar se o eleitor de Moro continua emocionalmente consolidado ou se começou um processo inicial de desgaste silencioso.\n\n**A grande expectativa está sobre Sandro Alex.**\nMas o dado mais aguardado está do outro lado da disputa. Porque esta será uma das primeiras pesquisas realmente capazes de medir se Ratinho Junior começa a transferir capital político para Sandro Alex. \nO governo intensificou agendas no interior, encontros do PSD, entregas de obras, viagens regionais e aparições conjuntas entre governador e pré-candidato. \n\n**Na prática, o estado já vive uma pré-campanha de continuidade.**\nO teste mais importante da pesquisa não será intenção de voto pura.\nO dado decisivo provavelmente estará nos cenários vinculando explicitamente Sandro Alex + apoio de Ratinho Junior e Moro + apoio de Flávio Bolsonaro. \nIsso porque a eleição paranaense começa a assumir duas narrativas muito claras:\nO campo governista: continuidade, gestão, obras, interiorização e aprovação administrativa. \nO campo de Moro: notoriedade, identidade ideológica, oposição ao sistema tradicional e alinhamento bolsonarista. \n\n> A pesquisa deve começar a mostrar qual dessas narrativas ganha mais força no atual momento.\n\nRatinho Junior entra definitivamente no centro da eleição.\nOutro ponto importante: o governador deixa de ser apenas “o cabo eleitoral desejado”. Agora passa a ser o principal personagem da sucessão estadual.\nAs perguntas sobre transferência de voto mostram exatamente isso: o tamanho da influência política de Ratinho e sua capacidade de transformar aprovação em sucessão. \n\n**Os indecisos continuarão sendo decisivos.**\nMesmo com Moro liderando a maioria dos cenários até aqui, existe um dado estrutural importante: a eleição ainda está muito aberta.\nPesquisas anteriores mostram que há parcela expressiva de indecisos, eleitores sem candidato consolidado e votos ainda em formação. \n\n> Isso significa que notoriedade inicial ajuda, mas não encerra disputa.\n\n Especialmente quando o grupo governista possui máquina administrativa forte, presença regional intensa e governador com aprovação elevada. \n\n**E aí?**\nA pesquisa do IRG não deve apenas medir intenção de voto. Ela provavelmente começará a responder algo maior: Moro já atingiu seu teto?  Ratinho consegue transferir força política? Sandro Alex começa a crescer de forma consistente? e o eleitor paranaense continuará votando mais pela gestão ou pela identidade ideológica?\n\n**Fato.**\nAté aqui, Moro liderou a corrida muito pela força do próprio nome. Mas a eleição começa a entrar em uma nova fase: a fase da transferência política. E é exatamente isso que a pesquisa do dia 21 tentará medir.\n',NULL,'/api/media/materia/novo-1779112529867-eo94uijnl/imagens/1779112536055-Sandro__Ratinho_e_S_rgio_Moro_montagem.png',NULL,0,'published','2026-05-19 12:07:51.533','2026-05-18 13:56:42.627','2026-05-20 19:50:37.861','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',7,NULL),
('ea1e7636-6b42-4482-9113-6ef0503d3928','Ratinho Junior anuncia R$ 338 milhões em segurança pública. O maior investimento da história ','ratinho-junior-anuncia-rdollar-338-milhoes-em-seguranca-publica-o-maior-investimento-da-historia-p790w','O pacote anunciado nesta terça-feira (5) pelo governador Carlos Massa Ratinho Junior contempla 3,2 mil armamentos, 1.245 viaturas e 29 embarcações, além de','O governador Carlos Massa Ratinho Junior entregou nesta terça-feira (5) o maior pacote de investimentos da história da segurança pública do Estado, totalizando R$ 338 milhões aplicados no fortalecimento das forças policiais e de resgate. \nO pacote contempla 3,2 mil armamentos, 1.245 viaturas e 29 embarcações, além de equipamentos de informática, sistemas de comunicação, tecnologia forense e materiais especializados, bem como a nova sede do Batalhão de Operações Policiais Especiais (Bope) da Polícia Militar do Paraná (PMPR).\n\nSegundo o governador, o objetivo do novo aporte é ampliar a presença das forças de segurança pública em todas as regiões do Estado, por meio da modernização das estruturas e do aumento da capacidade de resposta das corporações. \n\n> Estamos entregando uma estrutura e equipamentos modernos, à altura da importância das forças de segurança do Paraná, cujo trabalho fez com que o Estado alcançasse os menores índices de criminalidade da história, com redução de homicídios, feminicídios, roubos e outras ocorrências”, afirmou Ratinho Junior.\n\nA entrega ocorreu na nova sede do Bope, que recebeu investimento de R$ 50,7 milhões do Governo do Estado. A unidade da PMPR passa a funcionar em uma estrutura de 3,5 mil metros quadrados em São José dos Pinhais, na Região Metropolitana de Curitiba (RMC), voltada a operações de alta complexidade, planejamento, treinamento e atuação tática.\n\nA escolha da localização também levou em conta critérios logísticos. “Nós definimos este local por ser um ponto estratégico que integra diversas entradas e saídas da RMC, como o acesso ao Interior do Paraná, Contorno Sul de Curitiba, Litoral e São Paulo, além da Casa de Custódia de São José dos Pinhais e do Presídio de Piraquara, o que garante o deslocamento rápido dos agentes do Bope”, justificou o governador.\n\nhttps://youtu.be/R1sqTm8UuIA\n\nO secretário estadual da Segurança Pública, Saulo Sanson, classificou a entrega como um momento histórico para o setor. “Estamos colocando nas ruas um conjunto robusto de equipamentos e estruturas que fortalecem a atuação das forças de segurança em todas as regiões do Estado”, disse.\n\nDe acordo com Sanson, já há planejamento definido para a distribuição dos equipamentos entre as corporações, com envio imediato das viaturas e demais estruturas às diferentes regiões conforme as demandas operacionais. “Esses equipamentos começam a ser empregados imediatamente pelas equipes, reforçando o trabalho do policial que está na ponta e garantindo uma resposta mais rápida e eficiente à população”, explicou.\n\n',NULL,'/api/media/materia/novo-1778027686462-c7d78mwkv/imagens/1778027688275-entrega_seguran_a_p_blica_Bope.jpg',NULL,0,'published','2026-05-06 00:50:46.819','2026-05-06 00:39:53.158','2026-05-21 16:52:17.830','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ari Dias/AEN',10,NULL),
('ea81ca0a-c595-4bf3-8b5b-1d8cd8bf4202','Alexandre Curi: a política construída no ritmo do Legislativo','alexandre-curi-a-politica-construida-no-ritmo-do-legislativo-mlvxc','Deputados que se mantêm ao longo do tempo costumam desenvolver uma característica específica','Há trajetórias políticas que se projetam pelo impacto imediato.\nE há aquelas que se consolidam pela constância.\n\nA de Alexandre Curi pertence claramente ao segundo grupo.\n\n**1. A formação de um parlamentar de articulação**\nAo longo de sua atuação na Assembleia Legislativa do Paraná, Curi construiu um perfil que foge do improviso.\nSua presença no Legislativo não se resume a mandatos sucessivos.\n\n> É uma construção de método\n> baseada em articulação, negociação e conhecimento institucional.\n\nEsse tipo de atuação raramente ganha manchetes —\nmas costuma sustentar resultados.\n\n**2. Experiência como ativo político**\nEm um cenário cada vez mais marcado por candidaturas que se projetam rapidamente, a trajetória de Alexandre Curi representa outro caminho:\nO da política acumulada.\n•	conhecimento do funcionamento do Estado \n•	relacionamento com diferentes regiões \n•	trânsito entre forças políticas distintas. \nEsse conjunto forma um ativo relevante, especialmente em uma disputa como a do Senado, onde a atuação exige leitura mais ampla do processo político.\n\n**3. Capilaridade e presença regional**\nUm dos pontos mais consistentes de sua atuação está na capacidade de diálogo com o interior.\nDeputados que se mantêm ao longo do tempo costumam desenvolver uma característica específica:\nPresença contínua fora dos grandes centros.\nE isso se traduz em algo concreto:\n•	proximidade com prefeitos \n•	interlocução com lideranças locais \n•	compreensão de demandas regionais .\nNa política paranaense, esse tipo de capilaridade não é detalhe.\nÉ base.\n\n**4. O perfil que se ajusta ao Senado**\nO Senado exige um tipo específico de político:\n•	menos impulsivo \n•	mais articulador \n•	com visão institucional mais ampla.\nNesse sentido, a trajetória de Alexandre Curi indica uma adaptação natural a esse papel.\n- sua formação é legislativa\n- sua atuação é construída no diálogo\n- sua presença é mais estrutural do que episódica.\n- \n**5. O momento político**\nA pré-candidatura ao Senado surge em um contexto em que o eleitor tende a valorizar mais estabilidade do que ruptura.\nE, nesse ambiente, perfis com experiência e capacidade de articulação ganham relevância.\nNão por discurso.\nMas por consistência.\n\n**E aí?**\nAlexandre Curi não é um nome que surge de forma repentina.\nÉ resultado de um percurso.\nUm percurso que se desenvolveu dentro da política, entendendo seus limites, suas possibilidades e seus mecanismos reais de funcionamento.\nE, em uma eleição que ainda se desenha, essa construção pode fazer a diferença.\nEm um cenário de nomes que aparecem,\nAlexandre Curi é um nome que foi construído.\nE, na política,\nconstrução costuma pesar mais do que impulso.\n',NULL,'/api/media/materia/novo-1777558700653-4dnfevxfz/imagens/1777558702857-Alexandre_Curi.jpg',NULL,0,'published','2026-04-30 14:24:26.733','2026-04-30 14:20:22.992','2026-05-06 13:55:26.940','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: assessoria Alexandre Curi',6,NULL),
('ec7cb415-d2a8-4529-af13-e85d5cc3feac','Atletas corredores de todo o Estado cruzam a Ponte de Guaratuba na 1ª Maratona Internacional do Paraná','atletas-corredores-de-todo-o-estado-cruzam-a-ponte-de-guaratuba-na-1a-maratona-internacional-do-parana-zqgfa','A paisagem marcou o trajeto dos corredores das provas de 5 km e 21 km neste sábado (2) no Litoral do Paraná. Sob neblina e chuva, os atletas percorreram a Ponte','A largada da primeira etapa da Maratona Internacional do Paraná (MIP) movimentou o Litoral logo nas primeiras horas deste sábado (2). Sob neblina e chuva, milhares de atletas percorreram os trajetos de 5 km e 21 km pelas ruas de Guaratuba e Matinhos.\n\nO cronograma de largadas começou às 6h com os Atletas com Deficiência (ACD) na categoria de 5 km, seguidos pelo público geral da mesma distância. Às 7h25, foi a vez dos competidores ACD no percurso de 21 km, antecedendo as categorias Elite Feminina, Masculina e o pelotão geral da meia maratona.\n\n> O grande diferencial é o percurso sobre a Ponte de Guaratuba, recém-inaugurada sexta-feira (1º) pelo governador Carlos Massa Ratinho Junior.\n\n Principal cartão-postal da prova, a estrutura integra todos os trajetos, unindo o desafio físico a uma paisagem privilegiada. A travessia eleva o nível da competição ao conectar o atletismo a um dos projetos de infraestrutura mais emblemáticos do Estado.',NULL,'/api/media/materia/novo-1777740063575-liwq6s2ax/imagens/1777740070359-Ponte_atletas_corrida.jpg',NULL,0,'published','2026-05-06 09:44:41.581','2026-05-02 16:43:36.615','2026-05-14 23:42:41.119','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Felipe Henschel/AEN',10,NULL),
('edad3ea1-ce5b-4cc6-bdbb-f24260dbc38a','Assembleia aprova projeto para reforçar Guardas Municipais com repasse de recursos e doação de equipamentos','assembleia-aprova-projeto-para-reforcar-guardas-municipais-com-repasse-de-recursos-e-doacao-de-equipamentos-yaqck','A proposta autoriza apoio financeiro e envio de bens para fortalecer a segurança nos município','A Assembleia Legislativa do Paraná aprovou uma iniciativa que autoriza o Estado a fortalecer as Guardas Municipais por meio da transferência de recursos financeiros e da doação de bens, materiais e equipamentos. \n\n> A medida busca ampliar a capacidade operacional das corporações nos municípios e reforçar a segurança pública local. \n\nA proposta estabelece que os repasses financeiros deverão ser destinados exclusivamente a investimentos na estrutura física e operacional das Guardas Municipais, como a aquisição de viaturas, equipamentos de proteção e sistemas de comunicação. Já a doação de bens móveis – incluindo veículos, armamentos menos letais e outros equipamentos – será voltada a corporações regularmente constituídas e em funcionamento, conforme a legislação federal.\n\nO primeiro-secretário da Assembleia Legislativa, deputado Gugu Bueno, destacou o alcance da proposta para todo o Estado. “Um projeto de lei muito importante que estabelece a possibilidade do governo do Estado repassar estrutura, ajudando as guardas municipais por todo o Paraná. Hoje nós temos 40 municípios com guarda municipal funcionando, atendendo muito bem a população, e agora será possível repassar recurso, equipamento, viatura e treinamento para que a gente tenha um sistema de segurança pública ainda melhor”, afirmou.\n\n“Tratei pessoalmente da construção dessa lei com o governador Ratinho Junior, com a ajuda do líder Hussein Bakri (PSD). Essa lei autoriza o governo a repassar recursos às guardas municipais. Sabemos do brilhante trabalho realizado em todo o estado e é necessário que essa lei seja aprovada para que, num futuro próximo, nós, deputados, também possamos destinar recursos do Estado para equipar as Guardas com equipamentos, recursos financeiros e bens”, afirmou o deputado Batatinha (MDB) em Plenário.',NULL,'/api/media/materia/novo-1777324720031-4rypxij1w/imagens/1777324720202-Plen_rio_Alep.jpg',NULL,0,'published','2026-04-27 21:20:33.426','2026-04-27 21:18:59.279','2026-05-29 12:30:00.089','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Valdir Amaral/Alep',3,NULL),
('f4c50d20-c955-45f2-b3b0-33048b195c07','A ponte, as pessoas e o momento: quando a obra se transforma em símbolo','a-ponte-as-pessoas-e-o-momento-quando-a-obra-se-transforma-em-simbolo-7dvzi','O que se viu não foi apenas uma entrega institucional.','A Ponte de Guaratuba foi inaugurada nesta sexta-feira (01/05), diante de um cenário raro na política contemporânea: presença massiva, emoção visível e apropriação popular. \nMais de 20 mil pessoas, vindas de diversas regiões do Paraná, se deslocaram até o litoral para acompanhar o momento.\nNão como espectadores distantes.\nMas como participantes.\n\n**O gesto coletivo**\nApós a cerimônia, o público foi convidado a fazer algo incomum em inaugurações desse porte: caminhar pela ponte, ocupar o espaço e, simbolicamente, tomar posse da obra.\nO que se viu não foi apenas uma entrega institucional.\nFoi uma incorporação coletiva. \nA ponte deixou de ser projeto de governo e passou a ser experiência das pessoas.\n\nVeja o momento de celebração em cima da Ponte:\nhttps://www.youtube.com/shorts/sYlhwN63I4k?feature=share\n\n**A emoção como elemento político**\nDurante o evento, o governador Ratinho Junior demonstrou emoção em diversos momentos.\nAo seu lado estavam a esposa, os filhos e seu pai, o apresentador Ratinho.\nTodos visivelmente emocionados.\nEsse detalhe, embora pessoal, carrega um significado político importante: aproxima o gesto institucional da dimensão humana.\nE reforça a percepção de que a obra ultrapassa o campo administrativo.\n\n**A imagem que fica**\nA inauguração produziu uma cena difícil de ignorar: milhares de pessoas sobre a ponte, uso imediato da estrutura, presença familiar do governador, emoção compartilhada e uma obra entregue com grande participação popular.\nNo mundo da política, imagens assim não são apenas registro.\nSão construção de memória.\n\n**O significado ampliado**\nA Ponte da Vitória resolve um problema histórico, mas, neste momento, faz algo além: cria um marco simbólico de gestão, execução concreta, presença do Estado e resposta a uma demanda antiga \nE isso se consolida não apenas pela obra em si, mas pela forma como ela foi entregue.\n\n**E aí?**\nA inauguração da ponte não foi apenas um ato administrativo.\nFoi um momento político completo:\n•	obra \n•	público \n•	emoção \n•	e símbolo. \nPara o litoral, representa mudança prática.\nPara o governo, representa legado.\n\n**Fato**\nMais de 20 mil pessoas não foram apenas assistir. Foram participar.\nE, ao caminhar sobre a ponte, transformaram uma obra pública em algo próprio.\nPorque, na política, quando a população ocupa o espaço, a obra deixa de ser do governo — e passa a ser do Estado.\n',NULL,'/api/media/materia/novo-1777739375608-x8rb5ov80/imagens/1777739379431-Ponte_inaugura__o_II.jpg',NULL,0,'published','2026-05-05 13:57:50.538','2026-05-02 16:31:09.287','2026-05-09 17:34:07.008','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Geraldo Bubniak/AEN',33,NULL),
('f56db098-d9d3-4ccc-9d03-af9bd3ffdf8c','Ratinho Junior criou um modelo de presença política permanente no interior','ratinho-junior-criou-um-modelo-de-presenca-politica-permanente-no-interior-lxg9r','Ratinho Junior conseguiu criar uma relação rara entre governo e população, com presença constante.','O que se observa atualmente no Paraná não é apenas agenda administrativa. É um modelo claro de interiorização do poder público. Ratinho Junior conseguiu criar uma relação rara entre governo e população, com presença constante.\n\nO governador percorre pequenas cidades, regiões esquecidas historicamente, comunidades rurais e municípios que antes recebiam pouca atenção do Estado. \n\nO caso de Altamira do Paraná e Laranjal é simbólico. A autorização da pavimentação da ligação entre os dois municípios, investimento superior a R$ 156 milhões, representa uma demanda histórica de décadas da população regional. \n\nE o mais importante politicamente: o governador aparece pessoalmente para entregar, anunciar e ouvir a população.\n',NULL,'/api/media/materia/novo-1779919792591-d6pms9vn1/imagens/1779919793237-Laranjal_lotado.jpg',NULL,0,'published','2026-05-29 19:09:14.156','2026-05-27 22:11:12.493','2026-06-03 03:17:11.293','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Ricardo Zanoncini/AEN',10,NULL),
('fd1085f2-97d4-4d60-8af3-af044e843de7','Álvaro Dias pode redesenhar a eleição do Paraná?','alvaro-dias-pode-redesenhar-a-eleicao-do-parana-qt367','Embora não haja confirmação pública nesse sentido, a simples especulação já produz efeitos políticos relevantes. Atualmente, o MDB mantém oficialmente as pré-candidaturas de Rafael Greca ao Governo do Estado','A política paranaense entrou em um momento em que as pesquisas são importantes, mas as alianças começam a ser ainda mais decisivas.\n\nNos bastidores, uma das hipóteses mais comentadas é a possibilidade de o ex-senador Álvaro Dias abrir mão da disputa ao Senado para facilitar uma composição mais ampla entre MDB e PSD. Embora não haja confirmação pública nesse sentido, a simples especulação já produz efeitos políticos relevantes. Atualmente, o MDB mantém oficialmente as pré-candidaturas de Rafael Greca ao Governo do Estado e de Álvaro Dias ao Senado, sem romper com o grupo do governador Ratinho Junior. \n\nSe uma aproximação mais profunda entre MDB e PSD ocorrer, a principal consequência seria a consolidação de uma frente política capaz de reunir o interior, Curitiba e a Região Metropolitana em uma mesma chapa.\n\n**O crescimento de Sandro Alex muda a lógica das negociações.**\nHá poucos meses, a candidatura de Sandro Alex era vista principalmente como o projeto político do grupo de Ratinho Junior.\nHoje, o cenário é diferente.\nAs pesquisas recentes passaram a demonstrar competitividade real da candidatura governista, fortalecendo o PSD nas negociações e aumentando o interesse de partidos aliados em participar diretamente da chapa. \n\n> Quanto mais Sandro Alex cresce, maior se torna o valor político da vaga de vice-governador.\n\nE é exatamente nesse ponto que Rafael Greca surge como peça estratégica.\n\n**Greca resolveria um dos maiores desafios do PSD.**\nO principal desafio eleitoral de Sandro Alex já não está mais no interior.\nSeu maior desafio está em Curitiba e na Região Metropolitana.\nSandro possui forte identificação com o interior, a infraestrutura, o municipalismo e a gestão de Ratinho Junior. \nJá Rafael Greca possui capital político consolidado em Curitiba após três mandatos como prefeito e mantém forte identificação com parte expressiva do eleitorado da capital. \nUma eventual chapa Sandro Alex–Rafael Greca produziria um equilíbrio geográfico e eleitoral bastante relevante:\n**Sandro Alex:**\n•	Interior; \n•	Campos Gerais; \n•	Região Norte; \n•	legado das obras estaduais. \n**Rafael Greca:**\n•	Curitiba; \n•	Região Metropolitana; \n•	eleitor moderado; \n•	setor empresarial e técnico.\n \n**Eduardo Pimentel estaria entre os principais beneficiados.**\nExiste ainda uma variável frequentemente ignorada.\nEduardo Pimentel é prefeito de Curitiba e pertence ao PSD.\nAo mesmo tempo, construiu sua trajetória política diretamente ligada a Rafael Greca, de quem foi vice-prefeito.\nCaso MDB e PSD caminhem juntos, \n\n> Eduardo Pimentel deixaria de enfrentar qualquer dilema político entre a lealdade ao grupo de Ratinho Junior e a gratidão política ao grupo de Greca.\n \nUma composição entre os dois campos transformaria Curitiba em um dos principais polos da campanha governista.\nEm vez de dividir forças, a capital poderia se tornar um dos centros de sustentação eleitoral da candidatura.\n\n**O principal prejudicado seria Sergio Moro.**\nDo ponto de vista matemático e eleitoral, uma aliança PSD-MDB reduziria significativamente o espaço disponível para Sergio Moro.\nHoje, Moro depende de três pilares: eleitorado conservador, recall da Lava Jato e forte desempenho em Curitiba. \nÉ justamente nesse terceiro ponto que uma eventual composição envolvendo Greca poderia gerar dificuldades.\n\n> Greca continua sendo uma das lideranças mais influentes da capital e sua entrada formal na chapa governista teria potencial para reduzir a margem de crescimento de Moro em Curitiba e na Região Metropolitana.\n\nIsso não eliminaria a força eleitoral do senador, mas mudaria o ambiente da disputa.\n\n**E o que faria Álvaro Dias?**\nÁlvaro Dias continua sendo um dos nomes mais respeitados da política paranaense e mantém relevância eleitoral própria. \nCaso optasse por não disputar o Senado, sua decisão teria peso muito superior ao de uma simples retirada de candidatura.\nEla poderia representar sinalização de unidade do campo de centro-direita, fortalecimento do grupo de Ratinho Junior e reorganização completa das alianças para outubro. \nNaturalmente, isso dependeria de negociações partidárias complexas e de interesses regionais que ainda estão em movimento.\n\n**O cenário que começa a se desenhar.**\nSe as pesquisas continuarem apontando crescimento de Sandro Alex e competitividade contra Sergio Moro, a tendência natural da política é a concentração de forças.\n\n> Partidos e lideranças costumam se aproximar de projetos percebidos como viáveis.\n\nNesse contexto, uma eventual composição entre PSD e MDB teria capacidade de reunir Ratinho Junior, Sandro Alex, Rafael Greca, Eduardo Pimentel, prefeitos do PSD e do MDB e parte significativa da estrutura municipalista do estado.\nSeria uma chapa construída com forte presença administrativa, ampla capilaridade regional e grande peso eleitoral em Curitiba.\n\n**E aí?**\nNeste momento, ainda se trata de uma hipótese política, não de um cenário definido.\nMas é uma hipótese que faz sentido dentro da lógica eleitoral.\n\n> A aproximação entre PSD e MDB poderia resolver simultaneamente três desafios: ampliar a presença de Sandro Alex na capital, integrar Rafael Greca ao projeto sucessório de Ratinho Junior e pacificar a relação política envolvendo Eduardo Pimentel. \n\nSe esse movimento ocorrer, a disputa pelo Governo do Paraná deixará de ser apenas um confronto entre Sergio Moro e Sandro Alex.\n**Passará a ser uma disputa entre dois grandes blocos políticos organizados, com potencial para redefinir completamente o equilíbrio eleitoral do estado nas semanas que antecedem as convenções partidárias**.\n',NULL,'/api/media/materia/novo-1780694390010-n00d96uxd/imagens/1780694391742-GRUPO_UNIDO.png',NULL,0,'published','2026-06-05 21:22:08.245','2026-06-05 21:20:48.961','2026-06-07 13:58:10.010','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','915751e5-992d-4cee-909b-3780a3c00c59','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',15,NULL),
('fe85d8bd-fbdd-40aa-a03d-8ca5c6b454e4','Obras no interior transformam o Paraná e fortalecem a marca administrativa do governo Ratinho Junior','obras-no-interior-transformam-o-parana-e-fortalecem-a-marca-administrativa-do-governo-ratinho-junior-7r4xy','Hoje, os investimentos alcançam desde grandes centros regionais até pequenas cidades','O Paraná vive um dos maiores ciclos de investimentos públicos de sua história. E o principal reflexo disso aparece longe da capital, no interior do estado.\n\nEstradas, pavimentações, pontes, escolas, hospitais, equipamentos de segurança, infraestrutura rural e obras urbanas passaram a fazer parte da rotina de centenas de municípios paranaenses. O resultado é um volume recorde de investimentos que coloca o Paraná em posição de destaque nacional. \nSegundo dados apresentados pela Secretaria da Fazenda, o Estado liquidou mais de R$ 2,1 bilhões em investimentos apenas entre janeiro e abril de 2026, o maior valor já registrado em um primeiro quadrimestre nos últimos 26 anos. O número representa mais do que o triplo do valor executado no mesmo período do ano anterior. \n\n**O interior virou prioridade.**\nUm dos aspectos mais marcantes da atual gestão é a decisão política de descentralizar os investimentos. Durante décadas, muitas regiões do interior conviveram com estradas precárias, dificuldades logísticas, falta de infraestrutura urbana e carência de investimentos estaduais. \nO governo Ratinho Junior adotou caminho diferente. Hoje, os investimentos alcançam desde grandes centros regionais até pequenas cidades, com obras que impactam diretamente a vida da população.\n \n**Estradas rurais e logística ganharam protagonismo.**\nUma das maiores marcas desse ciclo de investimentos está na infraestrutura rural. Por meio de programas voltados à melhoria das estradas do campo, o Estado ampliou significativamente a capacidade de escoamento da produção agrícola e reduziu dificuldades históricas enfrentadas pelos produtores. \n\n> Os números impressionam: cerca de 270 municípios atendidos; 452 trechos contemplados; aproximadamente 2.780 quilômetros de vias beneficiadas e investimentos estimados em R$ 3,68 bilhões. \n\nIsso significa desenvolvimento econômico, geração de renda e maior competitividade para o agronegócio paranaense.\n\n**Obras deixaram de ser promessa para virar entrega.**\nExiste um detalhe importante nos números divulgados pela Secretaria da Fazenda: os recursos apresentados correspondem a investimentos liquidados.\nOu seja, obras executadas, equipamentos entregues, estruturas concluídas e investimentos efetivamente realizados. \nA diferença é significativa. Não se trata apenas de previsão orçamentária ou anúncio político. São investimentos que saíram do papel e chegaram aos municípios. \n\n**Educação, saúde e segurança também avançam.**\nO ciclo de investimentos não está concentrado apenas na infraestrutura rodoviária. O Estado ampliou recursos para escolas, creches, hospitais, equipamentos de saúde e modernização da segurança pública. \nSomente na área de segurança foram destinados mais de R$ 338 milhões para aquisição de viaturas, blindados, embarcações, armamentos, sistemas tecnológicos e equipamentos especializados. \n\n**O efeito político das obras.**\nNaturalmente, um volume dessa dimensão também produz efeitos políticos.\nRatinho Junior percorre o interior entregando investimentos e acompanhando obras que começaram ainda nos primeiros anos de sua gestão.\n\n> Em muitas cidades, a população vê pela primeira vez grandes intervenções estaduais chegando de forma concreta\n\nIsso ajuda a explicar os altos índices de aprovação do governo, a forte presença regional do PSD e o crescimento político de nomes ligados à gestão estadual. \n\n**Sandro Alex aparece diretamente associado às obras.**\nOutro fator importante é a ligação entre essas entregas e o trabalho desenvolvido por Sandro Alex durante sua passagem pela Secretaria de Infraestrutura.\nGrande parte das obras hoje em execução ou já concluídas passou pela estrutura administrativa comandada por ele.\nPor isso, em diversas agendas pelo interior, Sandro Alex aparece naturalmente associado aos investimentos realizados pelo governo.\nO eleitor percebe uma conexão direta entre planejamento, execução e continuidade administrativa. \n\n**E aí?**\nOs números divulgados pelo Governo do Paraná mostram mais do que um recorde financeiro. Eles revelam uma estratégia clara de transformar investimento público em desenvolvimento regional.\nCom mais de R$ 2,1 bilhões executados apenas nos primeiros quatro meses de 2026, o Paraná vive um dos maiores ciclos de obras de sua história recente. \nEstradas, pontes, escolas, hospitais, segurança pública e infraestrutura rural passaram a chegar com intensidade aos municípios.\n***E é justamente no interior que esse modelo de gestão encontra seu maior reconhecimento:\numa população que vê as obras acontecendo, os investimentos chegando e o Estado presente de forma concreta no dia a dia das cidades paranaenses.***\n',NULL,'/api/media/materia/novo-1780062786299-d5nixtc9p/imagens/1780062789224-OBRAS_RATINHO_JR.jpg',NULL,0,'published','2026-05-29 19:02:31.816','2026-05-29 13:54:21.887','2026-06-08 09:22:16.343','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Gilson Abreu/Arquivo AEN',8,NULL),
('fe89e0c7-9578-4488-bd91-898e5bef361f','Ratinho Junior acelera o governo em ano eleitoral — e transforma gestão em ativo político para Sandro Alex','ratinho-junior-acelera-o-governo-em-ano-eleitoral-e-transforma-gestao-em-ativo-politico-para-sandro-alex-l2jnc','Historicamente, muitos governos entram no último ano desacelerando, evitando exposição, reduzindo entregas e aguardando a eleição.','Existe uma diferença muito clara entre governos que entram em “modo eleitoral” e governos que mantêm ritmo administrativo até o último dia.\nO Paraná vive hoje o segundo cenário.\n\nE é fácil constatar. Claro que não há uma cobertura jornalística pelos veículos tradicionais da imprensa. Blogs e mídias sociais, veículos de comunicação locais publicam as visitas aos mais diversos municípios e as reportagens são publicadas diariamente pela Agência Estadual de Notícias. \n\n> É, sem dúvida alguma, um governo em movimento permanente\n\nInauguração de viadutos, lançamento de pontes, entrega de casas, pavimentação rural, liberação de recursos, construção de escolas, investimentos em infraestrutura, expansão universitária, fortalecimento do turismo e presença intensa no interior do estado. \nE isso possui enorme impacto político.\n\n**Governador em fim de mandato?**\nRatinho Junior se recusa a agir como se estivesse terminando seus dias no comando do Estado e esse é o principal diferencial político do atual momento.\nHistoricamente, muitos governos entram no último ano desacelerando, evitando exposição, reduzindo entregas e aguardando a eleição. \nRatinho Junior faz exatamente o contrário.\n\nO governador intensificou viagens, encontros regionais, agendas no interior, liberações de recursos e entrega de obras estruturantes. \n\n> A mensagem política é clara: o governo não acabou e o Paraná continua avançando\n\n.\n**\nGovernar não é crime eleitoral.**\nA oposição tenta transformar presença institucional em irregularidade eleitoral.\nIsso ficou evidente quando o grupo de Sergio Moro ingressou na Justiça tentando impedir a presença de Sandro Alex nas entregas a associação política entre governo e sucessão e até referências às obras realizadas. \n\nMas existe um ponto fundamental: ano eleitoral não paralisa administração pública. A legislação eleitoral impõe limites corretos, como, publicidade institucional, uso da máquina, abuso político, mas ela não proíbe inaugurações, entregas, fiscalização de obras, presença de lideranças ou continuidade administrativa. \n\n**Porque a população não pode ser punida pela eleição.**\nHospitais precisam funcionar, estradas precisam ser concluídas, casas precisam ser entregues escolas precisam abrir.\nGovernar até o último dia não é irregularidade. É obrigação administrativa.\nSandro Alex não é um espectador das obras — ele participou diretamente delas.\n\n> Esse é o ponto que mais incomoda a oposição. Sandro Alex não aparece artificialmente ao lado do governador.\n\nEle foi secretário de Infraestrutura de Ratinho Junior.\nE participou diretamente de programas rodoviários, pavimentação rural, modernização logística, obras urbanas, pontes, viadutos e expansão da malha viária estadual. \nGrande parte das entregas atuais passou pelas mãos de Sandro Alex.\nIsso cria uma associação política extremamente forte:\n\n***Ratinho simboliza aprovação***\n\n***Sandro simboliza continuidade administrativa.***\n\n**Moro tenta judicializar aquilo que não conseguiu conter politicamente.**\nA ação da oposição revela um problema evidente, que é a dificuldade de enfrentar o peso político do governo no interior.\nPorque as imagens que se repetem pelo Paraná mostram prefeitos agradecendo investimentos, lideranças regionais apoiando Ratinho e Sandro Alex sendo apresentado como continuidade do modelo administrativo atual. \nO eleitor percebe quem executou, quem apareceu apenas na eleição e quem participou das entregas. \nA tentativa de impedir Sandro Alex de acompanhar obras acabou produzindo efeito contrário: reforçou ainda mais a associação política entre ele e o governo.\n\n**O interior virou a grande fortaleza do grupo governista.**\nAs agendas recentes mostram um padrão muito claro: Francisco Alves, Terra Rica, Dois Vizinhos, Japurá, São Carlos do Ivaí, Verê, São Jorge d’Oeste, Iporã, Apucarana. \nO governo está presente em todas as regiões e isso não ocorre apenas com anúncios.\nExiste obra física, recurso liberado, estrada asfaltada, moradia entregue, escola construída e investimento efetivo. \n\nO interior costuma valorizar fortemente esse tipo de presença administrativa.\nRatinho Junior construiu uma narrativa de eficiência\nOutro aspecto importante: o governador conseguiu algo raro na política brasileira ao unir popularidade com sensação concreta de entrega.\n\n> O discurso do governo deixou de ser apenas político.\n> Virou ponte construída, estrada pronta, moradia entregue, hospital ampliado, iluminação pública e crescimento regional. \n\n**Isso explica os altos índices de aprovação.**\nA eleição começa a virar disputa entre gestão e notoriedade\nSergio Moro continua forte politicamente, pois possui notoriedade nacional, recall eleitoral e força em uma parte do eleitorado conservador. \nMas Ratinho Junior construiu algo diferente: estrutura regional de governo.\nE Sandro Alex cresce justamente nesse espaço, pregando continuidade, interiorização, administração e capacidade de execução. \nA disputa começa a sair do campo apenas ideológico e entra no campo: do “quem fez” e do “quem pode continuar”.\n\n**E aí?**\nO Paraná vive um cenário incomum: um governo altamente aprovado que continua acelerando entregas mesmo em ano eleitoral.\nAs ações recentes mostram ritmo administrativo intenso, presença permanente no interior e clara estratégia de transferência política para Sandro Alex. \nA oposição percebeu isso e por isso tentou judicializar a presença de Sandro Alex ao lado de Ratinho Junior.\nMas existe uma realidade impossível de esconder: Sandro não apareceu agora. Ele participou diretamente da construção desse governo.\n\n**Fato.**\nEstá evidente que o governo Ratinho Junior não entrou em clima de despedida. Entrou em ritmo de continuidade. Enquanto a oposição tenta transformar entrega de obras em debate judicial, o governo segue asfaltando, inaugurando, construindo, investindo e ocupando o interior do Paraná. \n***Sandro Alex cresce porque não é apenas o candidato apoiado por Ratinho. Ele é parte da estrutura que ajudou a executar grande parte dessas obras. E o eleitor começa a enxergar exatamente isso.***\n',NULL,'/api/media/materia/novo-1779573217070-4ux7pabpy/imagens/1779573220085-FOTO_ENTREGA_E_O_POVO_composi__o.png',NULL,0,'published','2026-05-23 21:54:44.458','2026-05-23 21:54:44.489','2026-05-29 13:29:02.345','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','56174e93-344f-4df5-8d43-55dbe079fc89','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Geraldo Bubniak/AEN',26,NULL),
('ff538777-f479-41a6-9c9f-deaae4b8d47e','O Paraná descobriu que turismo não é apenas paisagem. É estratégia econômica.','o-parana-descobriu-que-turismo-nao-e-apenas-paisagem-e-estrategia-economica-pvbs4','Durante muito tempo, o turismo no Paraná foi tratado quase como atividade complementar, algo secundário','Durante muito tempo, o turismo no Paraná foi tratado quase como atividade complementar, algo secundário. Enquanto outros estados transformavam identidade regional em indústria econômica, o Paraná parecia subutilizar parte enorme do seu potencial: natureza, gastronomia, cultura, interiorização e diversidade regional. \nOs movimentos recentes do setor mostram que isso começou a mudar. E o encontro promovido pelo Viaje Paraná em Campo Largo é um retrato claro dessa nova lógica. \n\n**O turismo deixou de ser tratado como “evento”.**\nEsse é o principal avanço. O governo começou a trabalhar o turismo como cadeia econômica, integração regional, geração de renda, fortalecimento local e desenvolvimento permanente. \nO evento em Campo Largo reuniu empresários, gestores, lideranças e profissionais do setor justamente para discutir: governança, sustentabilidade, integração regional e turismo inteligente. Isso revela uma mudança importante de mentalidade.\n\n**Nos últimos anos o Paraná começou a olhar para si mesmo.**\nTalvez o estado tenha demorado para perceber a própria força turística. Poucos lugares conseguem reunir simultaneamente: litoral, cânions, vinhos, turismo rural, tropeirismo, gastronomia, parques naturais, imigração europeia e turismo religioso. \nA pequena Campo Largo simboliza bem isso: enoturismo, turismo rural, tradição cultural, natureza e proximidade com Curitiba. \n\n> “O Turismo precisa ser compreendido como uma atividade econômica porque gera empregos, renda e traz resultados positivos ao comércio e a população”, disse Irapuan Cortes, diretor-presidente do Viaje Paraná. \n\n**O turismo virou política de desenvolvimento regional.**\nEsse é o aspecto mais inteligente da estratégia atual. O governo parece ter entendido que: turismo não movimenta apenas hotel e restaurante.\nMovimenta: pequenos empreendedores, comércio local, agricultura familiar, transporte, eventos, cultura regional e geração de emprego. E isso é especialmente importante para municípios fora dos grandes centros.\n\n**O interior passou a ocupar espaço estratégico.**\nHistoricamente, o turismo paranaense ficou muito concentrado em Curitiba, Foz do Iguaçu e litoral. Agora há uma tentativa clara de ampliar o mapa turístico estadual. A valorização dos Campos Gerais, do tropeirismo, do turismo rural e das rotas regionais mostra isso. O Paraná começa a vender experiência e não apenas destino.\n\n**A crítica positiva: o estado ainda explora menos do que poderia.**\nApesar dos avanços, existe um ponto evidente: o potencial turístico do Paraná ainda é maior do que sua exploração atual.\nO estado possui patrimônio natural forte, identidade cultural rica, logística privilegiada e diversidade regional incomum. \nMas ainda enfrenta baixa promoção nacional comparada a outros estados, subexploração internacional e necessidade maior de profissionalização em algumas regiões. \nÉ exatamente por isso que o Viaje Paraná ganhou importância crescente ao criar integração entre municípios, profissionalizar o setor e construir identidade turística estadual. \n\n**O turismo também virou ativo político.**\nHá um componente político importante nisso tudo. O governo Ratinho Junior tem trabalhado para consolidar uma imagem de modernização, infraestrutura, desenvolvimento regional e integração econômica. \n\n> O turismo se encaixa perfeitamente nessa narrativa. Porque permite mostrar investimento, circulação econômica, valorização regional e presença do estado no interior.\n\n**E aí?**\nO Paraná começa a viver uma mudança silenciosa no turismo. Deixa de tratar o setor como atividade periférica e passa a tratá-lo como vetor econômico estratégico. Esse é o principal mérito dessa nova fase seja justamente esse: integrar desenvolvimento regional com identidade cultural.\n\n**Fato.**\nO Paraná descobriu que turismo não é apenas cartão-postal. É economia circulando. É interior se fortalecendo. É identidade regional virando oportunidade. E, quando um estado começa a transformar território em experiência, o turismo deixa de ser passeio. Passa a ser projeto de desenvolvimento.\n',NULL,'/api/media/materia/ff538777-f479-41a6-9c9f-deaae4b8d47e/imagens/1778764552301-IRAPUAN_TURISMO.jpg',NULL,0,'published','2026-05-14 15:02:26.841','2026-05-14 13:15:26.165','2026-06-02 07:31:12.599','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','43dde722-27a9-4987-9bf3-a6a8ca6fd1c9','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: Viaje Paraná',22,NULL),
('ff9711b4-74a4-4ca2-be0f-333e8001f461','Avenida Arthur Bernardes: a decisão difícil que Eduardo Pimentel resolveu assumir','avenida-arthur-bernardes-a-decisao-dificil-que-eduardo-pimentel-resolveu-assumir-7i96f',NULL,'A polêmica envolvendo a retirada de árvores na Avenida Arthur Bernardes expôs um dos temas mais delicados da gestão urbana moderna: como conciliar preservação ambiental com necessidade de mobilidade e infraestrutura.\n\n**Os protestos são compreensíveis.**\nA Arthur Bernardes possui forte identidade afetiva para Curitiba: é um corredor verde, tem área de convivência, há memória urbana e símbolo do imaginário da “capital ecológica”. \nMas a discussão também revela outro ponto importante: administrar uma cidade complexa exige, muitas vezes, tomar decisões impopulares.\n\n**Eduardo Pimentel escolheu não recuar.**\nEsse é o principal dado político do episódio.\nMesmo diante de protestos, pressão de movimentos organizados, repercussão negativa nas redes e desgaste ambiental evidente, a Prefeitura decidiu manter o projeto do Novo Inter 2. \n\n> E isso revela uma característica importante da atual gestão: disposição de enfrentar desgaste político em nome de um projeto considerado estrutural para a cidade.\n\nA obra não é isolada. Faz parte de um redesenho urbano.\nO debate muitas vezes ficou concentrado apenas na derrubada das árvores, mas a Prefeitura sustenta que o projeto integra o Novo Inter 2: modernização do transporte coletivo, corredores sustentáveis, ônibus elétricos, drenagem, reorganização viária e requalificação urbana. \nOu seja, o governo municipal tenta apresentar a intervenção como parte de uma transformação mais ampla da mobilidade de Curitiba.\n\n**O impacto ambiental existe — mas a Prefeitura também construiu defesa técnica.**\nEsse é um ponto central. A Justiça chegou a suspender parcialmente as obras, mas o Tribunal de Justiça posteriormente derrubou a liminar e validou a continuidade do projeto. \n\nNa decisão, pesou a existência de estudos ambientais, justificativas técnicas e avaliação do impacto socioeconômico da obra.  Além disso, após pressão social, o projeto sofreu alterações para reduzir significativamente o número inicial de árvores previstas para corte: de mais de 300 para cerca de 103. \n\nIsso demonstra que houve resistência da Prefeitura em abandonar o projeto\nmas também adaptação diante da pressão pública.\n\n**A crítica ambiental revela força da sociedade curitibana.**\nOs protestos também mostram algo positivo sobre Curitiba: a cidade ainda possui forte consciência ambiental coletiva. Movimentos como o SOS Arthur Bernardes conseguiram: mobilizar moradores, gerar debate público, pressionar tecnicamente e influenciar mudanças no projeto. \n\nIsso é saudável para a democracia urbana.\nEduardo Pimentel reafirma a imagem de gestor pragmático.\n\n> Politicamente, o episódio ajuda a desenhar o perfil do prefeito. Pimentel parece optar por uma postura de gestor executivo, técnico, pragmático e menos movido por decisões emocionais.\n \nMesmo sabendo do desgaste potencial, manteve uma obra considerada estratégica para o transporte, a integração urbana e expansão da infraestrutura da cidade. \nA gestão também tenta neutralizar a narrativa de “antiambiental”.\n\nEsse talvez seja o ponto mais importante para o prefeito. Curitiba possui identidade ambiental muito forte e, por isso, Eduardo Pimentel tenta reforçar continuamente os programas de plantio, compensação ambiental, arborização urbana e recuperação verde. \n\nA Prefeitura destaca, por exemplo, programas que já ultrapassaram centenas de milhares de novas mudas plantadas na cidade. \n\nA mensagem política é clara: o governo sustenta que não existe abandono da pauta ambiental, mas sim substituição de modelo urbano em áreas específicas.\n\n**E aí?**\nA crise da Arthur Bernardes talvez revele algo maior sobre Curitiba: a cidade começa a enfrentar o conflito entre preservação afetiva e necessidade de modernização urbana. E Eduardo Pimentel decidiu assumir o custo político dessa escolha.\n\n**Fato.**\nGovernar Curitiba significa administrar uma cidade que ama suas árvores — e reage quando elas desaparecem. Mas também significa decidir.\n\n> Eduardo Pimentel escolheu sustentar uma obra que considera estratégica para a mobilidade e para o futuro urbano da capital.\n\nE, na política, há momentos em que o governante deixa de escolher entre aplauso e crítica e passa a escolher entre recuar ou assumir o desgaste.\n',NULL,'/api/media/materia/ff9711b4-74a4-4ca2-be0f-333e8001f461/imagens/1779125776204-Eduardo_composi__o.png',NULL,0,'published','2026-05-19 11:54:59.715','2026-05-18 17:21:06.875','2026-05-29 12:10:57.947','F8KwChHPKsQmY1bt8qQImGxCwHfOYmSr','5dc07ef7-86dd-4c21-9615-d5d3459c6fbf','f0e92b14-0870-46e2-a64d-1638b99b90e8','Foto: composição',3,NULL);
